function updateVoiceMini(){
    try{
        // Lazy-bind refs (works even before DOMContentLoaded)
        if (!voiceMiniEl) voiceMiniEl = document.getElementById("voice-mini");
        if (!voiceMiniEl) return;

        if (!voiceMiniTitleEl) voiceMiniTitleEl = document.getElementById("voice-mini-title");
        if (!voiceMiniSubEl) voiceMiniSubEl = document.getElementById("voice-mini-sub");
        if (!voiceMiniLeaveBtn) voiceMiniLeaveBtn = document.getElementById("voice-mini-leave");
        if (!voiceMiniVideoBtn) voiceMiniVideoBtn = document.getElementById("voice-mini-video");
        if (!voiceMiniShareBtn) voiceMiniShareBtn = document.getElementById("voice-mini-share");
        if (!voiceMiniActivityBtn) voiceMiniActivityBtn = document.getElementById("voice-mini-activity");
        if (!voiceMiniSoundboardBtn) voiceMiniSoundboardBtn = document.getElementById("voice-mini-soundboard");

        const connected = !!(groupCallActive && groupCallChannelId);
        voiceMiniEl.classList.toggle("is-hidden", !connected);
        voiceMiniEl.setAttribute("aria-hidden", connected ? "false" : "true");

        if (!connected){
            if (voiceMiniTitleEl) voiceMiniTitleEl.textContent = "Голос";
            if (voiceMiniSubEl) voiceMiniSubEl.textContent = "не подключено";
            return;
        }

        const cid = String(groupCallChannelId);
        let chName = "";
        try{
            const el = document.querySelector(`.guild-channel-item[data-channel-id="${cid}"]`);
            if (el) chName = (el.dataset.name || "").trim();
        }catch(e){}

        if (voiceMiniTitleEl) voiceMiniTitleEl.textContent = "Голосовая связь подключена";
        if (voiceMiniSubEl) {
            const gnm = (currentGuildName || "").trim();
            const left = chName ? `🔊 ${chName}` : `🔊 #${cid}`;
            voiceMiniSubEl.textContent = gnm ? `${left} / ${gnm}` : left;
        }

        // Keep "Me" status aligned with voice state
        try { updateMePanelStatusText(); } catch (e) {}
    }catch(e){}
}

function updateDmCallMini(){
    try{
        if (!dmCallMiniEl) dmCallMiniEl = document.getElementById("dm-call-mini");
        if (!dmCallMiniEl) return;

        if (!dmCallMiniTitleEl) dmCallMiniTitleEl = document.getElementById("dm-call-mini-title");
        if (!dmCallMiniSubEl) dmCallMiniSubEl = document.getElementById("dm-call-mini-sub");
        if (!dmCallMiniLeaveBtn) dmCallMiniLeaveBtn = document.getElementById("dm-call-mini-leave");
        if (!dmCallMiniMicBtn) dmCallMiniMicBtn = document.getElementById("dm-call-mini-mic");
        if (!dmCallMiniSoundBtn) dmCallMiniSoundBtn = document.getElementById("dm-call-mini-sound");
        if (!dmCallMiniScreenBtn) dmCallMiniScreenBtn = document.getElementById("dm-call-mini-screen");
        if (!dmCallMiniSignalEl) dmCallMiniSignalEl = document.getElementById("dm-call-mini-signal");

        const incoming = (!peerConnection && pendingIncomingCall && pendingIncomingCall.from_id);
        const active = (!!peerConnection && !!currentCallTargetId);
        const show = (!groupCallActive) && (active || incoming);

        if (!show){
            dmCallMiniEl.classList.add("is-hidden");
            dmCallMiniEl.setAttribute("aria-hidden", "true");
            return;
        }

        dmCallMiniEl.classList.remove("is-hidden");
        dmCallMiniEl.setAttribute("aria-hidden", "false");

        const peerId = active ? currentCallTargetId : (incoming ? pendingIncomingCall.from_id : null);
        const peerName = peerId ? getUserNameById(peerId) : "";
        // Title should reflect real call state (Discord-like)
if (dmCallMiniTitleEl){
    let title = "Подключение";
    try{
        const callBar = (window._callUI && window._callUI.callBar) ? window._callUI.callBar : document.getElementById("call-bar");
        const mode = callBar ? String(callBar.dataset.mode || "") : "";
        const st = (typeof getReconnectState === 'function') ? getReconnectState() : null;
        const connected = (mode === "connected") || (typeof callSeconds !== 'undefined' && callSeconds && callSeconds > 0);
        const reconnecting = (mode === "reconnecting" || mode === "dropped") || (st && st.type === "dm");
        if (incoming) title = "Входящий звонок";
        else if (connected) title = "На связи";
        else if (reconnecting) title = "Переподключение";
        else if (mode === "outgoing") title = "Звоним...";
        else if (mode === "connecting") title = "Идёт соединение...";
    }catch(e){
        title = incoming ? "Входящий звонок" : "Подключение";
    }
    dmCallMiniTitleEl.textContent = title;
}
        if (dmCallMiniSubEl) dmCallMiniSubEl.textContent = peerName || "…";

        if (dmCallMiniMicBtn) dmCallMiniMicBtn.classList.toggle("toggled", !!isMicMuted);
        if (dmCallMiniSoundBtn) dmCallMiniSoundBtn.classList.toggle("toggled", !!isRemoteMuted);

        // Bind controls once
        if (dmCallMiniLeaveBtn && !dmCallMiniLeaveBtn.dataset.bound){
            dmCallMiniLeaveBtn.dataset.bound = "1";
            dmCallMiniLeaveBtn.addEventListener("click", (e) => {
                e.preventDefault();
                e.stopPropagation();
                try{
                    if (!peerConnection && pendingIncomingCall && pendingIncomingCall.from_id && socket){
                        socket.emit("reject_call", {target_id: pendingIncomingCall.from_id, force: true});
                        pendingIncomingCall = null;
                        updateCallUI(false, "");
                        updateDmCallMini();
                        return;
                    }
                }catch(err){}
                try{ endCall(true); }catch(err){}
                try{ updateDmCallMini(); }catch(err){}
            });
        }

        if (dmCallMiniMicBtn && !dmCallMiniMicBtn.dataset.bound){
            dmCallMiniMicBtn.dataset.bound = "1";
            dmCallMiniMicBtn.addEventListener("click", (e) => {
                e.preventDefault(); e.stopPropagation();
                try{ toggleMic(); }catch(err){}
                try{ updateDmCallMini(); }catch(err){}
                try{ updateCallParticipantBadges(); }catch(err){}
            });
        }

        if (dmCallMiniSoundBtn && !dmCallMiniSoundBtn.dataset.bound){
            dmCallMiniSoundBtn.dataset.bound = "1";
            dmCallMiniSoundBtn.addEventListener("click", (e) => {
                e.preventDefault(); e.stopPropagation();
                try{ toggleSound(); }catch(err){}
                try{ updateDmCallMini(); }catch(err){}
                try{ updateCallParticipantBadges(); }catch(err){}
            });
        }

        if (dmCallMiniScreenBtn && !dmCallMiniScreenBtn.dataset.bound){
            dmCallMiniScreenBtn.dataset.bound = "1";
            dmCallMiniScreenBtn.addEventListener("click", (e) => {
                e.preventDefault(); e.stopPropagation();
                try{
                    // Inline screenshare: show inside call window (or start if none)
                    if (typeof openScreenShareModalFromState === 'function') openScreenShareModalFromState();
                    else startOrSwitchScreenShare();
                }catch(err){}
            });
        }

    }catch(e){}
}

