function _isSelectedVoiceChannelUI(channelId){
    try{
        if (String(currentChannelType || "") !== "voice") return false;
        const cid = channelId ? String(channelId) : String(currentChannelId || "");
        if (!cid) return false;
        // Voice UI is only for real voice channels (not adhoc group calls)
        return true;
    }catch(e){ return false; }
}

function _setVoiceTileText(title, sub){
    try{ if (voiceTileTitleEl) voiceTileTitleEl.textContent = title || "Голосовой канал"; }catch(e){}
    try{ if (voiceTileSubEl) voiceTileSubEl.textContent = sub || ""; }catch(e){}
}

function _attachVoiceShareVideo(stream, mode){
    // mode: 'none' | 'local' | 'remote'
    try{
        if (!voiceShareVideoEl) return;

        const mainTile = voiceTileMainEl || document.getElementById("voice-tile-main");

        if (!stream){
            try{ voiceShareVideoEl.pause(); }catch(e){}
            voiceShareVideoEl.srcObject = null;
            voiceShareVideoEl.style.display = "none";
            try{ if (mainTile) mainTile.classList.remove("has-share"); }catch(e){}
            try{ if (voiceTileOverlayEl) voiceTileOverlayEl.style.display = ""; }catch(e){}
            try{ if (voiceStageEmptyEl) voiceStageEmptyEl.style.display = ""; }catch(e){}
            return;
        }

        // When sharing, hide overlay UI that otherwise sits above the video.
        try{ if (voiceTileOverlayEl) voiceTileOverlayEl.style.display = "none"; }catch(e){}

        // Audio control (voice screenshare):
        // - local preview muted (avoid echo)
        // - remote can be muted/unmuted + per-stream volume
        try{ voiceShareVideoEl.muted = (String(mode||'') === 'local') ? true : !!isScreenMuted; try{ if (String(mode||'') === 'local') voiceShareVideoEl.volume = 0; }catch(e){} voiceShareVideoEl.autoplay = true; voiceShareVideoEl.playsInline = true; try{ if (String(mode||'') === 'local') voiceShareVideoEl.volume = 0; }catch(e){} }catch(e){}
        voiceShareVideoEl.srcObject = stream;
        try{ __ncApplySsVolumeToVideo(voiceShareVideoEl); }catch(e){}
        voiceShareVideoEl.style.display = "";
        try{ if (mainTile) mainTile.classList.add("has-share"); }catch(e){}
        try{ if (voiceStageEmptyEl) voiceStageEmptyEl.style.display = "none"; }catch(e){}
        try{ if (window && typeof window._ncSafePlayVideo === 'function') window._ncSafePlayVideo(voiceShareVideoEl, 5); else voiceShareVideoEl.play(); }catch(e){}
    }catch(e){}
}
function _ncGroupShareHasAny(){
    try{
        const hasLocal = !!(groupScreenSharing && groupScreenStream);
        const hasRemote = !!(groupRemoteScreensByPeer && Object.keys(groupRemoteScreensByPeer).length);
        return hasLocal || hasRemote;
    }catch(e){ return false; }
}

function _ncGetGroupShareStreamByKey(key){
    try{
        const k = String(key || '');
        if (!k) return null;
        if (k === 'local') return groupScreenStream || null;
        return (groupRemoteScreensByPeer && groupRemoteScreensByPeer[k]) ? groupRemoteScreensByPeer[k] : null;
    }catch(e){ return null; }
}

function _ncGetGroupShareKeys(){
    const keys = [];
    try{
        if (groupScreenSharing && groupScreenStream) keys.push('local');
    }catch(e){}
    try{
        Object.keys(groupRemoteScreensByPeer || {}).forEach(k => { if (k) keys.push(String(k)); });
    }catch(e){}
    return keys;
}

function _ncPickDefaultGroupShareKey(){
    const keys = _ncGetGroupShareKeys();
    const has = (k) => keys.includes(String(k));
    if (groupPinnedShareKey && has(groupPinnedShareKey)) return String(groupPinnedShareKey);
    if (groupSelectedShareKey && has(groupSelectedShareKey)) return String(groupSelectedShareKey);
    // Prefer remote first (Discord-like)
    const remote = keys.filter(k => k !== 'local');
    if (remote.length) return String(remote[0]);
    if (keys.includes('local')) return 'local';
    return null;
}

function _ncApplyGroupShareStage(){
    try{
        const key = _ncPickDefaultGroupShareKey();
        groupSelectedShareKey = key;
        const stream = _ncGetGroupShareStreamByKey(key);
        if (!stream){
            _attachVoiceShareVideo(null, 'none');
            try{ if (voiceShareStripEl) voiceShareStripEl.style.display = 'none'; }catch(e){}

            // Also reset inline call HUD demo stages (group calls should behave like Discord)
            try{
                const refs = window._callUI || {};
                const callBarEl = refs.callBar || document.getElementById('call-bar');
                if (callBarEl && (callBarEl.dataset.mode || '') !== 'idle'){
                    try{ window.__ncCallHudRemoteShareKey = ''; }catch(_){ }
                    try{ window.__ncCallHudLocalShareKey = ''; }catch(_){ }
                    try{ _attachCallInlineScreenShare(null, 'remote'); }catch(_){ }
                    try{ _attachCallInlineScreenShare(null, 'local'); }catch(_){ }
                }
            }catch(_){ }
            return;
        }
        const mode = (String(key)==='local') ? 'local' : 'remote';
        _attachVoiceShareVideo(stream, mode);
        // Apply per-demo volume for the currently staged share
        try{
            const id = (String(key)==='local') ? 'g:local' : (key ? ('g:'+String(key)) : '');
            if (id && typeof voiceShareVideoEl !== 'undefined' && voiceShareVideoEl){
                const v01 = __ncGetShareVolume01(id);
                try{ voiceShareVideoEl.muted = (String(mode)==='local') ? true : (v01 <= 0.001); }catch(_){}
                try{ _ncSetMediaElementGain(voiceShareVideoEl, (String(mode)==='local') ? 0 : v01); }catch(_){
                    try{ voiceShareVideoEl.volume = Math.max(0, Math.min(1, (String(mode)==='local') ? 0 : v01)); }catch(__){}
                }
            }
        }catch(_){}


        // Title/sub like Discord
        try{
            if (String(key)==='local'){
                _setVoiceTileText("Демонстрация экрана", "Ты показываешь экран");
            } else {
                const u = currentMembersById && key ? currentMembersById[String(key)] : null;
                _setVoiceTileText("Демонстрация экрана", u ? ("Показывает: " + (u.username || "")) : "Кто-то показывает экран");
            }
        }catch(e){}

        // Mirror staged screenshare into the inline call HUD (so group demo is visible inside calls)
        try{
            const __inVoiceUi = !!(typeof isVoiceView !== 'undefined' && isVoiceView && String(currentChannelType||'') === 'voice');
            if (!__inVoiceUi) {
                const refs = window._callUI || {};
            const callBarEl = refs.callBar || document.getElementById('call-bar');
            if (callBarEl && (callBarEl.dataset.mode || '') !== 'idle'){
                // Local preview always (if sharing)
                if (groupScreenSharing && groupScreenStream){
                    try{ window.__ncCallHudLocalShareKey = 'g:local'; }catch(_){ }
                    try{ _attachCallInlineScreenShare(groupScreenStream, 'local'); }catch(_){ }
                } else {
                    try{ window.__ncCallHudLocalShareKey = ''; }catch(_){ }
                    try{ _attachCallInlineScreenShare(null, 'local'); }catch(_){ }
                }

                // Remote stage: show selected remote share; if selection is local, keep remote hidden
                let rKey = (String(key)==='local') ? '' : String(key||'');
                let rStream = (rKey && groupRemoteScreensByPeer) ? groupRemoteScreensByPeer[rKey] : null;
                if (!rStream){ rKey=''; rStream=null; }

                try{ window.__ncCallHudRemoteShareKey = rKey ? ('g:'+rKey) : ''; }catch(_){ }
                try{ _attachCallInlineScreenShare(rStream, 'remote'); }catch(_){ }
            }
            }
        }catch(_){ }
    }catch(e){}
}

function _ncRenderVoiceShareStrip(){
    try{
        if (!voiceShareStripEl) return;
        const keys = _ncGetGroupShareKeys();
        if (!keys.length){
            voiceShareStripEl.innerHTML = '';
            voiceShareStripEl.style.display = 'none';
            return;
        }
        voiceShareStripEl.style.display = 'flex';
        // Keep a stable DOM if possible
        const existing = {};
        voiceShareStripEl.querySelectorAll('[data-share-key]').forEach(el => {
            try{ existing[String(el.dataset.shareKey||'')] = el; }catch(e){}
        });

        const meName = (typeof currentUserName !== 'undefined' && currentUserName) ? String(currentUserName) : "Вы";

        const frag = document.createDocumentFragment();

        keys.forEach(k => {
            const key = String(k);
            let tile = existing[key] || null;
            if (!tile){
                tile = document.createElement('div');
                tile.className = 'vshare-tile';
                tile.dataset.shareKey = key;

                const vid = document.createElement('video');
                vid.className = 'vshare-thumb';
                vid.autoplay = true;
                vid.playsInline = true;
                vid.muted = true;

                const meta = document.createElement('div');
                meta.className = 'vshare-meta';

                const name = document.createElement('span');
                name.className = 'vshare-name';

                const pin = document.createElement('button');
                pin.className = 'vshare-pin';
                pin.type = 'button';
                pin.textContent = '📌';

                meta.appendChild(name);
                meta.appendChild(pin);

                tile.appendChild(vid);
                tile.appendChild(meta);

                tile.addEventListener('click', (e) => {
                    try{
                        const kk = tile.dataset.shareKey;
                        groupSelectedShareKey = kk;
                        if (groupPinnedShareKey && String(groupPinnedShareKey) === String(kk)) {
                            // already pinned
                        }
                        _ncApplyGroupShareStage();
                        _ncRenderVoiceShareStrip();
                    }catch(err){}
                });

                pin.addEventListener('click', (e) => {
                    try{ e.preventDefault(); e.stopPropagation(); }catch(_){}
                    const kk = tile.dataset.shareKey;
                    if (groupPinnedShareKey && String(groupPinnedShareKey) === String(kk)) groupPinnedShareKey = null;
                    else groupPinnedShareKey = kk;
                    _ncApplyGroupShareStage();
                    _ncRenderVoiceShareStrip();
                });
            }

            // Update content
            try{
                const stream = _ncGetGroupShareStreamByKey(key);
                const vid = tile.querySelector('video');
                if (vid && stream && vid.srcObject !== stream) {
                    vid.srcObject = stream;
                    _ncSafePlayVideo(vid, 3);
                }
            }catch(e){}

            try{
                const nameEl = tile.querySelector('.vshare-name');
                if (nameEl){
                    if (key === 'local') nameEl.textContent = meName + " (вы)";
                    else {
                        const u = currentMembersById && key ? currentMembersById[String(key)] : null;
                        nameEl.textContent = u ? (u.username || ("User " + key)) : ("User " + key);
                    }
                }
            }catch(e){}

            // Selection/pin styles
            const sel = _ncPickDefaultGroupShareKey();
            tile.classList.toggle('is-sel', sel && String(sel) === String(key));
            const pinBtn = tile.querySelector('.vshare-pin');
            if (pinBtn){
                const isPin = groupPinnedShareKey && String(groupPinnedShareKey) === String(key);
                pinBtn.classList.toggle('is-pin', !!isPin);
            }

            frag.appendChild(tile);
        });

        // Replace strip content
        voiceShareStripEl.innerHTML = '';
        voiceShareStripEl.appendChild(frag);
    }catch(e){}
}


/* ---------------------------------------------------------------------------
   Screenshare grid + theater overlay (Discord-like)
   - DM: local + remote screenshares are shown as fixed tiles
   - Group: all active shares are shown simultaneously
   - Click tile => fullscreen overlay (theater)
--------------------------------------------------------------------------- */

function __ncInitTheaterOverlay(){
    try{
        if (!callTheaterOverlayEl || callTheaterOverlayEl.__ncInit) return;
        callTheaterOverlayEl.__ncInit = true;

        const close = () => { try{ __ncCloseTheaterOverlay(); }catch(e){} };

        try{
            if (btnCallTheaterCloseEl) btnCallTheaterCloseEl.addEventListener('click', close);
        try{
            if (btnCallTheaterFullEl) btnCallTheaterFullEl.addEventListener('click', () => {
                try{
                    // Fullscreen should show the *entire* shared screen, not a scaled-down box.
                    // Use the card container (not <video>) so our header/buttons stay visible.
                    const card = callTheaterOverlayEl ? callTheaterOverlayEl.querySelector('.call-theater-card') : null;
                    __ncToggleFullscreen(card || callTheaterOverlayEl || callTheaterVideoEl || null);
                }catch(_){ }
            });
        }catch(e){}
        }catch(e){}

        try{
            callTheaterOverlayEl.addEventListener('click', (e) => {
                try{
                    const t = e && e.target ? e.target : null;
                    const closeMe = (t && t.dataset && t.dataset.theaterClose === '1');
                    if (closeMe) close();
                }catch(_){}
            });
        }catch(e){}

        try{
            document.addEventListener('keydown', (e) => {
                try{
                    if (!__ncTheaterOpen) return;
                    if (e && e.key === 'Escape') close();
                }catch(_){}
            });
        }catch(e){}
    }catch(e){}
}

function __ncCloseTheaterOverlay(){
    try{ __ncTheaterOpen = false; __ncTheaterOpenId = null; }catch(e){}
    try{ if (__ncIsFullscreen && __ncIsFullscreen()) __ncExitFullscreen(); }catch(e){}
    try{
        if (callTheaterOverlayEl){
            callTheaterOverlayEl.classList.add('is-hidden');
            callTheaterOverlayEl.setAttribute('aria-hidden', 'true');
        }
    }catch(e){}
    try{
        if (callTheaterVideoEl){
            try{ callTheaterVideoEl.pause(); }catch(_){}
            callTheaterVideoEl.srcObject = null;
        }
    }catch(e){}
}

function __ncOpenTheaterOverlay(item){
    try{
        if (!item || !item.stream) return;
        if (!callTheaterOverlayEl || !callTheaterVideoEl) return;

        __ncTheaterOpen = true;
        __ncTheaterOpenId = String(item.id || '');

        try{
            if (callTheaterTitleEl) callTheaterTitleEl.textContent = (item.sub ? (item.title + " · " + item.sub) : (item.title || "Демонстрация экрана"));
        }catch(e){}

        try{
            callTheaterOverlayEl.classList.remove('is-hidden');
            callTheaterOverlayEl.setAttribute('aria-hidden', 'false');
        }catch(e){}

        // Theater audio:
        // - local preview muted (avoid echo)
        // - remote: allow audio + per-demo volume (slider in PKM menu)
        try{
            const sid = String(item.id || '');
            const isLocal = !!(item && item.isLocal);
            const v01 = __ncGetShareVolume01(sid);
            callTheaterVideoEl.muted = isLocal ? true : (v01 <= 0.001);
            callTheaterVideoEl.autoplay = true;
            callTheaterVideoEl.playsInline = true;
            try{ _ncSetMediaElementGain(callTheaterVideoEl, isLocal ? 0 : v01); }catch(_){
                try{ callTheaterVideoEl.volume = Math.max(0, Math.min(1, isLocal ? 0 : v01)); }catch(__){}
            }
        }catch(e){} 
        try{
            callTheaterVideoEl.srcObject = item.stream;
        }catch(e){}

        try{
            if (typeof _ncSafePlayVideo === 'function') _ncSafePlayVideo(callTheaterVideoEl, 6);
            else { const p = callTheaterVideoEl.play(); if (p && p.catch) p.catch(()=>{}); }
        }catch(e){}
    }catch(e){}
}

function __ncUserLabel(uid){
    try{
        if (uid == null) return '';
        const u = (typeof currentMembersById !== 'undefined' && currentMembersById) ? currentMembersById[String(uid)] : null;
        const name = u ? (u.username || u.name || u.display_name || '') : '';
        return name ? String(name) : String(uid);
    }catch(e){
        try{ return String(uid); }catch(_){ return ''; }
    }
}

function __ncBuildDmShareItems(){
    const out = [];
    try{
        if (typeof isScreenSharing !== 'undefined' && isScreenSharing && screenShareStream){
            out.push({
                id: 'dm:local',
                scope: 'dm',
                shareKey: 'local',
                isLocal: true,
                stream: screenShareStream,
                title: 'Демонстрация экрана',
                sub: 'Ты показываешь'
            });
        }
    }catch(e){}
    try{
        if (typeof remoteIsScreenSharing !== 'undefined' && remoteIsScreenSharing && remoteScreenStream){
            const n = (typeof currentCallTargetId !== 'undefined' && currentCallTargetId) ? __ncUserLabel(currentCallTargetId) : '';
            out.push({
                id: 'dm:remote',
                scope: 'dm',
                shareKey: 'remote',
                isLocal: false,
                stream: remoteScreenStream,
                title: 'Демонстрация экрана',
                sub: n ? ('Показывает: ' + n) : 'Показывает друг'
            });
        }
    }catch(e){}
    return out;
}

function __ncBuildGroupShareItems(){
    const out = [];
    try{
        if (typeof groupScreenSharing !== 'undefined' && groupScreenSharing && groupScreenStream){
            out.push({
                id: 'g:local',
                scope: 'group',
                shareKey: 'local',
                isLocal: true,
                stream: groupScreenStream,
                title: 'Демонстрация экрана',
                sub: 'Ты показываешь'
            });
        }
    }catch(e){}
    try{
        if (typeof groupRemoteScreensByPeer !== 'undefined' && groupRemoteScreensByPeer){
            Object.keys(groupRemoteScreensByPeer || {}).forEach(pid => {
                try{
                    const stream = groupRemoteScreensByPeer[pid];
                    if (!stream) return;
                    const name = __ncUserLabel(pid);
                    out.push({
                        id: 'g:' + String(pid),
                        scope: 'group',
                        shareKey: String(pid),
                        isLocal: false,
                        stream: stream,
                        title: 'Демонстрация экрана',
                        sub: name ? ('Показывает: ' + name) : 'Кто-то показывает'
                    });
                }catch(_){}
            });
        }
    }catch(e){}
    return out;
}

function __ncRenderShareGrid(container, items, opts){
    try{
        if (!container) return;
        const o = opts || {};
        const selected = String(o.selectedKey || '');

        // Keep latest item references for context menu / reopen
        try{
            if (!__ncShareItemById) __ncShareItemById = {};
        }catch(e){}


        const existing = {};
        try{
            container.querySelectorAll('[data-share-id]').forEach(el => {
                try{ existing[String(el.dataset.shareId || '')] = el; }catch(_){}
            });
        }catch(e){}

        const frag = document.createDocumentFragment();

        (items || []).forEach(item => {
            try{
                const id = String(item.id || '');
                if (!id) return;

                try{ __ncShareItemById[id] = item; }catch(e){}

                let tile = existing[id] || null;

                if (!tile){
                    tile = document.createElement('div');
                    tile.className = 'share-tile';
                    tile.tabIndex = 0;
                    tile.dataset.shareId = id;
                    tile.dataset.scope = String(item.scope || '');
                    tile.dataset.shareKey = String(item.shareKey || '');

                    const vid = document.createElement('video');
                    vid.className = 'share-video';
                    vid.autoplay = true;
                    vid.playsInline = true;
                    vid.muted = true;
                    try{ vid.volume = 0; }catch(_){}

                    const meta = document.createElement('div');
                    meta.className = 'share-meta';

                    const left = document.createElement('div');
                    left.style.minWidth = '0';

                    const t = document.createElement('div');
                    t.className = 'share-title';

                    const s = document.createElement('div');
                    s.className = 'share-sub';

                    left.appendChild(t);
                    left.appendChild(s);

                    const pill = document.createElement('div');
                    pill.className = 'share-pill';
                    pill.textContent = (item && item.isLocal) ? 'Ты' : 'LIVE';

                    meta.appendChild(left);
                    meta.appendChild(pill);

                    tile.appendChild(vid);
                    tile.appendChild(meta);

                    const onOpen = (ev) => {
                        try{ if (ev){ ev.preventDefault(); ev.stopPropagation(); } }catch(e){}

                        let cur = null;
                        try{
                            cur = (__ncShareItemById && id) ? __ncShareItemById[id] : null;
                        }catch(e){ cur = null; }
                        if (!cur) cur = item;

                        try{
                            if (String(cur.scope) === 'group'){
                                groupSelectedShareKey = String(cur.shareKey || '');
                                try{ _ncApplyGroupShareStage(); }catch(e){}
                                try{ _ncRenderVoiceShareGrid(); }catch(e){}
                            }
                        }catch(e){}
                        __ncOpenTheaterOverlay(cur);
                    };

                    tile.addEventListener('click', onOpen);
                                        const openCtx = (ev) => {
                      try{
                        if (!ev) return;
                        const isRight = (ev.type === 'contextmenu') || (ev.button === 2) || (ev.which === 3) || (typeof ev.buttons === 'number' && (ev.buttons & 2));
                        if (!isRight) return;

                        const before = String(__ncShareCtxOpenId || '');
                        try{ __ncOpenShareCtxMenu(ev, id); }catch(_){}

                        // Only swallow browser menu if our menu actually opened
                        const opened = (__ncShareCtxMenuEl && !__ncShareCtxMenuEl.classList.contains('is-hidden') && String(__ncShareCtxOpenId || '') === String(id));
                        if (opened || before !== String(__ncShareCtxOpenId || '')) {
                          try{ ev.preventDefault(); }catch(_){}
                          try{ ev.stopPropagation(); }catch(_){}
                          try{ if (ev.stopImmediatePropagation) ev.stopImmediatePropagation(); }catch(_){}
                        }
                      }catch(_){}
                    };

                    // PKM fallback: some layers swallow 'contextmenu', so also listen right-button down
                    tile.addEventListener('contextmenu', openCtx, { capture:true });
                    tile.addEventListener('pointerdown', openCtx, { capture:true });
                    tile.addEventListener('mousedown', openCtx, { capture:true });
                    tile.addEventListener('keydown', (e) => {
                        try{
                            if (e && (e.key === 'Enter' || e.key === ' ')) onOpen(e);
                        }catch(_){}
                    });
                }

                // Update selected state (group only)
                try{
                    if (String(item.scope) === 'group'){
                        tile.classList.toggle('is-selected', String(item.shareKey || '') === selected);
                    } else {
                        tile.classList.remove('is-selected');
                    }
                }catch(e){}

                // Update text
                try{
                    const t = tile.querySelector('.share-title');
                    const s = tile.querySelector('.share-sub');
                    if (t) t.textContent = item.title || 'Демонстрация экрана';
                    if (s) s.textContent = item.sub || '';
                }catch(e){}

                // Attach stream
                try{
                    const vid = tile.querySelector('video');
                    if (vid && item.stream && vid.srcObject !== item.stream){
                        vid.srcObject = item.stream;
                        try{
                            if (typeof _ncSafePlayVideo === 'function') _ncSafePlayVideo(vid, 3);
                            else { const p = vid.play(); if (p && p.catch) p.catch(()=>{}); }
                        }catch(_){}
                    }
                }catch(e){}

                delete existing[id];
                frag.appendChild(tile);
            }catch(e){}
        });

        // Remove stale
        try{
            Object.keys(existing).forEach(id => {
                try{ existing[id].remove(); }catch(_){}
            });
        }catch(e){}

        container.innerHTML = '';
        container.appendChild(frag);
    }catch(e){}
}



/* ---------------------------------------------------
   Demo tile context menu + fullscreen helpers
--------------------------------------------------- */

// Per-demo volume (0..2.0). Default 1.0 for remote, 0 for local preview.
var __ncShareVolumeById = __ncShareVolumeById || {};
function __ncGetShareVolume01(id){
  try{
    const k = String(id||'');
    if (!k) return 1.0;
    const v = __ncShareVolumeById[k];
    if (typeof v === 'number' && isFinite(v)) return Math.max(0, Math.min(2, v));
    return 1.0;
  }catch(_){ return 1.0; }
}
function __ncSetShareVolume01(id, v01){
  try{
    const k = String(id||'');
    if (!k) return;
    let v = Number(v01);
    if (!isFinite(v)) v = 1.0;
    v = Math.max(0, Math.min(2, v));
    __ncShareVolumeById[k] = v;

    // Apply to theater if open for this demo
    try{
      if (__ncTheaterOpen && String(__ncTheaterOpenId||'') === k && callTheaterVideoEl){
        try{ callTheaterVideoEl.muted = (v <= 0.001); }catch(_){}
        try{ _ncSetMediaElementGain(callTheaterVideoEl, v); }catch(_){ try{ callTheaterVideoEl.volume = Math.max(0, Math.min(1, v)); }catch(__){} }
      }
    }catch(_){}

    // Apply to voice stage if this demo is currently staged
    try{
      if (typeof groupCallActive !== 'undefined' && groupCallActive){
        const key = String(groupSelectedShareKey||'');
        const curId = (key === 'local') ? 'g:local' : (key ? ('g:'+key) : '');
        if (curId && curId === k && typeof voiceShareVideoEl !== 'undefined' && voiceShareVideoEl){
          try{ voiceShareVideoEl.muted = (v <= 0.001); }catch(_){}
          try{ _ncSetMediaElementGain(voiceShareVideoEl, v); }catch(_){ try{ voiceShareVideoEl.volume = Math.max(0, Math.min(1, v)); }catch(__){} }
        }
      }
    }catch(_){}
  }catch(_){}
}



function __ncRequestFullscreen(el){
    try{
        if (!el) return;
        const fn = el.requestFullscreen || el.webkitRequestFullscreen || el.mozRequestFullScreen || el.msRequestFullscreen;
        if (fn) {
            const r = fn.call(el);
            // requestFullscreen returns a Promise in modern browsers.
            try{ if (r && r.catch) r.catch(()=>{}); }catch(_){ }
        }
    }catch(e){}
}

function __ncToggleFullscreen(el){
    try{
        if (__ncIsFullscreen && __ncIsFullscreen()) {
            __ncExitFullscreen();
            return;
        }
        __ncRequestFullscreen(el || document.documentElement);
    }catch(e){}
}
function __ncExitFullscreen(){
    try{
        const d = document;
        const fn = d.exitFullscreen || d.webkitExitFullscreen || d.mozCancelFullScreen || d.msExitFullscreen;
        if (fn) fn.call(d);
    }catch(e){}
}
function __ncIsFullscreen(){
    try{
        const d = document;
        return !!(d.fullscreenElement || d.webkitFullscreenElement || d.mozFullScreenElement || d.msFullscreenElement);
    }catch(e){ return false; }
}

function __ncHideShareCtxMenu(){
    try{
        __ncShareCtxOpenId = null;
        if (__ncShareCtxMenuEl){
            __ncShareCtxMenuEl.classList.add('is-hidden');
            __ncShareCtxMenuEl.setAttribute('aria-hidden', 'true');
        }
    }catch(e){}
}

function __ncOpenShareCtxMenu(ev, shareId){
    try{
        if (!__ncShareCtxMenuEl || !ev) return;
        const id = String(shareId || '');
        if (!id) return;

        // FIX219: don't open stream menu if there is no active stream for this tile
        try{
            const item = (__ncShareItemById && id) ? __ncShareItemById[id] : null;
            if (!item || !item.stream){
                __ncHideShareCtxMenu();
                return;
            }
        }catch(e){}

        try{ ev.preventDefault(); ev.stopPropagation(); }catch(_){}

        __ncShareCtxOpenId = id;

        // Show first to measure
        try{
            __ncShareCtxMenuEl.classList.remove('is-hidden');
            __ncShareCtxMenuEl.setAttribute('aria-hidden', 'false');
        }catch(e){}

        const vw = Math.max(0, window.innerWidth || 0);
        const vh = Math.max(0, window.innerHeight || 0);
        const rect = __ncShareCtxMenuEl.getBoundingClientRect();

        let left = (ev.clientX != null ? ev.clientX : 8);
        let top  = (ev.clientY != null ? ev.clientY : 8);

        const pad = 8;
        if (left + rect.width > vw - pad) left = vw - pad - rect.width;
        if (top + rect.height > vh - pad) top = vh - pad - rect.height;
        if (left < pad) left = pad;
        if (top < pad) top = pad;

        __ncShareCtxMenuEl.style.left = left + 'px';
        __ncShareCtxMenuEl.style.top  = top  + 'px';

        // Sync per-demo volume slider
        try{
            const r = __ncShareCtxMenuEl.querySelector('[data-action="share-volume"]');
            const vv = __ncShareCtxMenuEl.querySelector('#share-ctx-vol-val');
            if (r){
                const v01 = __ncGetShareVolume01(id);
                const pct = Math.round(v01 * 100);
                r.value = String(pct);
                if (vv) vv.textContent = pct + '%';
            }
        }catch(_){}
    }catch(e){}
}

function __ncInitShareCtxMenu(){
    try{
        if (!__ncShareCtxMenuEl || __ncShareCtxMenuEl.__ncInit) return;
        __ncShareCtxMenuEl.__ncInit = true;

        const onAction = async (action) => {
            try{
                const id = String(__ncShareCtxOpenId || '');
                const item = (__ncShareItemById && id) ? __ncShareItemById[id] : null;
                __ncHideShareCtxMenu();
                if (!id || !item) return;

                if (action === 'open'){
                    __ncOpenTheaterOverlay(item);
                } else if (action === 'fullscreen'){
                    __ncOpenTheaterOverlay(item);
                    try{
                        setTimeout(() => {
                            try{
                                const card = callTheaterOverlayEl ? callTheaterOverlayEl.querySelector('.call-theater-card') : null;
                                __ncToggleFullscreen(card || callTheaterOverlayEl || callTheaterVideoEl || null);
                            }catch(_e){}
                        }, 30);
                    }catch(_){}
                } else if (action === 'copy'){
                    const text = id;
                    try{
                        if (navigator && navigator.clipboard && navigator.clipboard.writeText){
                            await navigator.clipboard.writeText(text);
                        } else {
                            const ta = document.createElement('textarea');
                            ta.value = text;
                            ta.style.position = 'fixed';
                            ta.style.left = '-9999px';
                            document.body.appendChild(ta);
                            ta.select();
                            document.execCommand('copy');
                            ta.remove();
                        }
                        try{ if (typeof showToast === 'function') showToast('Скопировано: ' + text); }catch(_){}
                    }catch(_){}
                }
            }catch(e){}
        };

        try{
            __ncShareCtxMenuEl.addEventListener('click', (e) => {
                try{
                    const t = e && e.target ? e.target : null;
                    const btn = t && t.closest ? t.closest('[data-action]') : null;
                    const action = btn ? String(btn.dataset.action || '') : '';
                    if (!action) return;
                    try{ e.preventDefault(); e.stopPropagation(); }catch(_){}
                    onAction(action);
                }catch(_){}
            });
        }catch(e){}

        // Hide on LMB outside / escape (keep menu open on PKM and while adjusting slider)
        try{
            const stop = (e) => { try{ if(e){ e.stopPropagation(); if(e.stopImmediatePropagation) e.stopImmediatePropagation(); } }catch(_){ } };
            try{ __ncShareCtxMenuEl.addEventListener('pointerdown', stop, true); }catch(_){}
            try{ __ncShareCtxMenuEl.addEventListener('mousedown', stop, true); }catch(_){}
            try{ __ncShareCtxMenuEl.addEventListener('click', stop, true); }catch(_){}
        }catch(_){}

        try{
            // Close only when clicking outside with LEFT mouse button
            document.addEventListener('pointerdown', (e) => {
                try{
                    if (!__ncShareCtxOpenId) return;
                    if (!e) return;
                    // 0 = left button (pointer events). Some browsers use 'button'.
                    const b = (typeof e.button === 'number') ? e.button : -1;
                    if (b !== 0) return;
                    const t = e.target || null;
                    if (__ncShareCtxMenuEl && t && __ncShareCtxMenuEl.contains(t)) return;
                    __ncHideShareCtxMenu();
                }catch(_){}
            }, true);
        }catch(_){}

        try{
            document.addEventListener('keydown', (e) => {
                try{
                    if (!__ncShareCtxOpenId) return;
                    if (e && e.key === 'Escape') __ncHideShareCtxMenu();
                }catch(_){}
            }, true);
        }catch(_){}

        // Volume slider handler
        try{
            const r = __ncShareCtxMenuEl.querySelector('[data-action="share-volume"]');
            const vv = __ncShareCtxMenuEl.querySelector('#share-ctx-vol-val');
            const onVol = (e) => {
                try{
                    const id = String(__ncShareCtxOpenId || '');
                    if (!id) return;
                    const raw = r ? Number(r.value) : 100;
                    const pct = (isFinite(raw) ? raw : 100);
                    if (vv) vv.textContent = Math.round(pct) + '%';
                    __ncSetShareVolume01(id, pct / 100);
                }catch(_){}
            };
            if (r){
                r.addEventListener('input', onVol, true);
                r.addEventListener('change', onVol, true);
            }
        }catch(_){}
    }catch(e){}
}



function _ncRenderCallShareGrid(){
    try{
        if (!callShareGridEl || !callSsGridEl) return;
        const isGroup = !!(typeof groupCallActive !== 'undefined' && groupCallActive);
        const items = isGroup ? __ncBuildGroupShareItems() : __ncBuildDmShareItems();
        const has = !!(items && items.length);

        try{
            callShareGridEl.classList.toggle('is-hidden', !has);
            callShareGridEl.setAttribute('aria-hidden', has ? 'false' : 'true');
        }catch(e){}

        try{
            callSsGridEl.classList.toggle('has-grid', has);
        }catch(e){}

        try{
            __ncRenderShareGrid(callShareGridEl, items, { selectedKey: (typeof groupSelectedShareKey !== 'undefined' ? groupSelectedShareKey : '') });
        }catch(e){}

        // Close theater if the opened stream disappeared
        try{
            if (__ncTheaterOpen && __ncTheaterOpenId){
                const ok = (items || []).some(it => String(it.id || '') === String(__ncTheaterOpenId));
                if (!ok) __ncCloseTheaterOverlay();
            }
        }catch(e){}
        try{ _ncUpdateCallHasScreen(); }catch(e){}
    }catch(e){}
}

function _ncRenderVoiceShareGrid(){
    try{
        if (!voiceShareGridEl) return;
        const items = __ncBuildGroupShareItems();
        const has = !!(items && items.length);

        try{ document.body.classList.toggle('nc-voice-share-grid-on', has); }catch(e){}
        try{
            voiceShareGridEl.classList.toggle('is-hidden', !has);
            voiceShareGridEl.setAttribute('aria-hidden', has ? 'false' : 'true');
        }catch(e){}

        try{
            __ncRenderShareGrid(voiceShareGridEl, items, { selectedKey: (typeof groupSelectedShareKey !== 'undefined' ? groupSelectedShareKey : '') });
        }catch(e){}

        try{
            if (__ncTheaterOpen && __ncTheaterOpenId){
                const ok = (items || []).some(it => String(it.id || '') === String(__ncTheaterOpenId));
                if (!ok) __ncCloseTheaterOverlay();
            }
        }catch(e){}
    }catch(e){}
}


function _ncOnGroupShareAvailabilityChanged(){
    try{
        _ncApplyGroupShareStage();
        _ncRenderVoiceShareStrip();
        try{ _ncRenderVoiceShareGrid(); }catch(e){}
        try{ _ncRenderCallShareGrid(); }catch(e){}
    }catch(e){}
}


function setVoiceViewActive(on){
    const chatMain = document.querySelector(".chat-main");
    if (!chatMain) return;

    isVoiceView = !!on;

    chatMain.classList.toggle("is-voice-view", isVoiceView);

    if (voiceViewEl) {
        voiceViewEl.classList.toggle("is-hidden", !isVoiceView);
        voiceViewEl.setAttribute("aria-hidden", isVoiceView ? "false" : "true");
    }

    // Allow DM-like Call HUD inside voice channels when explicitly requested.
    // (We use it when the user starts a voice-channel call "как DM" — without modal / without voice-stage.)
    try{
        if (isVoiceView) {
            const allowHud = !!(window.__ncVoiceUseCallHud);
            if (!allowHud) {
                if (typeof updateCallUI === "function") updateCallUI(false);
                if (typeof setCallHudMode === "function") setCallHudMode("idle");
            }
        }
    }catch(e){}

    // Members panel visibility is managed by sidebar mode (channels/friends).
    // Voice view should not override it.

    if (!isVoiceView) {
        // clear any voice-only previews when leaving voice UI
        try { _attachVoiceShareVideo(null); } catch (e) {}
        try { if (voiceParticipantsGridEl) voiceParticipantsGridEl.innerHTML=""; } catch (e) {}
        try { _setVoiceTileText("Голосовой канал", ""); } catch (e) {}

        // stop any voice-stage cosmetics
        try { stopVoiceStageSpeakerDemo(); } catch (e) {}
    }

    try { syncVoiceViewState(); } catch (e) {}

    try{ if (typeof __ncReanchorMusicMiniBar === 'function') __ncReanchorMusicMiniBar(); }catch(e){}
    try{ if (typeof __ncReanchorMusicDrawer === 'function') __ncReanchorMusicDrawer(); }catch(e){}
}

// v14.15: Per-channel accent colors for the voice stage (unique look)
function _syncVoiceAccentVars(){
    try{
        if (!voiceViewEl) return;
        const g = parseInt(currentGuildId || 0, 10) || 0;
        const c = parseInt(currentChannelId || 0, 10) || 0;
        // deterministic hues: stable per guild/channel
        const h1 = ((g * 37) + (c * 91)) % 360;
        const h2 = (h1 + 44) % 360;
        const h3 = (h1 + 214) % 360;
        voiceViewEl.style.setProperty('--nc-h1', String(h1));
        voiceViewEl.style.setProperty('--nc-h2', String(h2));
        voiceViewEl.style.setProperty('--nc-h3', String(h3));
    }catch(e){}
}



// v14.16: Premium voice HUD (stage meta + participant count)
function _updateVoicePremiumHud(){
    try{
        if (!voicePremiumBarEl) return;

        const inVoice = !!isVoiceView && String(currentChannelType || '') === 'voice' && !!currentChannelId;
        const voiceSideTile = document.getElementById('voice-tile-side');
        voicePremiumBarEl.classList.toggle('is-hidden', !inVoice);
        voicePremiumBarEl.setAttribute('aria-hidden', inVoice ? 'false' : 'true');
        if (!inVoice) return;

        

        // Side tile (Discord "Activities") — показываем только в серверном голосовом
        try{
            const showSide = document.body && document.body.classList && document.body.classList.contains('nc-server-mode');
            if (voiceSideTile){
                voiceSideTile.classList.toggle('is-hidden', !showSide);
                voiceSideTile.setAttribute('aria-hidden', showSide ? 'false' : 'true');
            }
        }catch(e){}

        const connected = !!(groupCallActive && groupCallChannelId && String(groupCallChannelId) === String(currentChannelId));
        voicePremiumBarEl.classList.toggle('is-live', !!connected);

        const chan = (voiceTileTitleEl && voiceTileTitleEl.textContent) ? String(voiceTileTitleEl.textContent).trim() : '';
        const guild = (currentGuildName || '').trim();
        const meta = [chan, guild].filter(Boolean).join(' · ');
        if (voicePremiumMetaEl) voicePremiumMetaEl.textContent = meta || '—';

        let n = 0;
        try { n = voiceParticipantsGridEl && voiceParticipantsGridEl.children ? voiceParticipantsGridEl.children.length : 0; } catch(e) {}
        if (voicePremiumCountEl) voicePremiumCountEl.textContent = String(n || 0);
    }catch(e){}
}

function updateVoiceToolbarState(){
    try{
        if (vctlMic) vctlMic.classList.toggle("toggled", !!isMicMuted);
        if (vctlSound) vctlSound.classList.toggle("toggled", !!isRemoteMuted);
        if (vctlShare) vctlShare.classList.toggle("active", !!groupScreenSharing);

        // Mirror state to bottom-left "Me" panel controls (Discord-like)
        if (meMicBtn) {
            meMicBtn.classList.toggle("toggled", !!isMicMuted);
            meMicBtn.classList.toggle("danger", !!isMicMuted);
        }
        if (meDeafenBtn) {
            meDeafenBtn.classList.toggle("toggled", !!isRemoteMuted);
            meDeafenBtn.classList.toggle("danger", !!isRemoteMuted);
        }
        if (voiceMiniShareBtn) voiceMiniShareBtn.classList.toggle("active", !!groupScreenSharing);
    }catch(e){}
}

function syncVoiceViewState(){
    try{
        const inVoice = !!isVoiceView && String(currentChannelType || "") === "voice" && !!currentChannelId;
        const voiceSideTile = document.getElementById('voice-tile-side');
        if (!inVoice) {
            if (voiceJoinBtn) voiceJoinBtn.classList.add("is-hidden");
            if (voiceStageHintEl) voiceStageHintEl.classList.add("is-hidden");
            try{ if (voiceSideTile){ voiceSideTile.classList.add('is-hidden'); voiceSideTile.setAttribute('aria-hidden','true'); } }catch(e){}
            return;
        }

        // Update per-channel accent variables for the voice stage
        try { _syncVoiceAccentVars(); } catch (e) {}

        // Side tile (Discord "Activities") — показываем только в серверном голосовом
        try{
            const showSide = document.body && document.body.classList && document.body.classList.contains('nc-server-mode');
            if (voiceSideTile){
                voiceSideTile.classList.toggle('is-hidden', !showSide);
                voiceSideTile.setAttribute('aria-hidden', showSide ? 'false' : 'true');
            }
        }catch(e){}


        const connected = !!(groupCallActive && groupCallChannelId && String(groupCallChannelId) === String(currentChannelId));

        // Stage text + hint
        if (voiceStageEmptyTextEl) {
            if (!connected) voiceStageEmptyTextEl.textContent = "Не подключено";
            else {
                const n = (voiceParticipantsGridEl && voiceParticipantsGridEl.children) ? voiceParticipantsGridEl.children.length : 0;
                voiceStageEmptyTextEl.textContent = (n <= 1) ? "Ты в голосовом. Ждём остальных…" : "Голосовая связь подключена";
            }
        }
        if (voiceStageHintEl) {
            voiceStageHintEl.classList.toggle("is-hidden", !!connected);
        }

        // Join button
        if (voiceJoinBtn) {
            voiceJoinBtn.classList.toggle("is-hidden", !!connected);
        }

        // Stage empty block: show when not connected OR when connected but no grid yet
        if (voiceStageEmptyEl) {
            const n = (voiceParticipantsGridEl && voiceParticipantsGridEl.children) ? voiceParticipantsGridEl.children.length : 0;
            const showEmpty = (!connected) || (connected && n <= 0);
            voiceStageEmptyEl.classList.toggle("is-hidden", !showEmpty);
        }

        // Sub-title
        if (voiceTileSubEl) {
            voiceTileSubEl.textContent = connected ? "Голосовая связь подключена" : "Нажми «Подключиться», чтобы войти в голосовой";
        }

        // Toolbar availability
        const canUse = !!connected;
        if (vctlMic) vctlMic.disabled = !canUse;
        if (vctlSound) vctlSound.disabled = !canUse;
        if (vctlShare) vctlShare.disabled = !canUse;
        if (vctlLeave) vctlLeave.disabled = !canUse;

        // Invite is always available (it opens invite panel)
        if (vctlInvite) vctlInvite.disabled = false;

        try { _updateVoicePremiumHud(); } catch (e) {}
        try { updateVoiceParticipantBadges(); } catch (e) {}
    try { updateCallParticipantBadges(); } catch (e) {}
    try { updateDmCallMini(); } catch (e) {}
    }catch(e){}
}

function _renderRightMembers(members){
    try{
        if (!rightMembersList) return;

        const countEl = document.getElementById('right-members-count');
        rightMembersList.innerHTML = "";

        // Cache by id for other UI bits (context menus, voice overlays)
        currentMembersById = {};
        (members || []).forEach(m => {
            if (!m || !m.id) return;
            currentMembersById[String(m.id)] = m;
        });

        // Filter ignored users
        let list = Array.isArray(members) ? members.slice() : [];
        try{
            list = list.filter(u => {
                const id = u && (u.id || u.user_id);
                return !isUserIgnored(id);
            });
        }catch(e){}

        if (countEl) countEl.textContent = String(list.length || 0);

        if (!list.length) {
            const empty = document.createElement("div");
            empty.className = "cp-result";
            empty.textContent = "Участников нет.";
            rightMembersList.appendChild(empty);
            return;
        }

        // Helpers
        const roleOrder = ["owner","admin","moderator","member","pending"];
        const roleRank = (r) => {
            const rr = String(r||'member').toLowerCase();
            const ix = roleOrder.indexOf(rr);
            return (ix >= 0) ? ix : 99;
        };
        const roleColor = (r) => {
            const rr = String(r||'member').toLowerCase();
            if (rr === 'owner') return '#b38cff';
            if (rr === 'admin') return '#ff5f73';
            if (rr === 'moderator') return '#6ad1ff';
            if (rr === 'pending') return 'rgba(255,255,255,.30)';
            return 'rgba(255,255,255,.55)';
        };
        const roleLabel = (r) => {
            try{ return (typeof _groupRoleLabel === 'function') ? _groupRoleLabel(r) : String(r||'member'); }catch(e){ return String(r||'member'); }
        };

        const presenceCls = (u) => {
            const online = !!(u && u.is_online);
            const mode = String((u && u.mode) || '').toLowerCase();
            if (online) {
                if (mode === 'away') return 'is-away';
                if (mode === 'dnd') return 'is-dnd';
                return 'is-online';
            }
            return 'is-offline';
        };

        const byName = (a,b) => (String(a.username||'')).localeCompare(String(b.username||''), 'ru');
        const byRoleThenName = (a,b) => {
            const ra = roleRank(a.member_role);
            const rb = roleRank(b.member_role);
            if (ra !== rb) return ra - rb;
            return byName(a,b);
        };

        // Split into pending / online / offline (Discord-like)
        const pending = list.filter(u => String(u.member_role||'').toLowerCase() === 'pending');
        const online = list.filter(u => !!u.is_online && String(u.member_role||'').toLowerCase() !== 'pending');
        const offline = list.filter(u => !u.is_online && String(u.member_role||'').toLowerCase() !== 'pending');

        online.sort(byRoleThenName);
        offline.sort(byRoleThenName);
        pending.sort(byName);

        const frag = document.createDocumentFragment();

        const makeGroup = (title, users, opts={}) => {
            const wrap = document.createElement('div');
            wrap.className = 'dc-mgroup';
            const h = document.createElement('div');
            h.className = 'dc-mgroup-title';
            h.textContent = title;
            wrap.appendChild(h);

            users.forEach(u => {
                const row = document.createElement('div');
                row.className = 'dc-member' + ((opts.offline || !u.is_online) ? ' is-offline' : '');

                const avatarUrl = (u.avatar_url || '').trim();
                const initials = (String(u.username||'?').trim().charAt(0) || '?').toUpperCase();

                const r = String(u.member_role || 'member').toLowerCase();
                const rLabel = roleLabel(r);
                const rColor = roleColor(r);

                // dataset used by context menus / profile modals
                try{
                    row.dataset.userId = String(u.id || 0);
                    row.dataset.username = String(u.username || '');
                    row.dataset.avatarUrl = String(avatarUrl || '');
                    row.dataset.status = (u.presence_text ? String(u.presence_text) : (u.is_online ? 'в сети' : 'не в сети'));
                    row.dataset.roleName = String(rLabel || '');
                    row.dataset.roleColor = String(rColor || '');
				    row.dataset.memberRole = String(r || 'member');
                    row.dataset.mode = String(u.mode || '');
                }catch(e){}

                // Context menu is handled by a document-level delegated listener
                // (see DOMContentLoaded -> ctxUserMenuForMembers).

                // Left click: handled by a delegated listener (Discord-like popout)

                const av = document.createElement('div');
                av.className = 'dc-mavatar' + (avatarUrl ? ' has-image' : '');
                if (avatarUrl) av.style.backgroundImage = `url('${String(avatarUrl).replace(/'/g, "%27")}')`;

                const init = document.createElement('span');
                init.className = 'dc-minitial';
                init.textContent = avatarUrl ? '' : initials;
                av.appendChild(init);

                const dot = document.createElement('span');
                dot.className = 'dc-mpresence ' + presenceCls(u);
                dot.setAttribute('aria-hidden', 'true');
                av.appendChild(dot);

                const meta = document.createElement('div');
                meta.className = 'dc-mmeta';
                const name = document.createElement('div');
                name.className = 'dc-mname';
                name.textContent = String(u.username || '');
                try{ name.style.color = rColor; }catch(e){}
                meta.appendChild(name);

                // Secondary line: status/presence text if exists
                const subText = String((u.presence_text || '')).trim();
                if (subText){
                    const sub = document.createElement('div');
                    sub.className = 'dc-msub';
                    sub.textContent = subText;
                    meta.appendChild(sub);
                }

                row.appendChild(av);
                row.appendChild(meta);
                wrap.appendChild(row);
            });

            frag.appendChild(wrap);
        };

        // Online role groups
        const onlineByRole = {};
        online.forEach(u => {
            const r = String(u.member_role || 'member').toLowerCase();
            const key = (r === 'mod') ? 'moderator' : r;
            if (!onlineByRole[key]) onlineByRole[key] = [];
            onlineByRole[key].push(u);
        });

        const roleKeys = Object.keys(onlineByRole);
        roleKeys.sort((a,b) => roleRank(a) - roleRank(b));

        roleKeys.forEach(r => {
            const users = onlineByRole[r] || [];
            users.sort(byName);
            const title = `${String(roleLabel(r)||'').toUpperCase()} — ${users.length}`;
            makeGroup(title, users, { offline: false });
        });

        // Offline block
        if (offline.length){
            makeGroup(`ОФФЛАЙН — ${offline.length}`, offline, { offline: true });
        }

        // Pending block (optional)
        if (pending.length){
            makeGroup(`PENDING — ${pending.length}`, pending, { offline: true });
        }

        rightMembersList.appendChild(frag);
    }catch(e){}
}


