function _ncClamp(n, a, b){
    const x = (typeof n === 'number' && !isNaN(n)) ? n : parseFloat(String(n||'0'));
    if (isNaN(x)) return a;
    return Math.max(a, Math.min(b, x));
}

function _ncVvLoad(){
    try{
        const s = JSON.parse(localStorage.getItem('nc_vv_settings')||'{}')||{};
        // Migration: remove deprecated Push-to-Talk mode/settings
        if (s && String(s.mode||'') === 'ptt_limited'){
            s.mode = 'vad';
            try{ delete s.pttBind; delete s.pttReleaseMs; }catch(e){}
            try{ localStorage.setItem('nc_vv_settings', JSON.stringify(s)); }catch(e){}
        }
        return s;
    }catch(e){ return {}; }
}


