function _ncChatLoad(){
    try{ return JSON.parse(localStorage.getItem('nc_chat_settings')||'{}')||{}; }catch(e){ return {}; }
}
function _ncChatSave(patch){
    try{
        const cur = _ncChatLoad();
        const next = Object.assign({}, cur, patch||{});
        localStorage.setItem('nc_chat_settings', JSON.stringify(next));
        try{ if (window.ncApplyChatSettingsLive) window.ncApplyChatSettingsLive(); }catch(e){}
        return next;
    }catch(e){ return _ncChatLoad(); }
}
function _ncChatConvertEmoticons(text){
    try{
        let t = String(text||'');
        // Quick replacements; keep it simple and safe.
        const repl = [
            [/(^|\s)(:-?\))(?!\S)/g, '$1🙂'],
            [/(^|\s)(;-?\))(?!\S)/g, '$1😉'],
            [/(^|\s)(:-?D)(?!\S)/gi, '$1😄'],
            [/(^|\s)(:-?\()(?!\S)/g, '$1🙁'],
            [/(^|\s)(:-?P)(?!\S)/gi, '$1😛'],
            [/(^|\s)<3(?!\S)/g, '$1❤️'],
        ];
        repl.forEach(([rg, to])=>{ t = t.replace(rg, to); });
        return t;
    }catch(e){ return String(text||''); }
}


function ncApplyChatSettingsLive(){
    try{
        const st = _ncChatLoad();
        const showReactions = (typeof st.showReactions === 'undefined') ? true : !!st.showReactions;
        const mediaUploads = (typeof st.mediaUploads === 'undefined') ? true : !!st.mediaUploads;
        const mediaLinks = (typeof st.mediaLinks === 'undefined') ? true : !!st.mediaLinks;
        const linkPreviews = (typeof st.linkPreviews === 'undefined') ? true : !!st.linkPreviews;

        document.documentElement.classList.toggle('nc-chat-no-reactions', !showReactions);
        document.documentElement.classList.toggle('nc-chat-no-upload-previews', !mediaUploads);
        document.documentElement.classList.toggle('nc-chat-no-media-links', !mediaLinks);
        document.documentElement.classList.toggle('nc-chat-no-link-previews', !linkPreviews);
        document.documentElement.classList.toggle('nc-chat-img-desc', !!st.imageDescriptions);
    }catch(e){}
}
try{ if (!window.ncApplyChatSettingsLive) window.ncApplyChatSettingsLive = ncApplyChatSettingsLive; }catch(e){}

function _ncGetMicGainFactor(){
    // micGain is stored as 0..200 (%). Some edge cases can store null/NaN (JSON turns NaN into null),
    // which previously resulted in a 0 gain (silence). Be strict and fall back to 100% when invalid.
    try{
        const s = _ncVvLoad();
        if (s && Object.prototype.hasOwnProperty.call(s, 'micGain')){
            const raw = s.micGain;
            if (raw === null || typeof raw === 'undefined') return 1;
            const str = String(raw).trim();
            if (str === '') return 1;
            const v = parseInt(str, 10);
            if (!Number.isFinite(v)) return 1;
            return _ncClamp(v/100, 0, 2);
        }
    }catch(e){}
    return 1;
}


function __ncEnsureMicGainNotSilent(){
    // If micGain is accidentally saved as 0..5%, outgoing audio becomes silent and looks like "mic not working".
    // During calls, auto-correct this to 100%.
    try{
        const raw = localStorage.getItem('nc_vv_settings') || '{}';
        const vv = JSON.parse(raw) || {};
        const mg = (vv && Object.prototype.hasOwnProperty.call(vv,'micGain')) ? Number(vv.micGain) : NaN;
        if (Number.isFinite(mg) && mg <= 5){
            vv.micGain = 100;
            localStorage.setItem('nc_vv_settings', JSON.stringify(vv));
            try{ if (window.ncApplyVvSettingsLive) window.ncApplyVvSettingsLive({ needsRestart:false }); }catch(e){}
            try{ if (localMicGainNode && localMicGainNode.gain) localMicGainNode.gain.value = 1; }catch(e){}
        }
    }catch(e){}
}


function _ncGetVoiceOutVol(){
    // Stored as 0..200% -> 0..2.0. (We use WebAudio for >100% amplification.)
    // Be robust to null/NaN values (JSON serializes NaN as null).
    try{
        const s = _ncVvLoad();
        if (s && Object.prototype.hasOwnProperty.call(s, 'outVol')){
            const raw = s.outVol;
            if (raw === null || typeof raw === 'undefined') return null;
            const str = String(raw).trim();
            if (str === '') return null;
            const v = parseInt(str, 10);
            if (!Number.isFinite(v)) return null;
            return _ncClamp(v/100, 0, 2);
        }
    }catch(e){}
    return null;
}

function ncApplyOutputDeviceNow(){
    // Applies selected output device to all relevant audio elements (if supported).
    try{
        const devId = (audioSettings && audioSettings.outputDeviceId) ? String(audioSettings.outputDeviceId) : '';
        const refs = window._callUI || {};
        const els = [];
        if (refs.remoteAudio) els.push(refs.remoteAudio);
        if (remoteScreenAudio) els.push(remoteScreenAudio);
        try{ if (typeof callScreenVideo !== 'undefined' && callScreenVideo) els.push(callScreenVideo); }catch(e){}
        try{ if (typeof callScreenVideoLocal !== 'undefined' && callScreenVideoLocal) els.push(callScreenVideoLocal); }catch(e){}
        try{ if (typeof voiceShareVideoEl !== 'undefined' && voiceShareVideoEl) els.push(voiceShareVideoEl); }catch(e){}
        try{ if (callScreenVideo) els.push(callScreenVideo); }catch(e){}
        try{ if (callScreenVideoLocal) els.push(callScreenVideoLocal); }catch(e){}
        try{ if (voiceShareVideoEl) els.push(voiceShareVideoEl); }catch(e){}
        // Rings/SFX
        try{
            const ringOut = document.getElementById('ring-out');
            const ringIn = document.getElementById('ring-in');
            const sfxDisc = document.getElementById('sfx-disconnect');
            const sfxRec = document.getElementById('sfx-reconnect');
            const sfxMute = document.getElementById('sfx-mute');
            const sfxUnmute = document.getElementById('sfx-unmute');
            if (ringOut) els.push(ringOut);
            if (ringIn) els.push(ringIn);
            if (sfxDisc) els.push(sfxDisc);
            if (sfxRec) els.push(sfxRec);
            if (sfxMute) els.push(sfxMute);
            if (sfxUnmute) els.push(sfxUnmute);
        }catch(e){}
        els.forEach(el => {
            if (!el) return;
            if (typeof el.setSinkId === 'function') {
                el.setSinkId(devId || 'default').catch(()=>{});
            }
        });
    }catch(e){}
}

function _ncDestroyLocalAudioPipeline(){
    try{ if (localMicSourceNode) localMicSourceNode.disconnect(); }catch(e){}
    try{ if (localMicHpNode) localMicHpNode.disconnect(); }catch(e){}
    try{ if (localMicGateNode) localMicGateNode.disconnect(); }catch(e){}
    try{ if (localMicDenoiseNode) localMicDenoiseNode.disconnect(); }catch(e){}
    try{ if (localMicLpNode) localMicLpNode.disconnect(); }catch(e){}
    try{ if (localMicEqBassNode) localMicEqBassNode.disconnect(); }catch(e){}
    try{ if (localMicEqTrebleNode) localMicEqTrebleNode.disconnect(); }catch(e){}
    try{
        if (localMicEnhNodes && localMicEnhNodes.length){
            localMicEnhNodes.forEach(n => { try{ n && n.disconnect && n.disconnect(); }catch(e){} });
        }
    }catch(e){}
    try{ if (localMicScriptNode) localMicScriptNode.disconnect(); }catch(e){}
    try{ if (localMicGainNode) localMicGainNode.disconnect(); }catch(e){}
    try{ if (localMicDestNode) localMicDestNode.disconnect(); }catch(e){}
    localMicSourceNode = null;
    localMicHpNode = null;
    localMicGateNode = null;
    localMicDenoiseNode = null;
    localMicLpNode = null;
    localMicEqBassNode = null;
    localMicEqTrebleNode = null;
    localMicEnhNodes = null;
    localMicScriptNode = null;
    localMicGainNode = null;
    localMicDestNode = null;
}

function _ncHasAudioWorklet(ctx){
    try{ return !!(ctx && ctx.audioWorklet && typeof AudioWorkletNode !== 'undefined'); }catch(e){ return false; }
}

// ===== ScriptProcessor fallback for denoise/gate (works even without secure context) =====
// AudioWorklet requires a secure context on many browsers. If the app is served over plain http
// (not localhost), worklets can be unavailable and "noise suppression" would do almost nothing.
// This fallback keeps ULTRA noise reduction working everywhere.

function _ncCreateScriptDenoiseGateNode(ctx, opts){
    // ScriptProcessor fallback for NEON ULTRA when AudioWorklet is unavailable.
    // Includes FFT denoise + click/transient suppression + VAD-based voice isolation.
    try{
        if (!ctx || !ctx.createScriptProcessor) return null;
        const o = opts || {};

        const aggr = _ncClamp(typeof o.aggressiveness === 'number' ? o.aggressiveness : 1.25, 0, 1.35);
        const floor = _ncClamp(typeof o.floor === 'number' ? o.floor : 0.030, 0.015, 0.25);
        const noiseLearn = _ncClamp(typeof o.noiseLearn === 'number' ? o.noiseLearn : 0.11, 0.005, 0.35);
        const speechThresh = _ncClamp(typeof o.speechThresh === 'number' ? o.speechThresh : 0.016, 0.004, 0.10);

        const voiceIsolation = !!o.voiceIsolation;
        const voiceHoldFrames = Math.max(0, Math.min(80, (o.voiceHoldFrames|0) || 22));
        const silenceFloor = _ncClamp(typeof o.silenceFloor === 'number' ? o.silenceFloor : 0.0, 0.0, 0.20);
        const hfDamp = _ncClamp(typeof o.hfDamp === 'number' ? o.hfDamp : 0.60, 0.15, 1.0);
        const vadMidDom = _ncClamp(typeof o.vadMidDom === 'number' ? o.vadMidDom : 1.15, 0.8, 3.0);
        const vadFlatMax = _ncClamp(typeof o.vadFlatMax === 'number' ? o.vadFlatMax : 0.82, 0.4, 1.0);

        const autoTune = !!o.autoTune;
        const warmupFrames = Math.max(0, Math.min(300, (o.warmupFrames|0) || 0));
        let warmLeft = warmupFrames;
        const crestThresh = _ncClamp(typeof o.crestThresh === 'number' ? o.crestThresh : 5.2, 2.5, 12.0);
        const diffThresh = _ncClamp(typeof o.diffThresh === 'number' ? o.diffThresh : 0.42, 0.05, 2.0);

        const gateThresholdDb = (typeof o.gateThresholdDb === 'number') ? o.gateThresholdDb : -52;
        const gateFloorDb = (typeof o.gateFloorDb === 'number') ? o.gateFloorDb : -80;
        const gateAttackMs = (typeof o.gateAttackMs === 'number') ? o.gateAttackMs : 2;
        const gateReleaseMs = (typeof o.gateReleaseMs === 'number') ? o.gateReleaseMs : 140;

        // Transient/click suppression (helps with keyboard/mouse taps)
        const clickSup = _ncClamp(typeof o.clickSuppression === 'number' ? o.clickSuppression : 1.0, 0, 1.0);
        const clickFloor = _ncClamp(typeof o.clickFloor === 'number' ? o.clickFloor : 0.07, 0.02, 0.9);
        const clickHoldFrames = Math.max(0, Math.min(30, (o.clickHoldFrames|0) || 10));
        const clickBroad = _ncClamp(typeof o.clickBroad === 'number' ? o.clickBroad : 0.70, 0.20, 1.0);
        const clickMid = _ncClamp(typeof o.clickMid === 'number' ? o.clickMid : 0.93, 0.70, 1.0);
        const clickLow = _ncClamp(typeof o.clickLow === 'number' ? o.clickLow : 0.55, 0.20, 1.0);
        const clickBroadSpeech = _ncClamp(typeof o.clickBroadSpeech === 'number' ? o.clickBroadSpeech : 0.97, 0.70, 1.0);

        function clamp(x,a,b){ return Math.max(a, Math.min(b, x)); }

        // --- Minimal FFT core (N=256) ---
        const N = 256;
        const hop = 128;
        const half = N >> 1;
        const eps = 1e-8;

        const frame = new Float32Array(N);
        const ola = new Float32Array(N);
        const win = new Float32Array(N);
        for (let i=0;i<N;i++){ win[i] = 0.5 - 0.5*Math.cos((2*Math.PI*i)/N); }

        const bitrev = new Uint16Array(N);
        const bits = Math.round(Math.log2(N));
        for (let i=0;i<N;i++){
            let x=i, r=0;
            for (let b=0;b<bits;b++){ r = (r<<1) | (x&1); x >>= 1; }
            bitrev[i]=r;
        }
        const cos = new Float32Array(half);
        const sin = new Float32Array(half);
        for (let k=0;k<half;k++){
            const ang = (2*Math.PI*k)/N;
            cos[k]=Math.cos(ang);
            sin[k]=Math.sin(ang);
        }
        const re = new Float32Array(N);
        const im = new Float32Array(N);

        const noise = new Float32Array(half+1);
        const gSmooth = new Float32Array(half+1);
        const gTmp = new Float32Array(half+1);
        const prevMag = new Float32Array(half+1);
        for (let k=0;k<noise.length;k++){ noise[k]=1e-3; gSmooth[k]=1; prevMag[k]=1e-3; }

        function fft(inverse){
            // bitrev
            for (let i=0;i<N;i++){
                const j = bitrev[i];
                if (j>i){
                    let tr=re[i]; re[i]=re[j]; re[j]=tr;
                    let ti=im[i]; im[i]=im[j]; im[j]=ti;
                }
            }
            for (let len=2; len<=N; len<<=1){
                const h = len>>1;
                const step = N/len;
                for (let i=0;i<N;i+=len){
                    for (let j=0;j<h;j++){
                        const idx = (j*step)|0;
                        const c = cos[idx];
                        const s = inverse ? sin[idx] : -sin[idx];
                        const ur = re[i+j];
                        const ui = im[i+j];
                        const vr = re[i+j+h]*c - im[i+j+h]*s;
                        const vi = re[i+j+h]*s + im[i+j+h]*c;
                        re[i+j] = ur+vr;
                        im[i+j] = ui+vi;
                        re[i+j+h] = ur-vr;
                        im[i+j+h] = ui-vi;
                    }
                }
            }
            if (inverse){
                const invN = 1/N;
                for (let i=0;i<N;i++){ re[i]*=invN; im[i]*=invN; }
            }
        }

        function rms128(buf, off){
            let s=0;
            for (let i=0;i<hop;i++){
                const x = buf[off+i]||0;
                s += x*x;
            }
            return Math.sqrt(s/hop);
        }

        // --- Click/VAD state ---
        let prevHf = 0;
        let prevLf = 0;
        let clickCountdown = 0;
        let speechHang = 0;

        // --- Noise gate envelope ---
        const sr = ctx.sampleRate || 48000;
        function dbToLin(db){ return Math.pow(10, db/20); }
        function coefFromMs(ms){ const t=Math.max(1,ms)/1000; return 1 - Math.exp(-1/(sr*t)); }
        const gateThreshold = dbToLin(gateThresholdDb);
        const gateFloor = dbToLin(gateFloorDb);
        const atk = coefFromMs(gateAttackMs);
        const rel = coefFromMs(gateReleaseMs);
        let env=0;
        let gateGain=1;

        function processHop(inBuf, inOff, outBuf, outOff){
            // shift frame and append
            frame.copyWithin(0, hop);
            for (let i=0;i<hop;i++) frame[N-hop+i] = inBuf[inOff+i] || 0;

            // window to FFT input
            for (let i=0;i<N;i++){ re[i]=frame[i]*win[i]; im[i]=0; }
            fft(false);

            // Band energies + mid flatness + HF flux spikes
            const kMidLo = 2;
            const kMidHi = 18;
            const kHfLo = 20;
            const kHfDamp = 32;

            let lfE=0, midE=0, hfE=0;
            let midLog=0, midSum=0, midCnt=0;
            let spikes=0;

            for (let k=0;k<=half;k++){
                const rr=re[k], ii=im[k];
                const p = rr*rr + ii*ii;
                const mag = Math.sqrt(p) + eps;

                if (k<=1) lfE += p;
                if (k>=kMidLo && k<=kMidHi){
                    midE += p;
                    midSum += mag;
                    midLog += Math.log(mag);
                    midCnt++;
                }
                if (k>=kHfLo) hfE += p;

                // HF flux spikes (clicks often create multiple spikes)
                if (k>=kHfLo){
                    const r = mag / (prevMag[k] + eps);
                    if (r > 3.5) spikes++;
                }
                prevMag[k] = mag;
            }

            const midFlat = (midCnt>0) ? (Math.exp(midLog/midCnt) / ((midSum/midCnt)+eps)) : 1.0;
            const domMidHf = midE / (hfE + 1e-9);

            const r = rms128(inBuf, inOff);
            // Time-domain transient cues (catch clicks during speech)
            let peak=0, diff=0;
            let prevS = inBuf[inOff] || 0;
            for (let i=0;i<hop;i++){
                const x = inBuf[inOff+i]||0;
                const ax = Math.abs(x);
                if (ax > peak) peak = ax;
                if (i>0) diff += Math.abs(x - prevS);
                prevS = x;
            }
            const crest = peak / (r + eps);
            const diffNorm = (diff / hop) / (r + eps);
            const tdTransient = (peak > (speechThresh * 0.65)) && (crest >= crestThresh) && (diffNorm >= diffThresh);

            const rmsOk = r >= (speechThresh * 0.85);
            const voiceLike = (domMidHf >= vadMidDom) && (midFlat <= vadFlatMax);
            const isSpeechNow = (voiceLike && (rmsOk || midE > 5e-7)) || (domMidHf >= (vadMidDom*1.7) && midE > 4e-7);

            if (isSpeechNow) speechHang = voiceHoldFrames;
            else if (speechHang > 0) speechHang--;

            const speechOn = voiceIsolation ? (speechHang > 0) : true;

            // Warmup: learn room noise quickly while silent
            if (warmLeft > 0){
                if (isSpeechNow) warmLeft = 0;
                else warmLeft--;
            }
            const warm = (warmLeft > 0);

            // Click detector (HF spike, LF thump, or HF flux)
            let clickDetected = false;
            if (clickSup > 0){
                const hfJump = (hfE - prevHf) / (prevHf + 1e-6);
                prevHf = hfE;
                const lfJump = (lfE - prevLf) / (prevLf + 1e-6);
                prevLf = lfE;

                const hfDominates = hfE > (midE * 2.1 + 1e-6);
                const bigHfJump = hfJump > 1.25;
                const bigLfJump = lfJump > 1.8;

                if ((hfDominates && bigHfJump) || (!speechOn && bigLfJump && lfE > (midE*0.9 + 1e-6)) || (spikes >= 3) || (tdTransient && spikes >= 2) || (tdTransient && (hfJump > 0.55 || hfDominates))){
                    clickDetected = true;
                }
            }

            if (clickDetected) clickCountdown = Math.max(clickCountdown, clickHoldFrames + (tdTransient ? 6 : 0));
            else if (clickCountdown > 0) clickCountdown--;

            // Dynamic HF damping (auto-tune for noisy mics)
            let hfD = hfDamp;
            if (autoTune){
                const hfRatio = hfE / (midE + 1e-9);
                if (hfRatio > 1.35) hfD = Math.min(hfD, 0.45);
                if (!speechOn && hfRatio > 1.10) hfD = Math.min(hfD, 0.35);
            }

            let learnFast = noiseLearn;
            if (warm) learnFast = Math.min(0.28, Math.max(learnFast, 0.20));
            const learnSlow = Math.max(0.0025, learnFast*(speechOn ? 0.05 : 0.20));

            for (let k=0;k<=half;k++){
                const rr=re[k], ii=im[k];
                const mag = Math.sqrt(rr*rr + ii*ii) + eps;

                const n0 = noise[k];
                const close = (mag <= n0 * (1.45 + 0.35*aggr));
                const lr = close ? learnFast : learnSlow;
                noise[k] = n0 + (mag - n0)*lr;

                const nEst = noise[k];
                // Keep denoise strong but preserve vocal tone (avoid underwater/robotic).
                const sub = nEst * (0.95 + 1.65*aggr);
                let g = (mag - sub) / mag;
                g = clamp(g, floor, 1);

                // Voice isolation shaping
                if (voiceIsolation){
                    if (k<=1) g *= 0.35;
                    if (k>=kHfDamp) g *= speechOn ? hfD : 0.06;
                }

                const gs = gSmooth[k];
                gSmooth[k] = gs + (g - gs)*0.26;
            }

            gTmp[0] = gSmooth[0];
            for (let k=1;k<half;k++){
                gTmp[k] = 0.18*gSmooth[k-1] + 0.64*gSmooth[k] + 0.18*gSmooth[k+1];
            }
            gTmp[half] = gSmooth[half];

            for (let k=0;k<=half;k++){
                let g = gTmp[k];

                if (clickCountdown > 0){
                    const amt = clickSup;
                    if (k >= 20){
                        const clickG = (1 - amt) * 1.0 + amt * clickFloor;
                        g *= clickG;
                    }
                    if (k <= 1){
                        const lowG = (1 - amt) * 1.0 + amt * clickLow;
                        g *= lowG;
                    } else if (k >= 2 && k <= 18){
                        const midG = (1 - amt) * 1.0 + amt * clickMid;
                        g *= midG;
                    }
                    // Additional ducking in the "keyboard band" during transients
                    if (k >= 10 && k <= 42){
                        const kb = speechOn ? 0.65 : 0.40;
                        g *= (1 - amt) * 1.0 + amt * kb;
                    }
                    g *= (speechOn ? clickBroadSpeech : clickBroad);
                }

                if (voiceIsolation && !speechOn) g *= silenceFloor;

                re[k] *= g; im[k] *= g;
                if (k>0 && k<half){ const mk=N-k; re[mk]*=g; im[mk]*=g; }
            }

            fft(true);
            for (let i=0;i<N;i++) ola[i] += re[i]*win[i];

            const voiceIso = (voiceIsolation && !speechOn) ? silenceFloor : 1;

            // gate envelope + output
            for (let i=0;i<hop;i++){
                const x = ola[i];
                const ax = Math.abs(x);
                const coef = (ax > env) ? atk : rel;
                env += (ax - env) * coef;
                const target = (env >= gateThreshold) ? 1 : gateFloor;
                const gcoef = (target > gateGain) ? atk : rel;
                gateGain += (target - gateGain) * gcoef;
                outBuf[outOff+i] = x * gateGain * voiceIso;
            }

            ola.copyWithin(0, hop);
            ola.fill(0, N-hop);
        }

        const sp = ctx.createScriptProcessor(256, 1, 1);
        sp.onaudioprocess = (e) => {
            try{
                const inp = e.inputBuffer.getChannelData(0);
                const out = e.outputBuffer.getChannelData(0);
                processHop(inp, 0, out, 0);
                processHop(inp, 128, out, 128);
            }catch(err){
                // fail open
                try{
                    const inp = e.inputBuffer.getChannelData(0);
                    const out = e.outputBuffer.getChannelData(0);
                    out.set(inp);
                }catch(e2){}
            }
        };
        return sp;
    }catch(e){
        return null;
    }
}


// Lightweight ScriptProcessor noise gate (no FFT). Used as a fallback when AudioWorklet
// isn't available but we still want background hiss to drop in silence.
function _ncCreateScriptGateOnlyNode(ctx, opts){
    try{
        if (!ctx || !ctx.createScriptProcessor) return null;
        const o = opts || {};
        const thresholdDb = (typeof o.thresholdDb === 'number') ? o.thresholdDb : -46;
        const floorDb = (typeof o.floorDb === 'number') ? o.floorDb : -30;
        const attackMs = (typeof o.attackMs === 'number') ? o.attackMs : 4;
        const releaseMs = (typeof o.releaseMs === 'number') ? o.releaseMs : 260;

        const sr = ctx.sampleRate || 48000;
        const thr = Math.pow(10, thresholdDb/20);
        const floor = Math.pow(10, floorDb/20);
        const atk = 1 - Math.exp(-1 / (sr * (Math.max(1, attackMs)/1000)));
        const rel = 1 - Math.exp(-1 / (sr * (Math.max(1, releaseMs)/1000)));

        let env = 0;
        let g = 1;
        const sp = ctx.createScriptProcessor(256, 1, 1);
        sp.onaudioprocess = (e) => {
            try{
                const input = e.inputBuffer.getChannelData(0);
                const output = e.outputBuffer.getChannelData(0);
                for (let i=0;i<input.length;i++){
                    const x = input[i] || 0;
                    const ax = Math.abs(x);
                    const ecoef = (ax > env) ? atk : rel;
                    env += (ax - env) * ecoef;
                    const target = (env >= thr) ? 1 : floor;
                    const gcoef = (target > g) ? atk : rel;
                    g += (target - g) * gcoef;
                    output[i] = x * g;
                }
            }catch(err){
                try{ e.outputBuffer.getChannelData(0).set(e.inputBuffer.getChannelData(0)); }catch(_){ }
            }
        };
        return sp;
    }catch(e){
        return null;
    }
}

function _ncBuildLocalAudioStream(rawStream){
    // Discord-like mic pipeline:
    // - Prefer WebRTC built-in echo/noise/AGC (set via getUserMedia constraints)
    // - Add only gentle post-processing locally (HPF + optional soft gate + subtle EQ + compression + limiter)
    // This avoids the "radio/underwater" artifacts caused by heavy spectral subtraction.
    try{
        if (!rawStream) return rawStream;
        const Ctx = window.AudioContext || window.webkitAudioContext;
        if (!Ctx) return rawStream;

        const ctx = _ensureVoiceAudioCtx();
        if (!ctx) return rawStream;

        try{ if (ctx.state === 'suspended') ctx.resume(); }catch(e){}

        // QUALITY MODE (Discord-like): by default we DO NOT run any custom WebAudio
        // processing, because extra compressor/gates can create a metallic/"robot" tone.
        // We only enable the heavier custom chain when the user selects Ultra noise mode.
        try{
            const vv = _ncVvLoad();
            const mode = (vv && vv.noiseSuppression != null)
                ? String(vv.noiseSuppression || '')
                : (audioSettings && audioSettings.noiseMode ? String(audioSettings.noiseMode) : '');
            if (!mode || mode !== 'ultra') {
                _ncDestroyLocalAudioPipeline();
                return rawStream;
            }
        }catch(e){}

        _ncDestroyLocalAudioPipeline();

        const src = ctx.createMediaStreamSource(rawStream);
        let node = src;

        // If browser noise suppression is disabled, we still want the user mic EQ to work.
        // When noise suppression is enabled, the EQ nodes are inserted inside that branch (after HPF).
        try{
            if (!noiseSuppressionEnabled){
                const vv = _ncVvLoad();
                const bassDb = parseInt(String(vv.micBassDb ?? 0), 10) || 0;
                const trebleDb = parseInt(String(vv.micTrebleDb ?? 0), 10) || 0;

                const bass = ctx.createBiquadFilter();
                bass.type = 'lowshelf';
                bass.frequency.value = 120;
                bass.gain.value = bassDb;
                node.connect(bass);
                node = bass;
                localMicEqBassNode = bass;

                const treb = ctx.createBiquadFilter();
                treb.type = 'highshelf';
                treb.frequency.value = 4500;
                treb.gain.value = trebleDb;
                node.connect(treb);
                node = treb;
                localMicEqTrebleNode = treb;
            }
        }catch(e){ localMicEqBassNode = null; localMicEqTrebleNode = null; }

        const mode = (audioSettings && audioSettings.noiseMode) ? String(audioSettings.noiseMode) : 'basic';
        const ultra = (noiseSuppressionEnabled && mode === 'ultra');

        // Small automatic tuning based on the selected input device.
        // Headset mics (e.g., Logitech G Pro) often have noticeable hiss/typing bleed, so we tighten suppression a bit.
        let __micLabel = '';
        try{
            const tr = (rawStream.getAudioTracks && rawStream.getAudioTracks()[0]) ? rawStream.getAudioTracks()[0] : null;
            __micLabel = tr && tr.label ? String(tr.label).toLowerCase() : '';
        }catch(e){}
        const __isHeadset = (__micLabel.includes('logitech') && (__micLabel.includes('g pro') || __micLabel.includes('pro x') || __micLabel.includes('gpro') || __micLabel.includes('gpro x'))) || (__micLabel.includes('headset') || __micLabel.includes('науш'));
        // Baseline "NEON-like" tuning (balanced: strong noise cut, minimal "underwater" artifacts)
        let denAgg = 0.96;
        let denFloor = 0.034;
        let denLearn = 0.078;
        let denHf = 0.68;
        let denHold = 28;
        let denClickFloor = 0.074;
        let denClickHold = 12;
        let denClickBroad = 0.42;
        let denClickLow = 0.36;
        let denClickMid = 0.68;
        let denClickBroadSpeech = 0.76;
        // Headset preset: a touch stronger for keyboard / hiss, but still tuned to avoid metallic artifacts.
        if (__isHeadset){
            denAgg = 0.99;
            denFloor = 0.036;
            denLearn = 0.082;
            denHf = 0.66;
            denHold = 30;
            denClickBroad = 0.46;
            denClickLow = 0.38;
            denClickMid = 0.72;
            denClickBroadSpeech = 0.80;
        }

        if (noiseSuppressionEnabled){

        // Highpass: remove rumble/desk thumps but keep some low end so voice can stay warm.
        try{
            const hp = ctx.createBiquadFilter();
            hp.type = 'highpass';
            hp.frequency.value = ultra ? 80 : 90;
            node.connect(hp);
            node = hp;
            localMicHpNode = hp;
        }catch(e){}

        // User mic EQ (bass/treble). These sliders live in Settings -> Voice & Video.
        // They must only affect the local microphone.
        try{
            const vv = _ncVvLoad();
            const bassDb = parseInt(String(vv.micBassDb ?? 0), 10) || 0;
            const trebleDb = parseInt(String(vv.micTrebleDb ?? 0), 10) || 0;

            const bass = ctx.createBiquadFilter();
            bass.type = 'lowshelf';
            bass.frequency.value = 120;
            bass.gain.value = bassDb;
            node.connect(bass);
            node = bass;
            localMicEqBassNode = bass;

            const treb = ctx.createBiquadFilter();
            treb.type = 'highshelf';
            treb.frequency.value = 4500;
            treb.gain.value = trebleDb;
            node.connect(treb);
            node = treb;
            localMicEqTrebleNode = treb;
        }catch(e){ localMicEqBassNode = null; localMicEqTrebleNode = null; }

        // Denoiser (ULTRA): reduce steady noise + typing/clicks.
        // Uses AudioWorklet when available; falls back to ScriptProcessor otherwise.
        try{
            if (ultra){
                const hasAw = _ncHasAudioWorklet(ctx);
                if (hasAw && __ncDenoiseReady){
                    const den = new AudioWorkletNode(ctx, 'neon-denoise-processor', {
                        processorOptions: {
                            aggressiveness: denAgg,
                            floor: denFloor,
                            noiseLearn: denLearn,
                            speechThresh: __isHeadset ? 0.016 : 0.014,
                            voiceIsolation: false,
                            voiceHoldFrames: denHold,
                            silenceFloor: 0.12,
                            hfDamp: denHf,
                            clickSuppression: 0.72,
                            clickFloor: denClickFloor,
                            clickHoldFrames: denClickHold,
                            clickBroad: denClickBroad,
                            clickLow: denClickLow,
                            clickMid: denClickMid,
                            clickBroadSpeech: denClickBroadSpeech,
                            autoTune: true
                        }
                    });
                    node.connect(den);
                    node = den;
                    localMicDenoiseNode = den;
                } else {
                    // ScriptProcessor fallback (works even if AudioWorklet is unavailable)
                    const sp = _ncCreateScriptDenoiseGateNode(ctx, {
                        aggressiveness: denAgg,
                        floor: denFloor,
                        noiseLearn: denLearn,
                        speechThresh: __isHeadset ? 0.016 : 0.014,
                        voiceIsolation: false,
                        voiceHoldFrames: denHold,
                        silenceFloor: 0.12,
                        hfDamp: denHf,
                        clickSuppression: 0.72,
                        clickFloor: denClickFloor,
                        clickHoldFrames: denClickHold,
                        clickBroad: denClickBroad,
                        clickLow: denClickLow,
                        clickMid: denClickMid,
                        clickBroadSpeech: denClickBroadSpeech,
                        gateThresholdDb: -61,
                        gateFloorDb: -58,
                        gateAttackMs: 7,
                        gateReleaseMs: 320,
                        autoTune: true
                    });
                    if (sp){
                        node.connect(sp);
                        node = sp;
                        localMicDenoiseNode = sp;
                        localMicScriptNode = sp;
                    }
                }
            }
        }catch(e){}

        // Optional soft gate (ULTRA only, when denoiser isn't available): lowers background between words.
        try{
            if (ultra && !localMicDenoiseNode){
                const hasAw = _ncHasAudioWorklet(ctx);
                if (hasAw && __ncNoiseGateReady){
                    const gate = new AudioWorkletNode(ctx, 'noise-gate-processor', {
                        processorOptions: {
                            thresholdDb: -60,
                            attackMs: 7,
                            releaseMs: 320,
                            floorDb: -40
                        }
                    });
                    node.connect(gate);
                    node = gate;
                    localMicGateNode = gate;
                } else {
                    const sg = _ncCreateScriptGateOnlyNode(ctx, {
                        thresholdDb: -60,
                        attackMs: 7,
                        releaseMs: 320,
                        floorDb: -40
                    });
                    if (sg){
                        node.connect(sg);
                        node = sg;
                        localMicGateNode = sg;
                        localMicScriptNode = sg;
                    }
                }
            }
        }catch(e){}


        // Soft gate for BASIC mode too: drops steady hiss between words (headsets benefit a lot).
        try{
            if (!ultra){
                const hasAw = _ncHasAudioWorklet(ctx);
                const thrDb = __isHeadset ? -44 : -46;
                const floorDb = __isHeadset ? -42 : -38;
                if (hasAw && __ncNoiseGateReady){
                    const gate = new AudioWorkletNode(ctx, 'noise-gate-processor', {
                        processorOptions: { thresholdDb: thrDb, attackMs: 10, releaseMs: 260, floorDb: floorDb }
                    });
                    node.connect(gate);
                    node = gate;
                    localMicGateNode = gate;
                } else {
                    const sg = _ncCreateScriptGateOnlyNode(ctx, {
                        thresholdDb: thrDb,
                        attackMs: 6,
                        releaseMs: 260,
                        floorDb: floorDb
                    });
                    if (sg){
                        node.connect(sg);
                        node = sg;
                        localMicGateNode = sg;
                        localMicScriptNode = sg;
                    }
                }
            }
        }catch(e){}
        // Lowpass: gentle HF rolloff to reduce harshness on cheap mics (does NOT affect clarity much).
        try{
            const lp = ctx.createBiquadFilter();
            lp.type = 'lowpass';
            lp.frequency.value = ultra ? 12000 : 14000;
            node.connect(lp);
            node = lp;
            localMicLpNode = lp;
        }catch(e){}

        // Voice enhancement (ULTRA): subtle EQ for warmth + clarity, designed to be safe across mic types.
        try{
            if (ultra){
                localMicEnhNodes = [];

                // Warmth / slight bass
                const warm = ctx.createBiquadFilter();
                warm.type = 'lowshelf';
                warm.frequency.value = 140;
                warm.gain.value = 2.2;
                node.connect(warm); node = warm; localMicEnhNodes.push(warm);

                // Cut mud
                const mud = ctx.createBiquadFilter();
                mud.type = 'peaking';
                mud.frequency.value = 260;
                mud.Q.value = 1.0;
                mud.gain.value = -2.0;
                node.connect(mud); node = mud; localMicEnhNodes.push(mud);

                // Reduce boxiness
                const box = ctx.createBiquadFilter();
                box.type = 'peaking';
                box.frequency.value = 900;
                box.Q.value = 1.2;
                box.gain.value = -1.2;
                node.connect(box); node = box; localMicEnhNodes.push(box);

                // Presence
                const pres = ctx.createBiquadFilter();
                pres.type = 'peaking';
                pres.frequency.value = 3200;
                pres.Q.value = 0.9;
                pres.gain.value = 2.3;
                node.connect(pres); node = pres; localMicEnhNodes.push(pres);

                // Light de-ess (static)
                const deess = ctx.createBiquadFilter();
                deess.type = 'peaking';
                deess.frequency.value = 7200;
                deess.Q.value = 2.8;
                deess.gain.value = -1.8;
                node.connect(deess); node = deess; localMicEnhNodes.push(deess);

                // Tiny air
                const air = ctx.createBiquadFilter();
                air.type = 'highshelf';
                air.frequency.value = 9000;
                air.gain.value = 0.6;
                node.connect(air); node = air; localMicEnhNodes.push(air);
            }
        }catch(e){}

        }

        // Gentle compression + limiter (ULTRA/BASIC). Keeps voice present without pumping/"radio".
        let micComp = null;
        let micLimiter = null;
        try{
            micComp = ctx.createDynamicsCompressor();
            if (ultra){
                micComp.threshold.value = -23;
                micComp.knee.value = 18;
                micComp.ratio.value = 2.7;
                micComp.attack.value = 0.0035;
                micComp.release.value = 0.18;
            } else {
                // BASIC: softer, just to keep voice a bit louder/steadier
                micComp.threshold.value = -26;
                micComp.knee.value = 24;
                micComp.ratio.value = 2.0;
                micComp.attack.value = 0.005;
                micComp.release.value = 0.18;
            }
            if (ultra) {
                micLimiter = _ncBuildLimiter(ctx);
            }
        }catch(e){ micComp = null; micLimiter = null; }

        const gain = ctx.createGain();
        gain.gain.value = _ncGetMicGainFactor();
        const dest = ctx.createMediaStreamDestination();

        if (micComp) {
            try{ node.connect(micComp); }catch(e){}
            node = micComp;
        }

        node.connect(gain);
        if (micLimiter) {
            try{ gain.connect(micLimiter); micLimiter.connect(dest); }catch(e){ gain.connect(dest); }
        } else {
            gain.connect(dest);
        }

        localMicSourceNode = src;
        localMicGainNode = gain;
        localMicDestNode = dest;

        return dest.stream;
    }catch(e){
        return rawStream;
    }
}

function _ncUpdateLocalMicGainFromSettings(){

    try{
        if (localMicGainNode && localMicGainNode.gain) {
            const should = (typeof _ncShouldTransmitAudioNow === 'function') ? _ncShouldTransmitAudioNow() : (!isMicMuted);
            localMicGainNode.gain.value = should ? _ncGetMicGainFactor() : 0;
        }
}catch(e){}
}

let __ncApplyVvTimer = null;
function ncApplyVvSettingsLive(opts){
    const o = opts || {};
    try{
        const s = _ncVvLoad();

        // User mic EQ (bass/treble) can be updated live without rebuilding the full pipeline.
        try{
            if (localMicEqBassNode && localMicEqBassNode.gain) {
                localMicEqBassNode.gain.value = parseInt(String(s.micBassDb ?? 0), 10) || 0;
            }
            if (localMicEqTrebleNode && localMicEqTrebleNode.gain) {
                localMicEqTrebleNode.gain.value = parseInt(String(s.micTrebleDb ?? 0), 10) || 0;
            }
        }catch(e){}

        // Devices
        if (typeof s.inputDeviceId !== 'undefined') audioSettings.inputDeviceId = s.inputDeviceId ? String(s.inputDeviceId) : null;
        if (typeof s.outputDeviceId !== 'undefined') audioSettings.outputDeviceId = s.outputDeviceId ? String(s.outputDeviceId) : null;

        // Custom processing switches -> constraints
        if (typeof s.echoCancel === 'boolean') audioSettings.echoCancellation = !!s.echoCancel;
        if (typeof s.agc === 'boolean') audioSettings.autoGainControl = !!s.agc;
        // Noise suppression
        if (typeof s.noiseSuppression !== 'undefined'){
            const n = String(s.noiseSuppression || 'krisp');
            if (n === 'none') {
                noiseSuppressionEnabled = false;
                try{ audioSettings.nativeNoiseSuppression = false; }catch(e){}
            } else if (n === 'standard') {
                noiseSuppressionEnabled = true;
                audioSettings.noiseMode = 'basic';
                // Browser mode: keep the native suppression on.
                try{ audioSettings.nativeNoiseSuppression = true; }catch(e){}
            } else {
                // NP ClearVoice: use our gentler custom chain without stacking the browser NS on top,
                // which helps preserve timbre and avoids the "underwater / radio" tone.
                noiseSuppressionEnabled = true;
                audioSettings.noiseMode = 'ultra';
                try{ audioSettings.nativeNoiseSuppression = false; }catch(e){}
            }
        }

        // YaBrowser safety: ULTRA (custom denoise/worklet) can spike CPU. Force BASIC.
        try{
            if (__ncIsYa || window.__NC_YABROWSER){
                if ((audioSettings.noiseMode || 'basic') === 'ultra'){
                    audioSettings.noiseMode = 'basic';
                    try{ localStorage.setItem('voice_noise_mode','basic'); }catch(e){}
                }
            }
        }catch(e){}

        // Prepare worklet (best-effort) so noise suppression has a real effect.
        try{ if (noiseSuppressionEnabled) { _ncEnsureNoiseGateReady(); } }catch(e){}

        // Output volume -> reuse existing volume system
        const v = _ncGetVoiceOutVol();
        if (v !== null){
            try{ saveVolume(VOL_KEY_VOICE, v); }catch(e){}
            try{
                const vs = document.getElementById('vol-voice');
                if (vs) vs.value = String(Math.round(v*100));
            }catch(e){}
            try{ applyVolumes(); }catch(e){}
        }

        // Apply output device (best-effort)
        try{ ncApplyOutputDeviceNow(); }catch(e){}

        // Mic gain (live)
        _ncUpdateLocalMicGainFromSettings();

        try{ _ncApplyLocalMicGateState(); }catch(e){}
        const active = !!(peerConnection || groupCallActive);
        const needsRestart = !!o.needsRestart;
        if (active && needsRestart){
            if (__ncApplyVvTimer) clearTimeout(__ncApplyVvTimer);
            __ncApplyVvTimer = setTimeout(() => { try{ ncRestartLocalAudioTrack(); }catch(e){} }, 250);
        }
    }catch(e){}
}
try{ window.ncApplyVvSettingsLive = ncApplyVvSettingsLive; }catch(e){}
try{ ncApplyVvSettingsLive(); }catch(e){}

async function ncRestartLocalAudioTrack(){
    // Re-acquire mic with current constraints and replace tracks in existing calls.
    try{
        if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) return false;
        const mode = (audioSettings && audioSettings.noiseMode) || 'basic';
        const audioConstraints = {};
        const __nativeNs = (audioSettings && typeof audioSettings.nativeNoiseSuppression === 'boolean') ? !!audioSettings.nativeNoiseSuppression : true;
        try{
            if (typeof audioSettings.echoCancellation === 'boolean') audioConstraints.echoCancellation = audioSettings.echoCancellation;
            if (typeof audioSettings.autoGainControl === 'boolean') audioConstraints.autoGainControl = audioSettings.autoGainControl;
            if (noiseSuppressionEnabled) {
                audioConstraints.noiseSuppression = __nativeNs;
            } else {
                audioConstraints.noiseSuppression = false;
            }
            
            // Best-effort "typing noise" suppression flags (Chrome legacy constraints).
            // These are ignored by browsers that don't support them.
            try{
                audioConstraints.googTypingNoiseDetection = true;
                audioConstraints.googHighpassFilter = true;
                if (typeof audioConstraints.noiseSuppression !== 'undefined') audioConstraints.googNoiseSuppression = audioConstraints.noiseSuppression;
                if (typeof audioConstraints.echoCancellation !== 'undefined') audioConstraints.googEchoCancellation = audioConstraints.echoCancellation;
                if (typeof audioConstraints.autoGainControl !== 'undefined') audioConstraints.googAutoGainControl = audioConstraints.autoGainControl;
            }catch(e){}
if (audioSettings.inputDeviceId) audioConstraints.deviceId = { exact: audioSettings.inputDeviceId };
        }catch(e){}

        try{
        if (noiseSuppressionEnabled) {
            await _ncEnsureNoiseGateReady();
            if (String(mode) === "ultra") { await _ncEnsureDenoiseReady(); }
        }
    }catch(e){}

        const raw = await navigator.mediaDevices.getUserMedia({ audio: audioConstraints });
        const send = _ncBuildLocalAudioStream(raw);

        const newTrack = (send && send.getAudioTracks) ? (send.getAudioTracks()[0] || null) : null;
        if (!newTrack) return false;

        // stop old processed + raw
        try{ if (localStream) localStream.getTracks().forEach(t => { try{t.stop();}catch(e){} }); }catch(e){}
        try{ if (localRawStream) localRawStream.getTracks().forEach(t => { try{t.stop();}catch(e){} }); }catch(e){}

        localRawStream = raw;
        localStream = send;
        try{ _ncApplyLocalMicGateState(); }catch(e){}

        // Replace on 1:1 (DM): ONLY the VOICE sender (avoid overwriting music/screen audio slots)
        try{
            if (peerConnection) {
                if (peerConnection.__ncDmTxVoiceA && peerConnection.__ncDmTxVoiceA.sender) {
                    try{ peerConnection.__ncDmTxVoiceA.sender.replaceTrack(newTrack); }catch(e){}
                } else if (peerConnection.getSenders) {
                    const txMusic = (peerConnection.__ncDmTxMusicA && peerConnection.__ncDmTxMusicA.sender) ? peerConnection.__ncDmTxMusicA.sender : null;
                    const txScrA  = (peerConnection.__ncDmTxScreenA && peerConnection.__ncDmTxScreenA.sender) ? peerConnection.__ncDmTxScreenA.sender : null;
                    peerConnection.getSenders().forEach(s=>{
                        if (!s || !s.track || s.track.kind !== 'audio') return;
                        if (txMusic && s === txMusic) return;
                        if (txScrA && s === txScrA) return;
                        try{ s.replaceTrack(newTrack); }catch(e){}
                    });
                }
            }
        }catch(e){}

        // Replace on group: only the MIC sender (do not overwrite music senders)
        try{
            if (groupCallActive && groupPeers) {
                Object.keys(groupPeers).forEach(pid => {
                    const ent = groupPeers[pid];
                    const pc = ent && ent.pc;
                    if (!pc || !pc.getSenders) return;

                    // Preferred: sender captured at connection creation
                    try{
                        if (ent && ent.__ncMicSender && ent.__ncMicSender.replaceTrack) {
                            ent.__ncMicSender.replaceTrack(newTrack);
                            return;
                        }
                    }catch(e){}

                    // Fallback: replace all audio senders EXCEPT the known music sender (per-peer)
                    let mSender = null;
                    try{
                        if (typeof groupMusicSendersByPeer !== 'undefined' && groupMusicSendersByPeer) {
                            mSender = groupMusicSendersByPeer[String(pid)] || null;
                        }
                    }catch(e){}
                    pc.getSenders().forEach(s => {
                        if (!s || !s.track || s.track.kind !== 'audio') return;
                        if (mSender && s === mSender) return;
                        try{ s.replaceTrack(newTrack); }catch(e){}
                    });
                });
            }
        }catch(e){}

        // Update local monitor
        try{
            const refs = window._callUI || {};
            if (refs.localAudio) refs.localAudio.srcObject = localStream;
        }catch(e){}

        // Keep analyzer on my uid
        try{ if (currentUserId) _attachVoiceAnalyzer(currentUserId, localStream); }catch(e){}

        // Output device and volume
        try{ ncApplyOutputDeviceNow(); }catch(e){}
        try{ applyVolumes(); }catch(e){}

        return true;
    }catch(e){
        console.warn('ncRestartLocalAudioTrack failed', e);
        return false;
    }
}

