// Group-call remote audio: play each incoming audio track through a dedicated <audio> element.
// This avoids WebAudio autoplay/suspended issues (especially in Yandex Browser).
const __ncGroupAudioEls = (window.__ncGroupAudioEls = window.__ncGroupAudioEls || {}); // key -> <audio>
let __ncGroupAudioUnlockedAt = 0;

function __ncGroupAudioNoteUserGesture(){
    try{ __ncGroupAudioUnlockedAt = Date.now(); }catch(e){}
}

function __ncGroupAudioTrackKey(peerId, track){
    try{
        const pid = String(peerId ?? '');
        const tid = track && track.id ? String(track.id) : String(Math.random()).slice(2);
        return pid + ':' + tid;
    }catch(e){
        return String(peerId ?? '') + ':' + String(Math.random()).slice(2);
    }
}

function __ncAttachGroupPeerAudio(peerId, track){
    try{
        if (!track) return;
        const key = __ncGroupAudioTrackKey(peerId, track);
        if (__ncGroupAudioEls[key]) return;

        const a = document.createElement('audio');
        a.autoplay = true;
        a.playsInline = true;
        a.muted = !!isRemoteMuted;
        a.style.display = 'none';
        a.dataset.ncGroupAudio = '1';
        a.dataset.ncPendingPlay = '';

        const ms = new MediaStream();
        try{ ms.addTrack(track); }catch(e){}
        a.srcObject = ms;

        try{ document.body.appendChild(a); }catch(e){}
        __ncGroupAudioEls[key] = a;

        // Apply current voice volume (global)
        try{
            const voiceVol = (typeof loadVolume === 'function') ? loadVolume(VOL_KEY_VOICE, 1) : 1;
            if (typeof _ncSetMediaElementGain === 'function') _ncSetMediaElementGain(a, voiceVol);
            else a.volume = Math.max(0, Math.min(1, voiceVol));
        }catch(e){}

        // Try play; if blocked, it will be marked pending by __ncTryPlay.
        try{
            if (typeof __ncTryPlay === 'function') __ncTryPlay(a);
            else {
                const p = a.play();
                if (p && typeof p.catch === 'function') p.catch(()=>{});
            }
        }catch(e){}

        // If a user gesture happened very recently (Accept/Join), retry once (helps Yandex).
        try{
            if (__ncGroupAudioUnlockedAt && (Date.now() - __ncGroupAudioUnlockedAt) < 5000) {
                const p2 = a.play();
                if (p2 && typeof p2.catch === 'function') p2.catch(()=>{});
            }
        }catch(e){}

        // Cleanup on end
        try{
            track.onended = () => { try{ __ncDetachGroupAudioKey(key); }catch(e){} };
        }catch(e){}

    }catch(e){}
}

function __ncDetachGroupAudioKey(key){
    try{
        const a = __ncGroupAudioEls[key];
        if (!a) return;
        try{ a.pause(); }catch(e){}
        try{ a.srcObject = null; }catch(e){}
        try{ a.remove(); }catch(e){}
        delete __ncGroupAudioEls[key];
    }catch(e){}
}

function __ncGroupAudioCleanupPeer(peerId){
    try{
        const pid = String(peerId ?? '');
        Object.keys(__ncGroupAudioEls).forEach(k => {
            if (k.startsWith(pid + ':')) __ncDetachGroupAudioKey(k);
        });
    }catch(e){}
}

function __ncGroupAudioSetMuted(m){
    try{
        Object.values(__ncGroupAudioEls).forEach(a => { try{ a.muted = !!m; }catch(e){} });
    }catch(e){}
}

function __ncGroupAudioSetVolume01(v01){
    try{
        const v = Math.max(0, Math.min(1, Number(v01) || 0));
        Object.values(__ncGroupAudioEls).forEach(a => { try{ a.volume = v; }catch(e){} });
    }catch(e){}
}

