// FIX116: Stable group-call screenshare uses dedicated transceiver "slots" per peer.
// This avoids addTrack() races / renegotiation glitches that caused black screens or "no demo".
function _ncEnsureGroupSsSlots(pc){
    try{
        if (!pc) return false;
        let added = false;
        if (!pc.__ncGrpTxScreenV){
            try{ pc.__ncGrpTxScreenV = pc.addTransceiver('video', { direction: 'sendrecv' }); added = true; }catch(e){}
        }
        if (!pc.__ncGrpTxScreenA){
            try{ pc.__ncGrpTxScreenA = pc.addTransceiver('audio', { direction: 'sendrecv' }); added = true; }catch(e){}
        }
        return added;
    }catch(e){
        return false;
    }
}
function _ncGetGroupSsSenders(pc){
    try{
        const v = (pc && pc.__ncGrpTxScreenV && pc.__ncGrpTxScreenV.sender) ? pc.__ncGrpTxScreenV.sender : null;
        const a = (pc && pc.__ncGrpTxScreenA && pc.__ncGrpTxScreenA.sender) ? pc.__ncGrpTxScreenA.sender : null;
        return { v, a };
    }catch(e){
        return { v: null, a: null };
    }
}

// Group call: keep the regular microphone sender bound even after screenshare renegotiation.
// Some Chromium builds can reshuffle audio senders/transceivers on the answerer side, which
// makes the 2nd participant appear in voice but their mic stops sending after demo starts.
async function _ncGroupEnsureMicSenderBound(peerId, opts = {}){
    try{
        const pid = String(peerId || '');
        const entry = groupPeers && groupPeers[pid];
        const pc = entry && entry.pc;
        if (!pc) return false;

        let at = null;
        try{ at = (localStream && localStream.getAudioTracks) ? (localStream.getAudioTracks()[0] || null) : null; }catch(e){}
        if (!at || at.readyState === 'ended') {
            try{ at = (localRawStream && localRawStream.getAudioTracks) ? (localRawStream.getAudioTracks()[0] || null) : null; }catch(e){}
        }
        if ((!at || at.readyState === 'ended') && opts && opts.tryRestart){
            try{ await startLocalAudio(true); }catch(e){}
            try{ at = (localStream && localStream.getAudioTracks) ? (localStream.getAudioTracks()[0] || null) : null; }catch(e){}
            if (!at || at.readyState === 'ended') {
                try{ at = (localRawStream && localRawStream.getAudioTracks) ? (localRawStream.getAudioTracks()[0] || null) : null; }catch(e){}
            }
        }
        if (!at || at.readyState === 'ended') return false;
        try{ at.enabled = true; }catch(e){}

        const ss = _ncGetGroupSsSenders(pc);
        const ssAudioSender = ss && ss.a ? ss.a : null;
        let musicSender = null;
        try{ musicSender = (groupMusicSendersByPeer && groupMusicSendersByPeer[pid]) ? groupMusicSendersByPeer[pid] : null; }catch(e){}

        let micSender = null;
        try{
            if (entry.__ncMicSender && entry.__ncMicSender !== ssAudioSender && entry.__ncMicSender !== musicSender) {
                micSender = entry.__ncMicSender;
            }
        }catch(e){}

        // Refresh sender by transceiver mapping first (more stable than relying on sender.track).
        try{
            if (!micSender && pc.getTransceivers){
                const txs = pc.getTransceivers() || [];
                for (const tx of txs){
                    if (!tx || !tx.sender || tx.sender === ssAudioSender || tx.sender === musicSender) continue;
                    const rk = tx.receiver && tx.receiver.track ? tx.receiver.track.kind : '';
                    const sk = tx.sender && tx.sender.track ? tx.sender.track.kind : '';
                    if (rk === 'audio' || sk === 'audio'){
                        micSender = tx.sender;
                        try{ tx.__ncRole = 'group_mic_audio'; }catch(e){}
                        break;
                    }
                }
            }
        }catch(e){}

        // Fallback: any audio sender except music/screenshare audio.
        try{
            if (!micSender && pc.getSenders){
                const senders = pc.getSenders() || [];
                micSender = senders.find(sd => {
                    try{
                        if (!sd || sd === ssAudioSender || sd === musicSender) return false;
                        if (sd.track && sd.track.kind === 'audio') return true;
                        if (pc.getTransceivers){
                            const tx = (pc.getTransceivers() || []).find(t => t && t.sender === sd);
                            const rk = tx && tx.receiver && tx.receiver.track ? tx.receiver.track.kind : '';
                            return rk === 'audio';
                        }
                    }catch(e){}
                    return false;
                }) || null;
            }
        }catch(e){}

        // Last resort: explicitly add the mic track (rare recovery path).
        if (!micSender){
            try{ micSender = pc.addTrack(at, new MediaStream([at])); }catch(e){}
        }
        if (!micSender) return false;

        try{ entry.__ncMicSender = micSender; }catch(e){}

        // Force sendrecv on the transceiver that owns the mic sender.
        try{
            if (pc.getTransceivers){
                (pc.getTransceivers() || []).forEach(tx => {
                    try{
                        if (!tx || tx.sender !== micSender) return;
                        try{ tx.direction = 'sendrecv'; }catch(e){}
                        try{ tx.__ncRole = 'group_mic_audio'; }catch(e){}
                    }catch(e){}
                });
            }
        }catch(e){}

        try{ await micSender.replaceTrack(at); }catch(e){}
        try{ isMicMuted = false; _ncApplyLocalMicGateState(); }catch(e){}

        // If our mic accidentally got duplicated into the screenshare-audio slot, clear it unless
        // we are intentionally sharing tab audio right now.
        try{
            const ssTrack = ssAudioSender && ssAudioSender.track ? ssAudioSender.track : null;
            const hasGroupSsAudio = !!(groupScreenSharing && groupScreenStream && groupScreenStream.getAudioTracks && groupScreenStream.getAudioTracks().length);
            const sameMic = !!(ssTrack && at && ssTrack.id && at.id && String(ssTrack.id) === String(at.id));
            if (sameMic && !hasGroupSsAudio){
                try{ await ssAudioSender.replaceTrack(null); }catch(e){}
            }
        }catch(e){}

        // Watchdog: if bytes don't flow after renegotiation, rebind once more (helps the answering peer).
        try{
            const doWatch = !(opts && opts.watchdog === false);
            if (doWatch){
                const token = Date.now() + ':' + pid;
                entry.__ncMicBindWatch = token;
                setTimeout(async () => {
                    try{
                        const e2 = groupPeers && groupPeers[pid];
                        if (!e2 || !e2.pc || e2.__ncMicBindWatch !== token) return;
                        const snd = e2.__ncMicSender;
                        if (!snd) return;
                        let bytes = 0;
                        try{ if (typeof __ncGetOutboundBytes === 'function') bytes = await __ncGetOutboundBytes(snd, 'audio'); }catch(e){}
                        if (Number(bytes || 0) >= 160) return;

                        try{ await startLocalAudio(true); }catch(e){}
                        let at2 = null;
                        try{ at2 = (localStream && localStream.getAudioTracks) ? (localStream.getAudioTracks()[0] || null) : null; }catch(e){}
                        if (!at2 || at2.readyState === 'ended') {
                            try{ at2 = (localRawStream && localRawStream.getAudioTracks) ? (localRawStream.getAudioTracks()[0] || null) : null; }catch(e){}
                        }
                        if (!at2) return;
                        try{ at2.enabled = true; }catch(e){}
                        try{ await snd.replaceTrack(at2); }catch(e){}
                        try{ isMicMuted = false; _ncApplyLocalMicGateState(); }catch(e){}
                    }catch(e){}
                }, (opts && opts.watchDelayMs) ? Number(opts.watchDelayMs) : 1400);
            }
        }catch(e){}

        return true;
    }catch(e){
        return false;
    }
}

