const RECONNECT_STORAGE_KEY = 'nc_reconnect_state_v1';

// ---------------------------------------------------------------------
// Discord-like auto reconnect for 1:1 DM calls (ЛС).
// When the connection drops, we retry with backoff during the reconnect window.
// This is intentionally conservative to avoid spamming offers / breaking the call flow.
// ---------------------------------------------------------------------
let __ncDmAutoReconnect = { active:false, timer:null, attempts:0, inFlight:false, startedAt:0, lastReason:'' };
const __NC_DM_AUTORECONNECT_MAX_ATTEMPTS = 14;
const __NC_DM_AUTORECONNECT_BASE_DELAY_MS = 650;
const __NC_DM_AUTORECONNECT_MAX_DELAY_MS = 12000;

function __ncStopDmAutoReconnect(){
    try{ if (__ncDmAutoReconnect && __ncDmAutoReconnect.timer) clearTimeout(__ncDmAutoReconnect.timer); }catch(e){}
    try{
        __ncDmAutoReconnect.timer = null;
        __ncDmAutoReconnect.active = false;
        __ncDmAutoReconnect.attempts = 0;
        __ncDmAutoReconnect.inFlight = false;
        __ncDmAutoReconnect.startedAt = 0;
        __ncDmAutoReconnect.lastReason = '';
        __ncDmAutoReconnect.role = '';
    }catch(e){}
}

function __ncCanAutoReconnectDm(st){
    try{
        if (!st || st.type !== 'dm') return false;
        if (st.expiresAt && Date.now() > st.expiresAt) return false;
        // If we are already connected (or in-progress), don't start a new cycle.
        if (peerConnection && currentCallTargetId) return false;
        // If we have a pending incoming call modal, let that flow resolve first.
        if (pendingIncomingCall && pendingIncomingCall.from_id) return false;
        return true;
    }catch(e){
        return false;
    }
}

function __ncKickDmAutoReconnect(reason, opts){
    try{
        const st = (typeof getReconnectState === 'function') ? getReconnectState() : null;
        if (!__ncCanAutoReconnectDm(st)) return;
        opts = opts || {};
        if (!__ncDmAutoReconnect.active || opts.reset){
            __ncDmAutoReconnect.active = true;
            __ncDmAutoReconnect.attempts = 0;
            __ncDmAutoReconnect.inFlight = false;
            __ncDmAutoReconnect.startedAt = Date.now();
            __ncDmAutoReconnect.lastReason = String(reason || '');
            __ncDmAutoReconnect.role = '';
            // Deterministic reconnect initiator to avoid "glare" (both sides sending offers):
            // Smaller user_id initiates; the other side waits briefly and auto-accepts.
            try{
                const me = (typeof currentUserId !== 'undefined' && currentUserId) ? (parseInt(currentUserId, 10) || 0) : 0;
                const peer = (st && st.targetId) ? (parseInt(st.targetId, 10) || 0) : 0;
                if (me && peer) __ncDmAutoReconnect.role = (me < peer) ? 'init' : 'wait';
                else __ncDmAutoReconnect.role = 'init';
            }catch(e){}
        }
        const delay = (typeof opts.delayMs === 'number') ? opts.delayMs : 450;
        __ncScheduleDmAutoReconnect(delay);
    }catch(e){}
}

function __ncScheduleDmAutoReconnect(delayMs){
    try{
        if (!__ncDmAutoReconnect || !__ncDmAutoReconnect.active) return;
        if (__ncDmAutoReconnect.timer) clearTimeout(__ncDmAutoReconnect.timer);
        __ncDmAutoReconnect.timer = setTimeout(__ncRunDmAutoReconnect, Math.max(0, Number(delayMs)||0));
    }catch(e){}
}

function __ncRunDmAutoReconnect(){
    let st = null;
    try{ st = (typeof getReconnectState === 'function') ? getReconnectState() : null; }catch(e){}
    if (!__ncCanAutoReconnectDm(st)) { __ncStopDmAutoReconnect(); return; }

    const refs = window._callUI || {};
    const callStatusText = refs.callStatusText;

    // If no socket connection, ask socket.io to reconnect, then try again shortly.
    if (!socket || !socket.connected){
        try{ if (typeof setCallHudMode === 'function') setCallHudMode('reconnecting'); }catch(e){}
        try{ if (callStatusText) callStatusText.textContent = 'Переподключаемся…'; }catch(e){}
        try{ socket && socket.connect && socket.connect(); }catch(e){}
        __ncScheduleDmAutoReconnect(800);
        return;
    }

    // If a reconnect attempt is already running, or we already created a PC, just wait.
    if (__ncDmAutoReconnect.inFlight || peerConnection){
        __ncScheduleDmAutoReconnect(1200);
        return;
    }

    // Deterministic initiator to avoid "glare" (both sides sending offers at the same time).
    // Smaller user_id initiates automatically; the other side waits a bit and auto-accepts.
    try{
        const me = (typeof currentUserId !== 'undefined' && currentUserId) ? (parseInt(currentUserId, 10) || 0) : 0;
        const peer = (st && st.targetId) ? (parseInt(st.targetId, 10) || 0) : 0;
        const role = (__ncDmAutoReconnect && __ncDmAutoReconnect.role) ? String(__ncDmAutoReconnect.role) : '';
        const myRole = role || ((me && peer && me < peer) ? 'init' : (me && peer ? 'wait' : 'init'));
        if (__ncDmAutoReconnect && !__ncDmAutoReconnect.role) __ncDmAutoReconnect.role = myRole;
        // Wait up to ~8s for the initiator to send an offer; then fall back to initiating.
        const elapsed = Date.now() - (Number(__ncDmAutoReconnect.startedAt) || Date.now());
        if (myRole === 'wait' && elapsed < 8000){
            try{ if (typeof setCallHudMode === 'function') setCallHudMode('reconnecting'); }catch(e){}
            try{ if (callStatusText) callStatusText.textContent = 'Ожидаем переподключение…'; }catch(e){}
            __ncScheduleDmAutoReconnect(900);
            return;
        }
    }catch(e){}

    // Attempts / limits
    __ncDmAutoReconnect.attempts = (Number(__ncDmAutoReconnect.attempts) || 0) + 1;
    const attemptNo = __ncDmAutoReconnect.attempts;

    if (attemptNo > __NC_DM_AUTORECONNECT_MAX_ATTEMPTS){
        __ncStopDmAutoReconnect();
        try{ if (typeof setCallHudMode === 'function') setCallHudMode('dropped'); }catch(e){}
        try{ if (callStatusText) callStatusText.textContent = 'Связь потеряна • нажми «Переподключиться»'; }catch(e){}
        return;
    }

    // Respect the reconnect window timer.
    try{
        if (st && st.expiresAt && Date.now() > st.expiresAt){
            __ncStopDmAutoReconnect();
            return;
        }
    }catch(e){}

    __ncDmAutoReconnect.inFlight = true;

    try{
        if (typeof setCallHudMode === 'function') setCallHudMode('reconnecting');
        if (callStatusText) callStatusText.textContent = 'Переподключаемся… попытка ' + attemptNo;
    }catch(e){}

    try{
        if (typeof attemptReconnectFromUI === 'function') attemptReconnectFromUI();
    }catch(e){}

    // Release "inFlight" after a short cool-down to avoid spamming offers.
    setTimeout(() => { try{ if (__ncDmAutoReconnect) __ncDmAutoReconnect.inFlight = false; }catch(e){} }, 2600);

    // Next delay: exponential backoff with jitter.
    const base = Math.min(__NC_DM_AUTORECONNECT_MAX_DELAY_MS, __NC_DM_AUTORECONNECT_BASE_DELAY_MS * Math.pow(1.6, Math.max(0, attemptNo - 1)));
    const jitter = Math.floor(Math.random() * 400);
    const next = base + jitter;

    __ncScheduleDmAutoReconnect(next);
}


