    // iOS-ish chat UX
    let shouldAutoScroll = true;

    // ---------------------------------------------------------------------
    // Persist last opened view (DM / server channel) + per-channel scroll.
    // Requirements:
    //  - On refresh, return user to the last opened DM/channel.
    //  - Restore scroll position inside that chat.
    // Implementation uses localStorage; server logic is not required.
    // ---------------------------------------------------------------------
    const __NC_LAST_VIEW_KEY = "nc_last_view_v2";
    const __NC_SCROLL_KEY_PREFIX = "nc_scroll_v2_";
    let __ncScrollSaveTimer = null;
    let __ncRestoringScroll = false;

    function __ncSafeJsonParse(raw){
        try{ return JSON.parse(raw); }catch(e){ return null; }
    }

    function __ncSetLastView(obj){
        try{
            const o = Object.assign({ ts: Date.now() }, (obj || {}));
            localStorage.setItem(__NC_LAST_VIEW_KEY, JSON.stringify(o));
        }catch(e){}
    }

    function __ncGetLastView(){
        try{
            const raw = localStorage.getItem(__NC_LAST_VIEW_KEY);
            const v = __ncSafeJsonParse(raw);
            return (v && typeof v === 'object') ? v : null;
        }catch(e){ return null; }
    }

    function __ncScrollKey(channelId){
        const cid = String(parseInt(channelId, 10) || 0);
        return __NC_SCROLL_KEY_PREFIX + cid;
    }

    function __ncCaptureScrollState(){
        try{
            if (!messagesContainer) return null;
            const cid = String(parseInt(currentChannelId, 10) || 0);
            if (!cid || cid === '0') return null;

            const contRect = messagesContainer.getBoundingClientRect();
            const rows = Array.from(messagesContainer.querySelectorAll('.msg-row[data-msg-id]'));
            let topId = null;
            let offset = 0;

            // Find first row that intersects the container viewport.
            for (let i=0; i<rows.length; i++){
                const el = rows[i];
                const r = el.getBoundingClientRect();
                if (r.bottom >= contRect.top + 1){
                    topId = (el.dataset.msgId || el.getAttribute('data-msg-id') || '').trim();
                    offset = Math.round(r.top - contRect.top);
                    break;
                }
            }

            return {
                scrollTop: Math.round(messagesContainer.scrollTop || 0),
                topId: topId || null,
                offset: Number.isFinite(offset) ? offset : 0,
                atBottom: !!isNearBottom(),
                ts: Date.now()
            };
        }catch(e){
            return null;
        }
    }

    function __ncSaveScrollState(channelId){
        try{
            const cid = String(parseInt(channelId, 10) || 0);
            if (!cid || cid === '0') return;
            const state = __ncCaptureScrollState();
            if (!state) return;
            localStorage.setItem(__ncScrollKey(cid), JSON.stringify(state));
        }catch(e){}
    }

    function __ncGetScrollState(channelId){
        try{
            const cid = String(parseInt(channelId, 10) || 0);
            if (!cid || cid === '0') return null;
            const raw = localStorage.getItem(__ncScrollKey(cid));
            const st = __ncSafeJsonParse(raw);
            return (st && typeof st === 'object') ? st : null;
        }catch(e){ return null; }
    }

    function __ncRestoreScrollState(channelId){
        if (!messagesContainer) return false;
        const cid = String(parseInt(channelId, 10) || 0);
        if (!cid || cid === '0') return false;

        const st = __ncGetScrollState(cid);
        if (!st) return false;

        function applyOnce(){
            try{
                __ncRestoringScroll = true;
                let applied = false;
                if (st && st.topId){
                    const el = messagesContainer.querySelector(`.msg-row[data-msg-id="${String(st.topId).replace(/"/g,'\\"')}"]`);
                    if (el){
                        const off = Number.isFinite(parseInt(st.offset,10)) ? parseInt(st.offset,10) : 0;
                        const target = Math.max(0, (el.offsetTop || 0) - off);
                        messagesContainer.scrollTop = target;
                        applied = true;
                    }
                }
                if (!applied && Number.isFinite(parseInt(st.scrollTop,10))) {
                    messagesContainer.scrollTop = Math.max(0, parseInt(st.scrollTop,10));
                    applied = true;
                }
                __ncRestoringScroll = false;
                try{ syncJumpLatestState(); }catch(e){}
                try{ scheduleJumpLatestSync(); }catch(e){}
                return applied;
            }catch(e){
                __ncRestoringScroll = false;
                return false;
            }
        }

        // Apply twice to handle late layout shifts (images/avatars).
        const ok1 = applyOnce();
        try{ requestAnimationFrame(() => { try{ applyOnce(); }catch(e){} }); }catch(e){
            try{ setTimeout(() => { try{ applyOnce(); }catch(err){} }, 60); }catch(err){}
        }
        return ok1;
    }

    function __ncScheduleScrollSave(){
        try{
            if (__ncRestoringScroll) return;
            if (!messagesContainer) return;
            if (!currentChannelId) return;
            if (__ncScrollSaveTimer) clearTimeout(__ncScrollSaveTimer);
            __ncScrollSaveTimer = setTimeout(() => {
                try{ __ncSaveScrollState(currentChannelId); }catch(e){}
            }, 220);
        }catch(e){}
    }

    function __ncSaveScrollForCurrent(){
        try{
            if (currentChannelId) __ncSaveScrollState(currentChannelId);
        }catch(e){}
    }

    // Save on refresh/close.
    try{
        window.addEventListener('beforeunload', () => {
            try{ __ncSaveScrollForCurrent(); }catch(e){}
        });
    }catch(e){}
    function getBottomGap() {
        if (!messagesContainer) return 0;
        return Math.max(0, messagesContainer.scrollHeight - messagesContainer.scrollTop - messagesContainer.clientHeight);
    }
    function isNearBottom() {
        if (!messagesContainer) return true;
        if (messagesContainer.scrollHeight <= (messagesContainer.clientHeight + 8)) return true;
        return getBottomGap() < 220;
    }
    function setJumpVisible(v) {
        if (!btnJumpLatest) return;
        btnJumpLatest.classList.toggle("is-hidden", !v);
    }
    function syncJumpLatestState() {
        try {
            if (!messagesContainer || !btnJumpLatest) return;
            const noOverflow = messagesContainer.scrollHeight <= (messagesContainer.clientHeight + 8);
            const near = isNearBottom();
            shouldAutoScroll = !!near;
            setJumpVisible(!(noOverflow || near));
        } catch (e) {}
    }
    function scheduleJumpLatestSync() {
        try {
            requestAnimationFrame(() => {
                try { syncJumpLatestState(); } catch (e) {}
                try {
                    requestAnimationFrame(() => {
                        try { syncJumpLatestState(); } catch (e) {}
                    });
                } catch (e) {}
            });
        } catch (e) {
            try { setTimeout(() => { try { syncJumpLatestState(); } catch (err) {} }, 40); } catch (err) {}
        }
    }

    // v49: The "↓ Новые" pill should never leak into other UI surfaces (settings, marketplace overlays, etc.).
    // If the user navigates away from the chat area, hide it proactively.
    try{
        document.addEventListener('click', (e) => {
            try{
                if (!btnJumpLatest) return;
                // If settings/theme preview is open, always hide.
                if (document.body.classList.contains('nc-modal-open') || document.body.classList.contains('nc-theme-preview-open')) {
                    setJumpVisible(false);
                    return;
                }
                // If the click happened outside the message scroller (navigation / other pages), hide.
                if (messagesContainer && !messagesContainer.contains(e.target) && !btnJumpLatest.contains(e.target)) {
                    setJumpVisible(false);
                }
            }catch(_e){}
        }, true);
    }catch(e){}

    // Also hide on class changes (e.g., settings modal opens without a click in some flows).
    try{
        const mo = new MutationObserver(() => {
            try{
                if (!btnJumpLatest) return;
                if (document.body.classList.contains('nc-modal-open') || document.body.classList.contains('nc-theme-preview-open')) {
                    setJumpVisible(false);
                }
            }catch(_e){}
        });
        mo.observe(document.body, { attributes:true, attributeFilter:['class'] });
    }catch(e){}

    if (messagesContainer) {
        messagesContainer.addEventListener("scroll", () => {
            try{ syncJumpLatestState(); }catch(e){}
            try{ __ncScheduleScrollSave(); }catch(e){}
        });
    }

    if (btnJumpLatest && messagesContainer) {
        btnJumpLatest.addEventListener("click", () => {
            messagesContainer.scrollTop = messagesContainer.scrollHeight;
            shouldAutoScroll = true;
            setJumpVisible(false);
            try{ scheduleJumpLatestSync(); }catch(e){}
            if (messageInput && messageInput.focus) messageInput.focus();
        });
    }

    function autoGrowTextarea(el) {
        if (!el) return;
        el.style.height = "auto";
        const h = Math.min(el.scrollHeight, 160);
        el.style.height = h + "px";
    }

    if (messageInput) {
        // textarea in 2026: grows and sends on Enter
        autoGrowTextarea(messageInput);
        messageInput.addEventListener("input", () => {
            autoGrowTextarea(messageInput);
            try {
                if (!socket || !socket.connected || !currentChannelId) return;
                const hasText = !!((messageInput.value || "").trim());
                if (!hasText) {
                    if (__ncTypingSent) {
                        socket.emit("typing", { channel_id: parseInt(currentChannelId), typing: false });
                        __ncTypingSent = false;
                    }
                    if (__ncTypingTimer) { clearTimeout(__ncTypingTimer); __ncTypingTimer = null; }
                    return;
                }
                if (!__ncTypingSent) {
                    socket.emit("typing", { channel_id: parseInt(currentChannelId), typing: true });
                    __ncTypingSent = true;
                }
                if (__ncTypingTimer) clearTimeout(__ncTypingTimer);
                __ncTypingTimer = setTimeout(() => {
                    try {
                        if (socket && socket.connected && __ncTypingSent) {
                            socket.emit("typing", { channel_id: parseInt(currentChannelId), typing: false });
                        }
                    } catch (e) {}
                    __ncTypingSent = false;
                }, 2400);
            } catch (e) {}
        });
        messageInput.addEventListener("keydown", (e) => {
            if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                if (messageForm && messageForm.requestSubmit) messageForm.requestSubmit();
                else if (messageForm) messageForm.dispatchEvent(new Event("submit", { cancelable: true }));
            }
        });
    }

