    function __ncRenderPendingItem(item){
        const li = document.createElement("li");
        li.className = "pending-item";
        li.dataset.reqId = String(item.request_id||"");
        li.dataset.direction = String(item.direction||"");
        li.dataset.userId = String(item.user_id||"");
        li.innerHTML = `
            <div class="pending-left">
                <div class="pending-avatar">${item.avatar ? `<img src="${item.avatar}" alt="">` : `<span class="avatar-fallback">${(item.username||"?").slice(0,1).toUpperCase()}</span>`}</div>
                <div class="pending-meta">
                    <div class="pending-name">@${item.username || ("#" + (item.user_id||""))}</div>
                    <div class="pending-sub">${item.direction === "incoming" ? "Входящий запрос" : "Исходящий запрос"}</div>
                </div>
            </div>
            <div class="pending-actions"></div>
        `;
        const actions = li.querySelector(".pending-actions");
        if (item.direction === "incoming") {
            actions.innerHTML = `
                <button class="btn-sm btn-accept" data-action="accept">Принять</button>
                <button class="btn-sm btn-decline" data-action="decline">Отклонить</button>
            `;
        } else {
            actions.innerHTML = `<button class="btn-sm btn-cancel" data-action="cancel">Отменить</button>`;
        }
        return li;
    }

    async function __ncLoadPendingRequests(){
        try{
            const r = await fetch("/api/friend-requests/pending");
            const data = await r.json().catch(()=>({}));
            if (!data || !data.success) return [];
            return Array.isArray(data.items) ? data.items : [];
        }catch(e){ return []; }
    }

    async function __ncRefreshPendingRequests(){
        const list = __ncEnsureFriendsPendingUI();
        if (!list) return;
        const items = await __ncLoadPendingRequests();
        list.innerHTML = "";
        items.forEach(it => list.appendChild(__ncRenderPendingItem(it)));
        __ncSetPendingBadges(items.length);
        // Also update empty state
        try{
            const empty = document.getElementById("friends-page-empty");
            if (empty) empty.classList.toggle("is-hidden", items.length>0);
        }catch(e){}
    }

    function __ncUpsertPendingFromEvent(payload, direction){
        const list = __ncEnsureFriendsPendingUI();
        if (!list || !payload || !payload.request_id) return;
        const reqId = String(payload.request_id);
        // remove existing
        try{
            const existing = list.querySelector(`[data-req-id="${reqId}"]`);
            if (existing) existing.remove();
        }catch(e){}
        const item = {
            request_id: payload.request_id,
            direction: direction,
            user_id: direction === "incoming" ? payload.from_id : payload.target_id,
            username: direction === "incoming" ? payload.from_username : payload.target_username,
            avatar: direction === "incoming" ? payload.from_avatar : payload.target_avatar
        };
        list.insertBefore(__ncRenderPendingItem(item), list.firstChild);
        // update badges
        try{ __ncSetPendingBadges(list.querySelectorAll(".pending-item").length); }catch(e){}
    }

