    function __ncSyncFriendsPageFromSidebar(){
        try{
            if (!friendsView) return;
            const mainList = document.getElementById("friends-page-list");
            const dmList = document.querySelector("#pane-friends .friend-list");
            if (!mainList || !dmList) return;

            const dmItems = Array.from(dmList.querySelectorAll('.dm-entry[data-user-id], .friend-item.dm-entry[data-user-id]'));
            if (!dmItems.length) return;

            try{
                const sig = dmItems.map((src) => [
                    String(src.dataset.userId || '').trim(),
                    String(src.dataset.username || '').trim(),
                    String(src.dataset.online || '0').trim(),
                    String(src.dataset.status || '').trim(),
                    src.classList.contains('active') ? '1' : '0'
                ].join('|')).join(';');
                const now = Date.now();
                if (sig && sig === __ncFriendsLastSidebarSig && (now - __ncFriendsLastSidebarSyncAt) < (now < (window.__ncFriendsBootUntil || 0) ? 1200 : 180)) return;
                __ncFriendsLastSidebarSig = sig;
                __ncFriendsLastSidebarSyncAt = now;
            }catch(_sigErr){}

            const esc = (s) => String(s||'').replace(/[&<>"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',"'":'&#39;'}[c] || c));
            const seen = new Set();

            dmItems.forEach((src) => {
                const uid = String(src.dataset.userId || '').trim();
                if (!uid) return;
                seen.add(uid);

                const name = String(src.dataset.username || (src.querySelector('.friend-name')?.textContent || '') || '').trim();
                const avatar = String(src.dataset.avatarUrl || '').trim();
                const online = String(src.dataset.online || '0') === '1';
                const status = String(src.dataset.status || (online ? 'в сети' : 'не в сети') || '').trim();
                const createdAt = String(src.dataset.createdAt || '').trim();
                const lastSeen = String(src.dataset.lastSeen || '').trim();

                let li = mainList.querySelector(`.friends-page-item[data-user-id="${uid}"]`);
                if (!li) {
                    li = document.createElement('li');
                    li.className = 'friend-item friends-page-item';
                    li.dataset.userId = uid;
                    li.dataset.username = name;
                    li.dataset.avatarUrl = avatar;
                    li.dataset.status = status;
                    li.dataset.online = online ? '1' : '0';
                    if (createdAt) li.dataset.createdAt = createdAt;
                    if (lastSeen) li.dataset.lastSeen = lastSeen;
                    li.innerHTML = `
                        <div class="avatar-circle ${avatar ? 'has-image' : ''}" ${avatar ? `style="background-image:url('${avatar}');"` : ''}>
                            <span class="avatar-initial">${(!avatar ? esc((name || '?').slice(0,1).toUpperCase()) : '')}</span>
                            <span class="presence-dot ${online ? 'is-online' : 'is-offline'}" aria-hidden="true"></span>
                        </div>
                        <div class="friend-meta">
                            <div class="friend-row">
                                <span class="friend-name">${esc(name)}</span>
                                <span class="unread-badge is-hidden" aria-hidden="true"></span>
                            </div>
                            <div class="friend-row sub">
                                <span class="friend-sub">${esc(status || (online ? 'в сети' : 'не в сети'))}</span>
                                <span class="friend-preview"></span>
                            </div>
                        </div>
                    `;
                    mainList.appendChild(li);
                    try{ attachFriendItemHandlers(li); }catch(e){}
                }

                try{
                    li.dataset.username = name;
                    li.dataset.avatarUrl = avatar;
                    li.dataset.status = status;
                    li.dataset.online = online ? '1' : '0';
                    if (createdAt) li.dataset.createdAt = createdAt;
                    if (lastSeen) li.dataset.lastSeen = lastSeen;

                    const nameEl = li.querySelector('.friend-name');
                    if (nameEl && nameEl.childNodes && nameEl.childNodes.length) {
                        // Preserve cosmetic tag spans if any, but replace the base text node.
                        const textNode = Array.from(nameEl.childNodes).find(n => n.nodeType === Node.TEXT_NODE);
                        if (textNode) textNode.nodeValue = name;
                        else nameEl.insertBefore(document.createTextNode(name), nameEl.firstChild || null);
                    } else if (nameEl) {
                        nameEl.textContent = name;
                    }
                    const subEl = li.querySelector('.friend-sub');
                    if (subEl) subEl.textContent = status || (online ? 'в сети' : 'не в сети');
                    const avatarEl = li.querySelector('.avatar-circle');
                    if (avatarEl) {
                        avatarEl.classList.toggle('has-image', !!avatar);
                        avatarEl.style.backgroundImage = avatar ? `url('${avatar}')` : '';
                        const initEl = avatarEl.querySelector('.avatar-initial');
                        if (initEl) initEl.textContent = avatar ? '' : ((name || '?').slice(0,1).toUpperCase());
                        const dot = avatarEl.querySelector('.presence-dot');
                        if (dot) { dot.classList.toggle('is-online', online); dot.classList.toggle('is-offline', !online); }
                    }
                }catch(e){}
            });

            // If template rendered stale rows, remove entries no longer present in DM sidebar.
            try{
                Array.from(mainList.querySelectorAll('.friends-page-item[data-user-id]')).forEach((li) => {
                    const uid = String(li.dataset.userId || '').trim();
                    if (uid && !seen.has(uid)) li.remove();
                });
            }catch(e){}
            try{ __ncRefreshFriendAdminPills(); }catch(e){}
        }catch(e){}
    }


    function __ncSetChannelTitle(text){
        try{
            const el = document.getElementById("current-channel-name");
            if (el) el.textContent = text;
        }catch(e){}
    }

    function __ncFriendsApplyTab(tab){
        try{
            if (!friendsView) return;
            const q = (friendsPageSearch && friendsPageSearch.value) ? String(friendsPageSearch.value).toLowerCase().trim() : "";
            const items = friendsPageItems();

            // tabs ui
            try{
                friendsTabs.forEach(b => b.classList.toggle("is-active", String(b.dataset.friendsTab) === String(tab)));
            }catch(e){}

            // pending placeholder
// pending list
            try{
                const pendingList = document.getElementById("friends-pending-list");
                if (pendingList) pendingList.classList.toggle("is-hidden", String(tab) !== "pending");
                const mainList = document.getElementById("friends-page-list");
                if (mainList) mainList.classList.toggle("is-hidden", String(tab) === "pending");
                if (String(tab) === "pending") { try{ __ncRefreshPendingRequests(); }catch(e){} }
            }catch(e){}

            if (friendsPendingPlaceholder) friendsPendingPlaceholder.classList.toggle("is-hidden", String(tab) !== "pending");

            let visible = 0;
            items.forEach(li => {
                const online = parseInt(li.dataset.online || "0", 10) === 1;
                const name = (li.dataset.username || "").toLowerCase();
                let ok = true;

                if (tab === "online") ok = online;
                else if (tab === "all") ok = true;
                else if (tab === "pending") ok = false; // pending is rendered in a separate list

                if (ok && q) ok = name.includes(q);

                li.style.display = ok ? "" : "none";
                if (ok) visible += 1;
            });

            if (friendsPageCount) {
                const label = (tab === "online") ? "В сети" : (tab === "all" ? "Все" : "Ожидание");
                friendsPageCount.textContent = (tab === "pending") ? "" : `${label} — ${visible}`;
            }

            if (friendsPageEmpty) friendsPageEmpty.classList.toggle("is-hidden", (tab === "pending") || (visible !== 0));
        }catch(e){}
    }

    function __ncOpenFriendsPage(){
        try{
            const chatMain = document.querySelector(".chat-main");
            if (chatMain) chatMain.classList.add("friends-mode");
            if (friendsView) friendsView.classList.remove("is-hidden");
            // Подтягиваем список друзей из DM-колонки, чтобы страница не была пустой до перезагрузки.
            try{ __ncFriendsScheduleSidebarSync(Date.now() < (window.__ncFriendsBootUntil || 0) ? 260 : 80); }catch(e){}
            // Старт страницы друзей стабилизируем и не дергаем пересборку много раз подряд.
            try{
                const __nc_delayedFriendsSync = () => { try{ __ncFriendsScheduleSidebarSync(60); }catch(_e){} };
                if (Date.now() >= (window.__ncFriendsBootUntil || 0)) {
                    if (typeof requestAnimationFrame === 'function') requestAnimationFrame(__nc_delayedFriendsSync);
                    setTimeout(__nc_delayedFriendsSync, 120);
                }
            }catch(e){}
            // When leaving the message thread view, ensure the "Новые" jump button never leaks across pages.
            try{
                const jl = document.getElementById('btn-jump-latest');
                if (jl) jl.classList.add('is-hidden');
            }catch(e){}
            __ncSetChannelTitle("Друзья");
            // hide call UI/actions while in friends page
            try{
                const callBar = document.getElementById("call-bar");
                if (callBar) callBar.style.display = "none";
            }catch(e){}
            try{
                const chatHeaderActions = document.getElementById("chat-header-actions");
                if (chatHeaderActions) chatHeaderActions.classList.add("is-hidden");
            }catch(e){}
            try{ __ncSetLastView({ kind: "friends" }); }catch(e){}
            // Friends search should start empty (no "liman" or other stale value).
            try{ if (friendsPageSearch) friendsPageSearch.value = ""; }catch(e){}
            const activeTabBtn = friendsView ? friendsView.querySelector('.friends-tab.is-active[data-friends-tab]') : null;
            let activeTab = activeTabBtn ? String(activeTabBtn.dataset.friendsTab || 'online') : 'online';
            __ncFriendsApplyTab(activeTab);
        }catch(e){}
    }

    function __ncCloseFriendsPage(){
        try{
            const chatMain = document.querySelector(".chat-main");
            if (chatMain) chatMain.classList.remove("friends-mode");
            if (friendsView) friendsView.classList.add("is-hidden");
            // Restore "Новые" jump button (it self-manages visibility based on unread state).
            try{
                const jl = document.getElementById('btn-jump-latest');
                if (jl) jl.classList.remove('is-hidden');
            }catch(e){}
            // restore call bar visibility (it self-manages state)
            try{
                const callBar = document.getElementById("call-bar");
                if (callBar) callBar.style.display = "";
            }catch(e){}
        }catch(e){}
    }

