    // ===== FIX221: Guild pages (Browse channels / Members) =====
    function __ncSetGuildPage(mode){
        // mode: null | 'browse' | 'members'
        try{ __ncGuildPage = mode || null; }catch(e){}

        const chatHeader = document.querySelector('.chat-header');
        const chatMessages = document.getElementById('chat-messages');
        const chatInput = document.querySelector('footer.chat-input');
        const friendsView = document.getElementById('friends-view');
        const voiceView = document.getElementById('voice-view');

        const isPage = !!mode;

        try{ if (guildBrowseView) { guildBrowseView.classList.toggle('is-hidden', mode !== 'browse'); guildBrowseView.setAttribute('aria-hidden', mode === 'browse' ? 'false' : 'true'); } }catch(e){}
        try{ if (guildMembersView){ guildMembersView.classList.toggle('is-hidden', mode !== 'members'); guildMembersView.setAttribute('aria-hidden', mode === 'members' ? 'false' : 'true'); } }catch(e){}

        // hide regular chat UI while a guild page is open
        try{ if (chatHeader) chatHeader.classList.toggle('is-hidden', isPage); }catch(e){}
        try{ if (chatMessages) chatMessages.classList.toggle('is-hidden', isPage); }catch(e){}
        try{ if (chatInput) chatInput.classList.toggle('is-hidden', isPage); }catch(e){}

        // guild pages should not show friends / voice dedicated screens
        try{ if (friendsView) friendsView.classList.toggle('is-hidden', isPage); }catch(e){}
        try{ if (voiceView) voiceView.classList.toggle('is-hidden', isPage); }catch(e){}
        try{ if (isPage) setVoiceViewActive(false); }catch(e){}

        // prevent friends-mode when switching pages
        try{ if (isPage){ const cm = document.querySelector('.chat-main'); if (cm) cm.classList.remove('friends-mode'); } }catch(e){}
    }
