    function __ncReadJsonLS(key, fallback){
        try{ const raw = localStorage.getItem(key); if (!raw) return fallback; const v = JSON.parse(raw); return v == null ? fallback : v; }catch(e){ return fallback; }
    }
    function __ncWriteJsonLS(key, value){
        try{ localStorage.setItem(key, JSON.stringify(value)); }catch(e){}
    }
    function __ncGetBrowseState(gid){
        const g = String(gid||'0');
        const cats = new Set(__ncReadJsonLS(`nc_browse_hide_cats_${g}`, []));
        const chs  = new Set(__ncReadJsonLS(`nc_browse_hide_ch_${g}`, []));
        return { cats, chs };
    }
    function __ncSaveBrowseState(gid, st){
        const g = String(gid||'0');
        __ncWriteJsonLS(`nc_browse_hide_cats_${g}`, Array.from(st.cats||[]));
        __ncWriteJsonLS(`nc_browse_hide_ch_${g}`, Array.from(st.chs||[]));
    }

    function __ncApplyBrowseVisibility(gid){
        try{
            const st = __ncGetBrowseState(gid);
            // categories
            document.querySelectorAll('#guild-cats-list .guild-cat').forEach(cat => {
                const id = String(cat.dataset.catId||'');
                cat.classList.toggle('nc-browse-hidden', st.cats.has(id));
            });
            // channels
            document.querySelectorAll('#guild-cats-list .guild-channel-item').forEach(li => {
                const id = String(li.dataset.channelId||'');
                li.classList.toggle('nc-browse-hidden', st.chs.has(id));
            });
        }catch(e){}
    }

    function __ncTimeAgo(iso){
        try{
            const d = iso ? new Date(String(iso)) : null;
            if (!d || isNaN(d.getTime())) return '—';
            const diff = Date.now() - d.getTime();
            const sec = Math.floor(diff/1000);
            if (sec < 60) return 'только что';
            const min = Math.floor(sec/60);
            if (min < 60) return `${min} мин назад`;
            const hr = Math.floor(min/60);
            if (hr < 24) return `${hr} ч назад`;
            const day = Math.floor(hr/24);
            if (day < 30) return `${day} дн назад`;
            const mon = Math.floor(day/30);
            if (mon < 12) return `${mon} мес назад`;
            const yr = Math.floor(mon/12);
            return `${yr} г назад`;
        }catch(e){ return '—'; }
    }

    async function __ncEnsureGuildChannels(gid){
        const g = String(gid||'0');
        if (__ncGuildChannelsCache[g]) return __ncGuildChannelsCache[g];
        try{
            const resp = await fetch(`/api/guilds/${g}/channels`);
            const data = await resp.json();
            if (resp.ok && data && !data.error){
                __ncGuildChannelsCache[g] = data;
                return data;
            }
        }catch(e){}
        return null;
    }

    function __ncRenderGuildBrowse(gid, data, q){
        if (!guildBrowseBody) return;
        const st = __ncGetBrowseState(gid);
        const query = String(q||'').trim().toLowerCase();
        const cats = (data && Array.isArray(data.categories)) ? data.categories : [];
        const unc = (data && Array.isArray(data.uncategorized)) ? data.uncategorized : [];

        const blocks = [];

        function mkRow(ch){
            const id = String(ch.id);
            const name = String(ch.name||'');
            const type = String(ch.type||'text').toLowerCase();
            const icon = (type==='voice')
              ? `<svg class="i" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 14a3 3 0 0 0 3-3V5a3 3 0 0 0-6 0v6a3 3 0 0 0 3 3z" fill="currentColor"></path><path d="M19 11a1 1 0 0 0-2 0 5 5 0 0 1-10 0 1 1 0 0 0-2 0 7 7 0 0 0 6 6.92V20H9a1 1 0 0 0 0 2h6a1 1 0 0 0 0-2h-2v-2.08A7 7 0 0 0 19 11z" fill="currentColor"></path></svg>`
              : `<svg class="i" viewBox="0 0 24 24" aria-hidden="true"><path d="M10 3L8 21M16 3l-2 18M4 8h18M3 16h18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"></path></svg>`;
            const on = !st.chs.has(id);
            return `
              <div class="gb-row" data-ch-id="${id}">
                <div class="gb-row-left">
                  <span class="guild-channel-icon" aria-hidden="true">${icon}</span>
                  <div class="gb-row-text" style="min-width:0">
                    <div class="gb-row-name">${escapeHtml(name)}</div>
                    <div class="gb-row-meta">${type==='voice' ? 'Голосовой канал' : 'Текстовый канал'}</div>
                  </div>
                </div>
                <div class="gb-check ${on ? 'is-on' : ''}" title="Показывать в списке">
                  <svg class="i" viewBox="0 0 24 24" aria-hidden="true"><path d="M20 6L9 17l-5-5" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"/></svg>
                </div>
              </div>
            `;
        }

        function addCat(title, catId, channels){
            const cid = String(catId||'0');
            const isHidden = st.cats.has(cid);
            const catChannels = (channels||[]).filter(ch => {
                if (!query) return true;
                return String(ch.name||'').toLowerCase().includes(query);
            });
            if (!catChannels.length) return;
            blocks.push(`
              <div class="gb-cat" data-cat-id="${cid}">
                <div class="gb-cat-head">
                  <div class="gb-cat-title">${escapeHtml(title||'')}</div>
                  <div class="gb-cat-actions">
                    <span style="opacity:.75;font-weight:800;font-size:12px">Подписаться на категорию</span>
                    <div class="nc-switch ${isHidden ? '' : 'is-on'}" role="switch" aria-checked="${isHidden ? 'false' : 'true'}" tabindex="0" data-cat-switch="${cid}"></div>
                  </div>
                </div>
                <div class="gb-list">
                  ${catChannels.map(mkRow).join('')}
                </div>
              </div>
            `);
        }

        cats.forEach(c => addCat(String(c.name||'Категория'), String(c.id||''), c.channels||[]));
        if (unc && unc.length) addCat('Без категории', '0', unc);

        guildBrowseBody.innerHTML = blocks.join('') || `<div style="opacity:.75;padding:14px">Каналы не найдены</div>`;

        // interactions
        try{
            guildBrowseBody.querySelectorAll('[data-cat-switch]').forEach(sw => {
                sw.addEventListener('click', () => {
                    const cid = String(sw.getAttribute('data-cat-switch')||'');
                    const hidden = st.cats.has(cid);
                    if (hidden) st.cats.delete(cid); else st.cats.add(cid);
                    __ncSaveBrowseState(gid, st);
                    __ncApplyBrowseVisibility(gid);
                    __ncRenderGuildBrowse(gid, data, guildBrowseSearch ? guildBrowseSearch.value : '');
                });
            });
            guildBrowseBody.querySelectorAll('[data-ch-id]').forEach(row => {
                row.addEventListener('click', (ev) => {
                    // click on check toggles visibility; click on row name opens channel
                    const chId = String(row.getAttribute('data-ch-id')||'');
                    const clickedCheck = !!(ev && ev.target && ev.target.closest && ev.target.closest('.gb-check'));
                    if (clickedCheck){
                        const hidden = st.chs.has(chId);
                        if (hidden) st.chs.delete(chId); else st.chs.add(chId);
                        __ncSaveBrowseState(gid, st);
                        __ncApplyBrowseVisibility(gid);
                        __ncRenderGuildBrowse(gid, data, guildBrowseSearch ? guildBrowseSearch.value : '');
                        return;
                    }
                    // open channel
                    try{
                        const li = document.querySelector(`.guild-channel-item[data-channel-id="${CSS.escape(chId)}"]`);
                        const rowEl = li ? (li.querySelector('.guild-channel-row') || li) : null;
                        if (rowEl) rowEl.click();
                    }catch(e){}
                });
            });
        }catch(e){}
    }

    async function __ncOpenGuildBrowse(){
        // Иногда currentGuildId может быть сброшен (например, после переходов через Friends/Voice UI).
        // Восстанавливаем его по активному серверу в рейле.
        try{
            if (!currentGuildId) {
                const act = document.querySelector('#server-list .dc-server.is-active, .channel-item.dc-server.is-active');
                const gid = act ? parseInt(String(act.dataset.channelId||'0'), 10) : 0;
                if (gid) {
                    currentGuildId = gid;
                    currentGuildName = (act.dataset.channelName || currentGuildName || '').trim();
                }
            }
        }catch(e){}

        if (!currentGuildId){ try{ ncToast('Сначала выберите сервер'); }catch(e){}; return; }

        // Если пользователь был на странице "Друзья", гарантированно закрываем её.
        try{ setSidebarMode('channels'); }catch(e){}
        try{ const cm = document.querySelector('.chat-main'); if (cm) cm.classList.remove('friends-mode'); }catch(e){}
        try{ const fv = document.getElementById('friends-view'); if (fv) fv.classList.add('is-hidden'); }catch(e){}
        try{ if (typeof __ncCloseFriendsPage === 'function') __ncCloseFriendsPage(); }catch(e){}
        __ncSetGuildPage('browse');
        try{ if (guildBrowseCreateBtn) guildBrowseCreateBtn.style.display = currentGuildCanManage ? '' : 'none'; }catch(e){}
        const data = await __ncEnsureGuildChannels(currentGuildId);
        if (data){
            __ncApplyBrowseVisibility(currentGuildId);
            __ncRenderGuildBrowse(currentGuildId, data, guildBrowseSearch ? guildBrowseSearch.value : '');
        }
    }

    async function __ncOpenGuildMembers(){
        // Иногда currentGuildId может быть сброшен (например, после переходов через Friends/Voice UI).
        // Восстанавливаем его по активному серверу в рейле.
        try{
            if (!currentGuildId) {
                const act = document.querySelector('#server-list .dc-server.is-active, .channel-item.dc-server.is-active');
                const gid = act ? parseInt(String(act.dataset.channelId||'0'), 10) : 0;
                if (gid) {
                    currentGuildId = gid;
                    currentGuildName = (act.dataset.channelName || currentGuildName || '').trim();
                }
            }
        }catch(e){}

        if (!currentGuildId){ try{ ncToast('Сначала выберите сервер'); }catch(e){}; return; }

        // Если пользователь был на странице "Друзья", гарантированно закрываем её.
        try{ setSidebarMode('channels'); }catch(e){}
        try{ const cm = document.querySelector('.chat-main'); if (cm) cm.classList.remove('friends-mode'); }catch(e){}
        try{ const fv = document.getElementById('friends-view'); if (fv) fv.classList.add('is-hidden'); }catch(e){}
        try{ if (typeof __ncCloseFriendsPage === 'function') __ncCloseFriendsPage(); }catch(e){}
        __ncSetGuildPage('members');

        const gid = String(currentGuildId);
        const q = String((guildMembersSearch && guildMembersSearch.value) || '').trim().toLowerCase();

        async function fetchMembers(){
            try{
                const resp = await fetch(`/api/guilds/${gid}/members`);
                const data = await resp.json();
                if (resp.ok && data && !data.error){
                    __ncGuildMembersCache[gid] = { members: (data.members||[]), ts: Date.now() };
                    return data.members || [];
                }
            }catch(e){}
            return [];
        }

        let members = (__ncGuildMembersCache[gid] && Array.isArray(__ncGuildMembersCache[gid].members)) ? __ncGuildMembersCache[gid].members : null;
        if (!members) members = await fetchMembers();

        function render(){
            if (!guildMembersBody) return;
            const query = String((guildMembersSearch && guildMembersSearch.value) || '').trim().toLowerCase();
            let rows = (members || []).filter(m => {
                if (!query) return true;
                return String(m.username||'').toLowerCase().includes(query);
            });

            // sort: toggles by username asc/desc
            try{
                const s = __ncReadJsonLS(`nc_members_sort_${gid}`, { by: 'username', dir: 'asc' });
                if (s && s.by === 'username'){
                    rows.sort((a,b) => {
                        const aa = String(a.username||'').toLowerCase();
                        const bb = String(b.username||'').toLowerCase();
                        const r = aa.localeCompare(bb);
                        return (s.dir === 'desc') ? -r : r;
                    });
                }
            }catch(e){}

            const html = `
              <div class="gm-wrap">
                <div class="gm-head">Недавние участники</div>
                <table class="gm-table">
                  <thead>
                    <tr>
                      <th>Имя</th>
                      <th>В числе участников с</th>
                      <th>В Neon с</th>
                      <th>Роль</th>
                      <th style="text-align:right">Действия</th>
                    </tr>
                  </thead>
                  <tbody>
                    ${rows.map(m => {
                        const av = String(m.avatar_url||'');
                        const joined = m.joined_at || m.joinedAt || '';
                        const created = m.created_at || m.createdAt || '';
                        const role = String(m.role||'участник');
                        return `
                          <tr data-user-id="${String(m.id)}">
                            <td>
                              <div class="gm-user" data-user-id="${String(m.id)}">
                                ${av ? `<img class="gm-av" alt="" src="${escapeHtml(av)}">` : `<span class="gm-av"></span>`}
                                <div style="min-width:0">
                                  <div class="gm-name">${escapeHtml(String(m.username||''))}</div>
                                  <div class="gm-sub">${(m.is_online ? 'в сети' : 'не в сети')}</div>
                                </div>
                              </div>
                            </td>
                            <td>${__ncTimeAgo(joined)}</td>
                            <td>${__ncTimeAgo(created)}</td>
                            <td><span class="gm-role">${escapeHtml(role)}</span></td>
                            <td>
                              <div class="gm-actions">
                                <button class="icon-btn" type="button" title="Профиль" data-profile="${String(m.id)}"><svg class="i" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 12a4 4 0 1 0-0.01 0" fill="none" stroke="currentColor" stroke-width="2"/><path d="M4 21a8 8 0 0 1 16 0" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg></button>
                                <button class="icon-btn" type="button" title="Сообщение" data-dm="${String(m.id)}"><svg class="i" viewBox="0 0 24 24" aria-hidden="true"><path d="M21 15a4 4 0 0 1-4 4H8l-5 3V7a4 4 0 0 1 4-4h10a4 4 0 0 1 4 4v8z" fill="none" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/></svg></button>
                              </div>
                            </td>
                          </tr>
                        `;
                    }).join('')}
                  </tbody>
                </table>
              </div>
            `;
            guildMembersBody.innerHTML = html;

            // action hooks
            try{
                guildMembersBody.querySelectorAll('[data-profile]').forEach(b => {
                    b.addEventListener('click', async (ev) => {
                        try{ ev.preventDefault(); ev.stopPropagation(); }catch(e){}
                        const uid = parseInt(String(b.getAttribute('data-profile')||'0'),10);
                        if (!uid) return;
                        try{ window.__ncOpenUserMiniProfile && window.__ncOpenUserMiniProfile(uid); }catch(e){}
                    });
                });
                guildMembersBody.querySelectorAll('[data-dm]').forEach(b => {
                    b.addEventListener('click', async (ev) => {
                        try{ ev.preventDefault(); ev.stopPropagation(); }catch(e){}
                        const uid = parseInt(String(b.getAttribute('data-dm')||'0'),10);
                        if (!uid) return;
                        try{ await openDm(uid, null); }catch(e){}
                    });
                });
            }catch(e){}
        }

        render();
    }

