    if (svsInviteEditBtn){
        svsInviteEditBtn.addEventListener('click', async () => {
            try{
                if (!_svsIsAdmin()) { ncToast('Нет прав'); return; }
                if (!svsInviteSettingsModal) { ncToast('Нет окна настроек'); return; }
                // prefill selects from current data
                try{
                    const expIso = (__svsServerData && __svsServerData.invite_expires_at) ? String(__svsServerData.invite_expires_at) : '';
                    if (svsInviteExpiresSel){
                        let best = '604800'; // default 7d
                        if (!expIso) best = '0';
                        else {
                            const dt = new Date(expIso);
                            if (!isNaN(dt.getTime())){
                                const sec = Math.max(0, Math.round((dt.getTime()-Date.now())/1000));
                                const opts = Array.from(svsInviteExpiresSel.options || []).map(o => String(o.value));
                                let closest = opts[0] || '0';
                                let cd = 1e18;
                                opts.forEach(v => {
                                    const n = parseInt(v,10);
                                    const d = Math.abs(n - sec);
                                    if (d < cd){ cd = d; closest = String(v); }
                                });
                                best = closest;
                            }
                        }
                        svsInviteExpiresSel.value = best;
                    }
                    if (svsInviteMaxUsesSel){
                        const mu = (__svsServerData && (__svsServerData.invite_max_uses!==undefined)) ? parseInt(String(__svsServerData.invite_max_uses),10) : 0;
                        svsInviteMaxUsesSel.value = String(mu || 0);
                    }
                }catch(e){}

                try{ await _svsLoadInviteChannels(); }catch(e){}
                try{ if (svsInviteTemporaryChk) svsInviteTemporaryChk.checked = !!(__svsServerData && __svsServerData.invite_temporary); }catch(e){}

                svsInviteSettingsModal.classList.add('active');
                svsInviteSettingsModal.setAttribute('aria-hidden','false');
                if (svsInviteSettingsNote) svsInviteSettingsNote.textContent = '';
            }catch(e){}
        });
    }

