                    // Calls header elements may not carry data-user-id. Force it from current DM target.
                    try{
                        const uid0 = parseInt(el.dataset.userId || el.dataset.userid || el.dataset.uid || '0', 10) || 0;
                        if (!uid0 && (peerConnection || groupCallActive)) {
                            const dmUid = parseInt((currentCallTargetId || currentDmUserId || 0), 10) || 0;
                            if (dmUid) {
                                try{ el.dataset.userId = String(dmUid); }catch(e){}
                                try{ el.dataset.uid = String(dmUid); }catch(e){}
                            }
                        }
                    }catch(e){}

                    ev.preventDefault();
                    try{ ev.stopPropagation(); }catch(e){}
