    // DM (fix107): ensure 1:1 call voice is always full-duplex, even on browsers that
    // occasionally generate SDP with audio=sendonly/recvonly because replaceTrack() is not awaited.
    function __ncDmFixSdpForceSendRecvFirstAudio(sdp){
        try{
            if (!sdp) return sdp;
            sdp = String(sdp);
            const NL = (sdp.indexOf('\r\n') >= 0) ? '\r\n' : '\n';
            let start = sdp.indexOf(NL + 'm=audio');
            if (start >= 0) start += NL.length;
            else if (sdp.startsWith('m=audio')) start = 0;
            else return sdp;

            const next = sdp.indexOf(NL + 'm=', start);
            const end = (next >= 0) ? next : sdp.length;

            const head = sdp.slice(0, start);
            let sect = sdp.slice(start, end);
            const tail = sdp.slice(end);

            const lines = sect.split(NL);
            if (!lines.length) return sdp;

            let dirIdx = -1;
            for (let i = 0; i < lines.length; i++){
                const ln = (lines[i] || '').trim();
                if (ln === 'a=sendrecv' || ln === 'a=sendonly' || ln === 'a=recvonly' || ln === 'a=inactive'){
                    dirIdx = i;
                    break;
                }
                if (ln.startsWith('m=') && i > 0) break;
            }

            if (dirIdx >= 0){
                lines[dirIdx] = 'a=sendrecv';
            } else {
                // Insert right after the m=audio line.
                lines.splice(1, 0, 'a=sendrecv');
            }

            sect = lines.join(NL);
            return head + sect + tail;
        }catch(e){
            return sdp;
        }
    }

    function __ncDmFixDescSendRecvFirstAudio(desc){
        try{
            if (!desc) return desc;
            const type = (desc.type != null) ? desc.type : (desc && desc['type']);
            const sdp0 = (desc.sdp != null) ? desc.sdp : (desc && desc['sdp']);
            if (!type || !sdp0) return desc;
            const sdp = __ncDmFixSdpForceSendRecvFirstAudio(sdp0);
            // Keep it as a plain RTCSessionDescriptionInit (works in all modern browsers).
            return { type: type, sdp: sdp };
        }catch(e){
            return desc;
        }
    }

    async function __ncDmEnsureVoiceBound(pc){
        try{
            if (!pc) return;
            try{ __ncEnsureDmMediaSlots(pc); }catch(e){}

            // Prefer RAW mic track for sending (more reliable than the WebAudio pipeline at answer-time).
            let at = (localRawStream && localRawStream.getAudioTracks) ? (localRawStream.getAudioTracks()[0] || null) : null;
            if (!at || at.readyState === 'ended') at = (localStream && localStream.getAudioTracks) ? (localStream.getAudioTracks()[0] || null) : null;
            if (at) { try{ at.enabled = true; }catch(e){} }

            // Force sendrecv on the dedicated DM voice transceiver.
            try{ if (pc.__ncDmTxVoiceA) pc.__ncDmTxVoiceA.direction = 'sendrecv'; }catch(e){}

            // Await replaceTrack so createOffer/createAnswer sees a live sender (prevents audio=recvonly).
            try{
                const sender = (pc.__ncDmTxVoiceA && pc.__ncDmTxVoiceA.sender) ? pc.__ncDmTxVoiceA.sender : null;
                if (sender && typeof sender.replaceTrack === 'function') {
                    await sender.replaceTrack(at);
                    return;
                }
            }catch(e){}

            // Fallback: find any audio sender and bind.
            try{
                const s = (pc.getSenders && pc.getSenders().find(x => x && x.track && x.track.kind === 'audio')) || null;
                if (s && typeof s.replaceTrack === 'function') await s.replaceTrack(at);
            }catch(e){}
        }catch(e){}
    }
    try{ window.__ncDmEnsureVoiceBound = __ncDmEnsureVoiceBound; }catch(e){}



// Safe video autoplay helper (prevents "black screen" after srcObject attach)
    // - uses loadedmetadata/canplay and a few retries
    function _ncSafePlayVideo(el, tries = 4){
        try{
            if (!el) return;
            let left = Math.max(1, parseInt(tries, 10) || 4);

            const tryPlay = () => {
                try{
                    const p = el.play();
                    if (p && typeof p.catch === 'function') {
                        p.catch(() => {
                            left -= 1;
                            if (left > 0) setTimeout(tryPlay, 220);
                        });
                    }
                }catch(e){
                    left -= 1;
                    if (left > 0) setTimeout(tryPlay, 220);
                }
            };

            // Immediate attempt (useful when called from user gesture)
            tryPlay();

            // Metadata/canplay attempts (useful when attach happens before the element is ready)
            const oncePlay = () => { tryPlay(); };
            el.addEventListener('loadedmetadata', oncePlay, { once: true });
            el.addEventListener('canplay', oncePlay, { once: true });
        }catch(e){}
    }

