    // Ensure the incoming-call modal is ALWAYS visible when activated.
    // In some builds the modal exists in DOM but doesn't render due to stacking contexts
    // or because older CSS had hard overrides. This helper forces it on top.
    function showIncomingCallModal(data){
        try{
            const mi = document.getElementById('modal-incoming-call');
            if (!mi) return false;
            // Ensure buttons are enabled for a new incoming call.
            try{
                const a = document.getElementById('btn-accept-call');
                const r = document.getElementById('btn-reject-call');
                if (a) a.disabled = false;
                if (r) r.disabled = false;
            }catch(e){}
            const userEl = document.getElementById('incoming-call-user');
            if (userEl) userEl.textContent = (data && (data.from_name || data.username || data.from)) ? String(data.from_name || data.username || data.from) : 'Пользователь';
            try{
                const nm = (userEl && userEl.textContent) ? String(userEl.textContent) : '';
                const fb = document.getElementById('incoming-call-avatar-fallback');
                if (fb) fb.textContent = (nm.trim()[0] || '?').toUpperCase();
            }catch(e){}
            mi.classList.add('active');
            mi.classList.remove('is-hidden');
            mi.removeAttribute('hidden');
            mi.setAttribute('aria-hidden','false');
            // force top-most stacking
            mi.style.display = 'flex';
            mi.style.pointerEvents = 'auto';
            mi.style.zIndex = '999999';
            // ensure it is the last element in body (top of stacking order)
            try{ document.body.appendChild(mi); }catch(e){}
            return true;
        }catch(e){
            return false;
        }
    }

    function hideIncomingCallModal(){
        try{
            const mi = document.getElementById('modal-incoming-call');
            if (!mi) return;
            // Strong hide: some builds have CSS that keeps the backdrop visible.
            // Always force it off so it cannot block clicks.
            mi.classList.remove('active');
            mi.classList.add('is-hidden');
            mi.setAttribute('aria-hidden','true');
            try{ mi.setAttribute('hidden',''); }catch(_e){}
            mi.style.display = 'none';
            mi.style.pointerEvents = 'none';
            mi.style.zIndex = '';
        }catch(e){}
    }

