    function _gcModeLabel(online, modeRaw){
        const mode = ((modeRaw || "") + "").toLowerCase().trim();
        if (!online) return (mode === "invisible") ? "скрытность" : "не в сети";
        if (mode === "away") return "нет на месте";
        if (mode === "dnd") return "не беспокоить";
        if (mode === "invisible") return "скрытность";
        return "в сети";
    }

    function _gcGetLis(){
        if (!modalGroupCall) return [];
        return Array.from(modalGroupCall.querySelectorAll(".group-call-friend-item"));
    }

    function _gcCollectSelected(){
        if (!modalGroupCall) return [];
        const checked = modalGroupCall.querySelectorAll(".group-call-friend-checkbox:checked");
        const ids = [];
        checked.forEach(cb => {
            const val = parseInt(cb.value, 10);
            if (val && (!currentUserId || val !== currentUserId)) ids.push(val);
        });
        return ids;
    }

    function _gcApplyFilter(q){
        const query = (q || "").toLowerCase().trim();
        _gcGetLis().forEach(li => {
            const name = (li.dataset.username || "").toLowerCase();
            const show = (!query) || name.includes(query);
            li.style.display = show ? "" : "none";
        });
    }

    function _gcRenderSelected(){
        if (!modalGroupCall) return;

        const ids = _gcCollectSelected();
        const count = ids.length;

        if (groupCallCount) groupCallCount.textContent = String(count);

        if (btnStartGroupCallSelected) {
            btnStartGroupCallSelected.disabled = (count === 0);
        }

        if (groupCallSelected) {
            groupCallSelected.innerHTML = "";
            if (count === 0) {
                const empty = document.createElement("div");
                empty.className = "modal-hint";
                empty.textContent = "Никто не выбран.";
                groupCallSelected.appendChild(empty);
            } else {
                ids.forEach(id => {
                    const li = modalGroupCall.querySelector('.group-call-friend-item[data-user-id="' + id + '"]');
                    const nm = li ? (li.dataset.username || ("#" + id)) : ("#" + id);

                    const chip = document.createElement("button");
                    chip.type = "button";
                    chip.className = "gc-chip";
                    chip.dataset.userId = String(id);
                    chip.innerHTML = `<span class="t">${escapeHtml(nm)}</span><span class="x" aria-hidden="true">×</span>`;
                    groupCallSelected.appendChild(chip);
                });
            }
        }

        if (groupCallPreview) {
            groupCallPreview.innerHTML = "";
            if (count === 0) {
                const tile = document.createElement("div");
                tile.className = "gc-tile";
                tile.innerHTML = `<div class="name"><div class="t">Предпросмотр</div><div class="s">Выбери участников</div></div>`;
                groupCallPreview.appendChild(tile);
            } else {
                // show up to 8 tiles, rest collapsed
                const max = 8;
                const showIds = ids.slice(0, max);
                showIds.forEach(id => {
                    const li = modalGroupCall.querySelector('.group-call-friend-item[data-user-id="' + id + '"]');
                    const nm = li ? (li.dataset.username || ("#" + id)) : ("#" + id);
                    const avatarUrl = li ? (li.dataset.avatarUrl || "") : "";
                    const online = li ? (String(li.dataset.online) === "1") : false;
                    const mode = li ? (li.dataset.mode || "") : "";

                    const tile = document.createElement("div");
                    tile.className = "gc-tile";

                    const av = document.createElement("span");
                    av.className = "avatar-circle sm" + (avatarUrl ? " has-image" : "");
                    if (avatarUrl) av.style.backgroundImage = "url('" + avatarUrl.replace(/'/g, "%27") + "')";
                    const init = document.createElement("span");
                    init.className = "avatar-initial";
                    init.textContent = avatarUrl ? "" : (nm ? nm.trim()[0].toUpperCase() : "?");
                    const dot = document.createElement("span");
                    dot.className = "presence-dot";
                    dot.setAttribute("aria-hidden", "true");
                    av.appendChild(init);
                    av.appendChild(dot);

                    try { setPresenceDot(dot, online, mode); } catch(e) {}

                    const nameBox = document.createElement("div");
                    nameBox.className = "name";
                    const t = document.createElement("div");
                    t.className = "t";
                    t.textContent = nm;
                    const s = document.createElement("div");
                    s.className = "s";
                    s.textContent = _gcModeLabel(online, mode);
                    nameBox.appendChild(t);
                    nameBox.appendChild(s);

                    tile.appendChild(av);
                    tile.appendChild(nameBox);
                    groupCallPreview.appendChild(tile);
                });

                if (ids.length > max) {
                    const more = document.createElement("div");
                    more.className = "gc-tile";
                    more.innerHTML = `<div class="name"><div class="t">+${ids.length - max}</div><div class="s">ещё участников</div></div>`;
                    groupCallPreview.appendChild(more);
                }
            }
        }
    }



    function openGroupCallModal(opts = {}) {
        // Voice channel: no friend-pick modal. Join voice instantly.
        try{
            if (String(currentChannelType || '') === 'voice' && currentChannelId){
                __ncQuickJoinVoiceChannel(currentChannelId);
                return;
            }
        }catch(e){}
        // Voice view / connected voice: never show modal
        try{
            const cid = Number(currentChannelId || 0) || Number(groupCallChannelId || 0);
            if (cid){
                let t = String(currentChannelType || '').toLowerCase();
                try{
                    const li = document.querySelector('.guild-channel-item[data-channel-id="'+String(cid)+'"]');
                    if (li && li.dataset && li.dataset.type) t = String(li.dataset.type || t).toLowerCase();
                }catch(e){}
                if (t === 'voice' || !!isVoiceView){
                    __ncQuickJoinVoiceChannel(cid);
                    return;
                }
            }
        }catch(e){}
        // Kill-switch: optionally disable modal completely
        try{ if (window.__ncDisableGroupCallModal) { return; } }catch(e){}
        if (!modalGroupCall) return;

        // FIX21: some safety scripts / browsers may have left inline display:none;
        // clear it so CSS (.modal-backdrop.active{display:flex}) can actually show.
        try {
            modalGroupCall.style.display = '';
            modalGroupCall.style.pointerEvents = '';
            modalGroupCall.style.visibility = '';
            modalGroupCall.style.opacity = '';
            modalGroupCall.removeAttribute('hidden');
        } catch (e) {}

        const intent = opts.intent || "start";
        const precheckIds = Array.isArray(opts.precheckIds) ? opts.precheckIds : [];
        const disableIds = Array.isArray(opts.disableIds) ? opts.disableIds : [];

        modalGroupCall.dataset.intent = intent;

        if (groupCallTitle) {
            groupCallTitle.textContent = (intent === "invite") ? "Добавить в звонок" : "Групповой звонок";
        }
        if (groupCallSub) {
            groupCallSub.textContent = (intent === "invite")
                ? "Выбери людей, которых пригласить в текущий звонок."
                : "Выбери друзей, которым позвонить.";
        }
        if (btnStartGroupCallSelected) {
            btnStartGroupCallSelected.textContent = (intent === "invite") ? "Пригласить" : "Позвонить";
        }

        const checkboxes = modalGroupCall.querySelectorAll(".group-call-friend-checkbox");
        checkboxes.forEach(cb => {
            const id = parseInt(cb.value, 10);
            cb.disabled = false;
            cb.checked = precheckIds.includes(id);

            if (disableIds.includes(id)) {
                cb.checked = true;
                cb.disabled = true;
            }

            const li = cb.closest(".group-call-friend-item");
            if (li) li.dataset.disabled = cb.disabled ? "1" : "0";
        });

        // reset search filter on open
        if (groupCallSearch) {
            groupCallSearch.value = "";
            _gcApplyFilter("");
        }

        modalGroupCall.classList.add("active");
        modalGroupCall.setAttribute("aria-hidden", "false");
        if (groupCallResult) groupCallResult.textContent = "";

        try { _gcRenderSelected(); } catch (e) {}

        // focus search for quick selection
        setTimeout(() => {
            try { if (groupCallSearch) groupCallSearch.focus(); } catch (e) {}
        }, 30);
    }

    // Export for external binders / console debugging (some browsers lose direct header click events).
    try { window.openGroupCallModal = openGroupCallModal; } catch (e) {}
    try { window.__ncOpenGroupCallModal = openGroupCallModal; } catch (e) {}
    try {
        window.__ncForceOpenGroupCall = function(){
            try{
                if (typeof __ncOpenGroupCallFromHeader === 'function') { __ncOpenGroupCallFromHeader(null); return; }
            }catch(e){}
            try{
                // Fallback: if in DM
                if (typeof startAdhocGroupCall === 'function' && typeof currentDmUserId !== 'undefined' && currentDmUserId){
                    const t = (typeof currentDmName !== 'undefined' && currentDmName) ? String(currentDmName) : "Звонок";
                    startAdhocGroupCall([Number(currentDmUserId)], { title: t });
                }
            }catch(e){}
        };
    } catch (e) {}


    function fmtMskDate(iso) {
        if (!iso) return "—";
        try {
            const d = new Date(iso);
            return new Intl.DateTimeFormat("ru-RU", { timeZone: "Europe/Moscow", day: "2-digit", month: "2-digit", year: "numeric" }).format(d);
        } catch (e) {
            return "—";
        }
    }

    function fmtMskDateTime(iso) {
        if (!iso) return "—";
        try {
            const d = new Date(iso);
            return new Intl.DateTimeFormat("ru-RU", { timeZone: "Europe/Moscow", day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" }).format(d);
        } catch (e) {
            return "—";
        }
    }

    function setPresenceDot(dotEl, online, mode) {
        if (!dotEl) return;
        const m = ((mode || "") + "").toLowerCase().trim();

        // reset
        dotEl.classList.remove("is-online","is-offline","is-away","is-dnd","is-invisible");

        if (online) {
            if (m === "away") dotEl.classList.add("is-away");
            else if (m === "dnd") dotEl.classList.add("is-dnd");
            else dotEl.classList.add("is-online");
            return;
        }

        if (m === "invisible") dotEl.classList.add("is-invisible");
        else dotEl.classList.add("is-offline");
    }

        function __ncShowActivityAllowed(){
        try{
            const ui = JSON.parse(localStorage.getItem('nc_settings_ui_state')||'{}')||{};
            if (Object.prototype.hasOwnProperty.call(ui, 'showActivity')){
                return ui.showActivity !== false;
            }
        }catch(e){}
        return true;
    }

function setMiniProfile(user) {
        if (!miniCard) return;

        // Мягкая смена контента, чтобы карточка не "дёргалась"
        miniCard.classList.add("is-switching");
        if (window.__ncMiniSwitchT) clearTimeout(window.__ncMiniSwitchT);
        window.__ncMiniSwitchT = setTimeout(() => {
            if (miniCard) miniCard.classList.remove("is-switching");
        }, 220);

        const name = user && (user.title || user.name || "");
        const uid = user && (user.user_id || user.userId || user.id || user.uid);
        const avatarUrl = ((user && (user.avatar_url || user.avatarUrl || user.avatar)) || (miniCard && miniCard.dataset ? (miniCard.dataset.avatarUrl || "") : "") || "");
        const online = !!(user && (user.is_online || user.online));
        const mode = (user && (user.mode || user.presence_mode || user.presenceMode)) || "";
        const statusText = (user && (user.status || user.statusText)) || "";
        const presenceText = (user && (user.presence_text || user.presenceText)) || "";
        const label = presenceText ? presenceText : (online ? "в сети" : "не в сети");

        if (!name) {
            miniCard.classList.add("is-empty");
            miniCard.classList.remove("is-filled");
            try{ delete miniCard.dataset.userId; }catch(e){}
            try{
                if (miniAvatar) {
                    miniAvatar.style.backgroundImage = "";
                    miniAvatar.classList.remove("has-image");
                }
                if (miniCard && miniCard.dataset) miniCard.dataset.avatarUrl = "";
            }catch(e){}
            try{
                const sideFooter = document.getElementById("user-mini-side-footer");
                if (sideFooter) sideFooter.classList.add("is-hidden");
            }catch(e){}
            if (miniChip) miniChip.classList.add("is-hidden");
            if (miniUserName) { miniUserName.textContent = ""; miniUserName.title = ""; }
            if (miniUserSub) { miniUserSub.textContent = ""; miniUserSub.title = ""; }
            if (miniInitial) miniInitial.textContent = "?";
            setPresenceDot(miniDot, false, "offline");
            if (miniCreated) miniCreated.textContent = "—";
            if (miniActivity) miniActivity.textContent = "—";
            return;
        }

        miniCard.classList.remove("is-empty");
        miniCard.classList.add("is-filled");

        try{
            if (uid) miniCard.dataset.userId = String(uid);
        }catch(e){}

        try{
            if (miniAvatar) {
                if (avatarUrl) {
                    miniAvatar.style.backgroundImage = "url('" + String(avatarUrl).replace(/'/g, "%27") + "')";
                    miniAvatar.classList.add("has-image");
                    if (miniInitial) miniInitial.textContent = "";
                    if (miniCard && miniCard.dataset) miniCard.dataset.avatarUrl = String(avatarUrl);
                    currentDmAvatar = String(avatarUrl);
                } else {
                    miniAvatar.style.backgroundImage = "";
                    miniAvatar.classList.remove("has-image");
                    if (miniCard && miniCard.dataset) miniCard.dataset.avatarUrl = "";
                    currentDmAvatar = null;
                }
            }
        }catch(e){}

        try{
            const sideFooter = document.getElementById("user-mini-side-footer");
            if (sideFooter) sideFooter.classList.remove("is-hidden");
        }catch(e){}

        if (miniChip) {
            miniChip.classList.remove("is-hidden");
            miniChip.textContent = statusText ? statusText : label;
        }
        if (miniUserName) { miniUserName.textContent = name; miniUserName.title = name; }
        if (miniInitial) miniInitial.textContent = avatarUrl ? "" : name.charAt(0).toUpperCase();
        if (miniUserSub) { miniUserSub.textContent = label; miniUserSub.title = label; }
        setPresenceDot(miniDot, online, mode);

        if (miniCreated) miniCreated.textContent = user.created_at_label || fmtMskDate(user.created_at);
        const allowAct = __ncShowActivityAllowed();
        const activity = (allowAct && user && user.activity_label) ? user.activity_label : (online ? "сейчас" : (user.last_seen_label || fmtMskDateTime(user.last_seen)));
        if (miniActivity) miniActivity.textContent = activity;
    }


// --- Presence (online/offline) sync ---
const presenceById = {};

function applyPresenceToFriendItem(userId, online, mode, presenceText, lastSeenIso, activityLabel) {
    const items = __ncGetFriendItemsByUserId(userId);
    if (!items.length) return;

    const m = ((mode || "") + "").toLowerCase().trim();

    items.forEach((item) => {
        item.dataset.online = online ? "1" : "0";
        item.dataset.presenceMode = m;
        if (lastSeenIso) item.dataset.lastSeen = lastSeenIso;
        if (activityLabel) item.dataset.activityLabel = activityLabel;

        const sub = item.querySelector(".friend-sub");
        if (sub) sub.textContent = presenceText ? presenceText : (online ? "в сети" : "не в сети");

        const dot = item.querySelector(".presence-dot");
        setPresenceDot(dot, online, m);
    });

    try{
        const friendsViewEl = document.getElementById('friends-view');
        if (friendsViewEl && !friendsViewEl.classList.contains('is-hidden')) {
            const activeBtn = friendsViewEl.querySelector('.friends-tab.is-active[data-friends-tab]');
            const activeTab = activeBtn ? String(activeBtn.dataset.friendsTab || 'online') : 'online';
            if (typeof __ncFriendsApplyTab === 'function') __ncFriendsApplyTab(activeTab);
        }
    }catch(_e){}
}


function applyPresenceUpdate(p) {
    if (!p || !p.user_id) return;
    const uid = parseInt(p.user_id, 10);
    const online = !!p.online;
    const mode = (p.mode || "").toLowerCase().trim();
    const presenceText = p.presence_text || p.presenceText || "";
    const activityLabel = p.activity_label || p.activityLabel || "";
    const lastSeen = p.last_seen || "";

    presenceById[uid] = Object.assign({}, presenceById[uid] || {}, { online, mode, presence_text: presenceText, activity_label: activityLabel, last_seen: lastSeen });

    applyPresenceToFriendItem(uid, online, mode, presenceText, lastSeen, activityLabel);

    // If this is me, sync bottom-left dot/menu too
    try {
        if (parseInt(uid, 10) === parseInt(currentUserId, 10)) {
            setMyPresenceModeUI(mode || (chatMainEl ? chatMainEl.dataset.currentPresenceMode : "online"), online);
        }
    } catch (e) {}

    // If this user is open in mini-profile right now, refresh it.
    if (typeof currentDmUserId !== "undefined" && currentDmUserId && parseInt(currentDmUserId, 10) === uid) {
        const curName = (typeof currentDmName !== "undefined" && currentDmName) ? currentDmName : (miniUserName ? miniUserName.textContent : "");
        setMiniProfile({
            title: curName,
            avatar_url: currentDmAvatar || (miniCard && miniCard.dataset ? (miniCard.dataset.avatarUrl || "") : ""),
            is_online: online,
            mode: mode,
            presence_text: presenceText,
            created_at: (presenceById[uid] || {}).created_at,
            last_seen: lastSeen,
            activity_label: activityLabel,
        });
    }

    // Modal (if it's open for the same user)
    if (modalUserMini && modalUserMini.classList.contains("active") && modalUserMini.dataset && parseInt(modalUserMini.dataset.userId || "0", 10) === uid) {
        if (modalUserStatus) modalUserStatus.textContent = presenceText ? presenceText : (online ? "в сети" : "не в сети");
        setPresenceDot(modalUserDot, online, mode);
        const __actOk = (typeof __ncShowActivityAllowed === "function") ? __ncShowActivityAllowed() : true;
        if (modalUserActivity) modalUserActivity.textContent = (__actOk && activityLabel) ? activityLabel : (online ? "сейчас" : fmtMskDateTime(lastSeen));
    }
}

async function refreshPresenceBulk() {
    try {
        const r = await fetch("/api/presence_bulk");
        const data = await r.json();
        const arr = (data && data.users) ? data.users : [];
        arr.forEach(u => {
            const uid = parseInt(u.user_id, 10);
            presenceById[uid] = {
                online: !!u.online,
                mode: (u.mode || "").toLowerCase().trim(),
                presence_text: u.presence_text || "",
                activity_label: u.activity_label || "",
                created_at: u.created_at,
                last_seen: u.last_seen,
                created_at_label: u.created_at_label,
                last_seen_label: u.last_seen_label
            };
            applyPresenceToFriendItem(uid, !!u.online, u.mode, (u.presence_text || ""), u.last_seen, (u.activity_label || ""));
        });

        // if mini-profile already opened, refresh activity labels
        if (typeof currentDmUserId !== "undefined" && currentDmUserId) {
            const u = presenceById[parseInt(currentDmUserId, 10)];
            if (u) {
                setMiniProfile({
                    title: currentDmName,
                    avatar_url: currentDmAvatar || (miniCard && miniCard.dataset ? (miniCard.dataset.avatarUrl || "") : ""),
                    is_online: u.online,
                    mode: u.mode,
                    presence_text: u.presence_text,
                    activity_label: u.activity_label,
                    created_at: u.created_at,
                    last_seen: u.last_seen,
                    created_at_label: u.created_at_label,
                    last_seen_label: u.last_seen_label
                });
            }
        }
    } catch (e) {}


// --- Sidebar meta (DM previews + unread) ---
const friendListEl = document.querySelector(".friend-list");
const channelListEl = document.querySelector(".channel-list");


function _setUnreadBadge(item, count) {
    if (!item) return;
    const badge = item.querySelector(".unread-badge");
    if (!badge) return;
    const n = Math.max(0, parseInt(count || 0, 10) || 0);
    if (n <= 0) {
        badge.classList.add("is-hidden");
        badge.setAttribute("aria-hidden", "true");
        badge.textContent = "";
        item.dataset.unread = "0";
        return;
    }
    badge.classList.remove("is-hidden");
    badge.setAttribute("aria-hidden", "false");
    badge.textContent = String(n > 99 ? "99+" : n);
    item.dataset.unread = String(n);
}

function updateFriendsLauncherBadge(){
    try{
        const badge = document.getElementById("friends-unread-total");
        if (!badge) return;
        let total = 0;
        document.querySelectorAll("#pane-friends .friend-item.dm-entry, #pane-friends .dm-entry").forEach(it => {
            total += (parseInt(it.dataset.unread || "0", 10) || 0);
        });
        if (total > 0) {
            badge.textContent = total > 99 ? "99+" : String(total);
            badge.classList.remove("is-hidden");
            badge.setAttribute("aria-hidden", "false");
        } else {
            badge.textContent = "";
            badge.classList.add("is-hidden");
            badge.setAttribute("aria-hidden", "true");
        }
    }catch(e){}
}


// --- Global unread (brand badge + document title) ---
const __ncBaseTitle = (document && document.title) ? String(document.title) : "Neon Chat";

function __ncGetTotalUnread(){
    let total = 0;
    try{
        document.querySelectorAll("#pane-friends .friend-item.dm-entry, #pane-friends .dm-entry").forEach(it => {
            total += (parseInt(it.dataset.unread || "0", 10) || 0);
        });
    }catch(e){}
    // Sum only top-level server bubbles to avoid double count with channel list inside a server.
    try{
        document.querySelectorAll(".channel-item.dc-server").forEach(it => {
            total += (parseInt(it.dataset.unread || "0", 10) || 0);
        });
    }catch(e){}
    return total;
}

function __ncUpdateBrandUnreadBadge(){
    try{
        const el = document.getElementById("nc-brand-unread");
        if (!el) return;
        const total = __ncGetTotalUnread();
        if (total > 0){
            el.textContent = total > 99 ? "99+" : String(total);
            el.classList.remove("is-hidden");
            el.setAttribute("aria-hidden","false");
        } else {
            el.textContent = "";
            el.classList.add("is-hidden");
            el.setAttribute("aria-hidden","true");
        }
    }catch(e){}
}

function __ncUpdateDocumentTitleUnread(){
    try{
        const total = __ncGetTotalUnread();
        if (total > 0){
            const prefix = "(" + (total > 99 ? "99+" : String(total)) + ") ";
            if (!String(document.title||"").startsWith(prefix)){
                document.title = prefix + __ncBaseTitle.replace(/^\(\d+\+?\)\s*/,'');
            }
        } else {
            // restore
            document.title = __ncBaseTitle.replace(/^\(\d+\+?\)\s*/,'');
        }
    }catch(e){}
}

function __ncUpdateGlobalUnreadUI(){
    try{ __ncUpdateBrandUnreadBadge(); }catch(e){}
    try{ __ncUpdateDocumentTitleUnread(); }catch(e){}
}

// Update when tab becomes visible (keeps title correct after returning)
try{
    document.addEventListener("visibilitychange", () => {
        if (!document.hidden) __ncUpdateGlobalUnreadUI();
    });
}catch(e){}

function _flashPlusOne(item){
    try{
        if(!item) return;
        // Small "+1" pop that fades out. Doesn't mess with actual unread count.
        const pop = document.createElement("span");
        pop.className = "unread-pop";
        pop.textContent = "+1";
        item.appendChild(pop);
        setTimeout(()=>{ try{ pop.remove(); }catch(e){} }, 1100);
    }catch(e){}
}

function _pulseBadge(item){
    try{
        const badge = item ? item.querySelector(".unread-badge") : null;
        if(!badge) return;
        badge.classList.remove("is-pulse");
        // Force reflow so animation restarts
        void badge.offsetWidth;
        badge.classList.add("is-pulse");
        setTimeout(()=>{ try{ badge.classList.remove("is-pulse"); }catch(e){} }, 700);
    }catch(e){}
}


function _setPreview(item, text) {
    if (!item) return;
    const pv = item.querySelector(".friend-preview");
    if (!pv) return;
    const t = (text || "").toString().replace(/\s+/g, " ").trim();
    pv.textContent = t;
    pv.title = t;
}

function _reorderFriendList() {
    if (!friendListEl) return;
    const items = Array.from(friendListEl.querySelectorAll(".friend-item.dm-entry, .dm-entry"));
    items.sort((a, b) => {
        const atA = Date.parse(a.dataset.lastMessageAt || "") || 0;
        const atB = Date.parse(b.dataset.lastMessageAt || "") || 0;
        if (atA !== atB) return atB - atA;

        const onA = (a.dataset.online === "1") ? 1 : 0;
        const onB = (b.dataset.online === "1") ? 1 : 0;
        if (onA !== onB) return onB - onA;

        const na = (a.querySelector(".friend-name")?.textContent || "").toLowerCase();
        const nb = (b.querySelector(".friend-name")?.textContent || "").toLowerCase();
        return na.localeCompare(nb);
    });

    items.forEach(it => friendListEl.appendChild(it));
}

async function refreshSidebarMeta() {
    try {
        const r = await fetch("/api/sidebar_meta");
        const data = await r.json();
        const friends = (data && data.friends) ? data.friends : [];
        friends.forEach(f => {
            const uid = parseInt(f.user_id, 10);
            const item = __ncGetSidebarFriendItemByUserId(uid);
            if (!item) return;

            if (f.dm_channel_id) item.dataset.dmChannelId = String(f.dm_channel_id);
            if (f.last_message_at) item.dataset.lastMessageAt = String(f.last_message_at);

            _setPreview(item, f.last_message || "");
            _setUnreadBadge(item, f.unread || 0);

            // Also refresh presence from this endpoint (cheap and current)
            try {
                applyPresenceToFriendItem(uid, !!f.online, f.mode, (f.presence_text || ""), null, null);
            } catch (e) {}
        });

        

        // Channels: unread counts
        try{
            const channels = (data && data.channels) ? data.channels : [];
            
            channels.forEach(ch => {
                            const cid = parseInt(ch.channel_id, 10);
                            const item = document.querySelector(`.channel-item[data-channel-id="${cid}"]`) ||
                                         document.querySelector(`.channel-item[data-channelId="${cid}"]`);
                            if (!item) return;

                            // Sync meta used by the rail bubbles
                            try{
                                if (ch.name) item.dataset.channelName = String(ch.name);
                                if (ch.is_private !== undefined) item.dataset.isPrivate = (ch.is_private ? "1" : "0");
                                if (ch.my_role) item.dataset.myRole = String(ch.my_role);
                                item.dataset.iconUrl = (ch.icon_url || "");
                                applyChannelBubble(item);
                            }catch(e){}

                            _setUnreadBadge(item, ch.unread || 0);
                        });
        }catch(e){}

        _reorderFriendList();
        try{ updateFriendsLauncherBadge(); }catch(e){}
            try{ __ncUpdateGlobalUnreadUI(); }catch(e){}
} catch (e) {}


}


// Throttled sidebar meta refresh (DM mapping + unread counts).
let __ncSidebarMetaRefreshTimer = null;
function scheduleSidebarMetaRefresh(){
    try{
        if (__ncSidebarMetaRefreshTimer) return;
        __ncSidebarMetaRefreshTimer = setTimeout(() => {
            __ncSidebarMetaRefreshTimer = null;
            try { refreshSidebarMeta(); } catch (e) {}
        }, 400);
    }catch(e){}
}

function sidebarOnNewMessage(msg) {
    if (!msg || !msg.channel_id) return;

    const chId = String(msg.channel_id || "");
    const isMine = (parseInt(msg.user_id, 10) === parseInt(currentUserId, 10));
    const isOpen = (String(currentChannelId || "") === chId);

    // --- DM (friends list) ---
    try {
        if (friendListEl) {
            const item = friendListEl.querySelector(`.dm-entry[data-dm-channel-id="${chId}"]`) ||
                         friendListEl.querySelector(`.dm-entry[data-dmChannelId="${chId}"]`) ||
                         friendListEl.querySelector(`.dm-entry[data-dm-channel-id='${chId}']`);

            if (item) {
                item.dataset.lastMessageAt = new Date().toISOString();
                _setPreview(item, msg.content || "");

                if (!isMine && !isOpen) {
                    const prev = parseInt(item.dataset.unread || "0", 10) || 0;
                    _setUnreadBadge(item, prev + 1);
                    _pulseBadge(item);
                    _flashPlusOne(item);
                }
                if (isOpen) {
                    _setUnreadBadge(item, 0);
                
                    try{ __ncUpdateGlobalUnreadUI(); }catch(e){}}
                _reorderFriendList();
            }
        }
    } catch (e) {}

    // --- Channels list ---
    try {
        if (channelListEl) {
            const item = channelListEl.querySelector(`.channel-item[data-channel-id="${chId}"]`) ||
                         channelListEl.querySelector(`.channel-item[data-channelId="${chId}"]`) ||
                         channelListEl.querySelector(`.channel-item[data-channel-id='${chId}']`);

            if (item) {
                if (!isMine && !isOpen) {
                    const prev = parseInt(item.dataset.unread || "0", 10) || 0;
                    _setUnreadBadge(item, prev + 1);
                    _pulseBadge(item);
                    _flashPlusOne(item);
                }
                if (isOpen) {
                    _setUnreadBadge(item, 0);
                
                    try{ __ncUpdateGlobalUnreadUI(); }catch(e){}}
            }
        }
    } catch (e) {}

    try{ updateFriendsLauncherBadge(); }catch(e){}
    try{ __ncUpdateGlobalUnreadUI(); }catch(e){}

    // --- Sound ---
    // Sound should work even when you are inside the chat. If you don't want sound: set DND / offline / invisible.
    try {
        if (!isMine) {
            playNotifySound();
        }
    } catch (e) {}

    // Ensure mapping/unread counts stay accurate even if a DM was never opened in this session.
    try { if (!isMine) scheduleSidebarMetaRefresh(); } catch (e) {}
}

}

function startPresencePing() {
    if (!socket) return;
    if (window.__nc_presencePingTimer) clearInterval(window.__nc_presencePingTimer);
    window.__nc_presencePingTimer = setInterval(() => {
        try {
            if (socket && socket.connected) socket.emit("presence_ping", {});
        } catch (e) {}
    }, 25000);
}

    function updateHeaderCallActions() {
        if (!chatHeaderActions) return;

        const hasSelection = !!currentChannelId || !!currentDmUserId;
        if (!hasSelection) {
            chatHeaderActions.classList.add("is-hidden");
            if (btnHeaderCall) btnHeaderCall.style.display = "none";
            if (btnHeaderGroupCall) btnHeaderGroupCall.style.display = "none";
            return;
        }

        // Calls are available in:
        //   - single DM (currentDmUserId)
        //   - adhoc group chat (currentChannelType === 'adhoc_group')
        // Channels (servers) do not have header call buttons.
        const isAdhocGroup = (typeof currentChannelType !== 'undefined' && currentChannelType === 'adhoc_group');
        if (currentDmUserId || isAdhocGroup) {
            chatHeaderActions.classList.remove('is-hidden');
            if (isAdhocGroup) {
                // In group DM, only show group call button
                if (btnHeaderCall) btnHeaderCall.style.display = 'none';
                if (btnHeaderGroupCall) btnHeaderGroupCall.style.display = 'flex';
            } else {
                if (btnHeaderCall) btnHeaderCall.style.display = 'flex';
                if (btnHeaderGroupCall) btnHeaderGroupCall.style.display = 'flex';
            }
        } else {
            chatHeaderActions.classList.add('is-hidden');
            if (btnHeaderCall) btnHeaderCall.style.display = 'none';
            if (btnHeaderGroupCall) btnHeaderGroupCall.style.display = 'none';
        }
    }

    setMiniProfile(null);
    updateHeaderCallActions();
                    try { closeFriendsDrawer(); } catch (e) {}
                    try { updateFriendsLauncherBadge(); } catch (e) {}

    if (btnMiniCall) {
        btnMiniCall.addEventListener("click", (e) => {
            try { e.preventDefault(); e.stopPropagation(); } catch (err) {}
            try{
                const uid = parseInt((miniCard && miniCard.dataset) ? (miniCard.dataset.userId || "0") : "0", 10) || 0;
                const uname = (miniUserName && miniUserName.textContent) ? miniUserName.textContent.trim() : "";
                ncStartCallFromUI({userId: uid, name: uname});
            }catch(err){
                ncStartCallFromUI();
            }
        });
    }

    if (btnMiniOpenDm) {
        btnMiniOpenDm.addEventListener("click", () => {
            try{
                const uid = parseInt((miniCard && miniCard.dataset) ? (miniCard.dataset.userId || "0") : "0", 10) || 0;
                const uname = (miniUserName && miniUserName.textContent) ? miniUserName.textContent.trim() : "";
                if (uid) {
                    openDmByUserId(uid, uname);
                    return;
                }
            }catch(e){}
            if (!currentDmUserId) alert("Сначала выбери друга в списке.");
        });
    }

    // Right panel: open full profile
    const btnMiniFullProfile = document.getElementById("btn-mini-full-profile");
    if (btnMiniFullProfile) {
        btnMiniFullProfile.addEventListener("click", () => {
            try{
                const uid = parseInt((miniCard && miniCard.dataset) ? (miniCard.dataset.userId || "0") : "0", 10) || 0;
                if (!uid) return;

                const uname = (miniUserName && miniUserName.textContent) ? miniUserName.textContent.trim() : ("#" + uid);
                const status = (miniChip && !miniChip.classList.contains("is-hidden")) ? (miniChip.textContent || "") : "";
                const aurl = (miniAvatar && miniAvatar.style && miniAvatar.style.backgroundImage) ? (miniAvatar.style.backgroundImage || "") : "";
                // extract url('...')
                let avatarUrl = "";
                const m = /url\(['\"]?(.*?)['\"]?\)/.exec(aurl || "");
                if (m && m[1]) avatarUrl = m[1];

                openUserFullProfileModal(uid, uname, status, avatarUrl);
            }catch(e){}
        });
    }


    function _ncNormShowcase(sc){
        sc = sc || {};
        return {
            tagline: String(sc.tagline || '').trim(),
            favorite_game: String(sc.favorite_game || '').trim(),
            about: String(sc.about || '').trim(),
        };
    }

    function _ncApplyMiniShowcase(sc){
        const box = document.getElementById('modal-user-showcase');
        if (!box) return;
        const s = _ncNormShowcase(sc);
        if (!s.tagline && !s.favorite_game && !s.about){
            box.style.display = 'none';
            box.innerHTML = '';
            return;
        }
        const parts = [];
        if (s.tagline) parts.push(`<div class="ums-tag">${_ncEscHtml(s.tagline)}</div>`);
        if (s.favorite_game) parts.push(`<div class="ums-game">🎮 ${_ncEscHtml(s.favorite_game)}</div>`);
        if (s.about) parts.push(`<div class="ums-about">${_ncEscHtml(s.about)}</div>`);
        box.innerHTML = parts.join('');
        box.style.display = '';
    }

    function _ncApplyFullShowcase(sc){
        const wrap = document.getElementById('full-user-showcase');
        const t = document.getElementById('full-showcase-tagline');
        const g = document.getElementById('full-showcase-game');
        const a = document.getElementById('full-showcase-about');
        if (!wrap || !t || !g || !a) return;
        const s = _ncNormShowcase(sc);
        if (!s.tagline && !s.favorite_game && !s.about){
            wrap.style.display = 'none';
            t.textContent = '—'; g.textContent = '—'; a.textContent = '';
            return;
        }
        t.textContent = s.tagline || '—';
        g.textContent = s.favorite_game || '—';
        a.textContent = s.about || '';
        wrap.style.display = '';
    }

    function openUserMiniModal(name, status, avatarUrl, opts) {
        if (!modalUserMini) return;
        opts = opts || {};
        try { if (opts.userId) modalUserMini.dataset.userId = String(opts.userId); } catch (e) {}

        const uid = parseInt((opts && opts.userId) ? opts.userId : "0", 10) || 0;
        const nick = (typeof __ncGetFriendNick === "function" && uid) ? (__ncGetFriendNick(uid) || "") : "";
        const handle0 = (opts && (opts.username || opts.handle)) ? String(opts.username || opts.handle) : (name ? String(name) : "");
        const handle = handle0 && handle0 !== ("#" + uid) ? handle0 : "";
        const display = (nick || (opts && opts.displayName) || handle || name || (uid ? ("User " + uid) : "")) || "Профиль пользователя";

        if (modalUserName) modalUserName.textContent = display;
        if (modalUserUsername) modalUserUsername.textContent = handle ? ("@" + handle) : (uid ? ("@" + ("user" + uid)) : "");
        if (modalUserStatus) modalUserStatus.textContent = status || "";

        // Async enrich (created/last seen/username/avatar/status)
        (async () => {
            if (!uid) return;
            const p = await _ncFetchUserProfile(uid, currentGuildId);
            if (!p) return;

            const uname = (p.username || "").trim();
            const disp2 = (nick || uname || display).trim();
            if (modalUserName) modalUserName.textContent = disp2 || display;
            if (modalUserUsername) modalUserUsername.textContent = uname ? ("@" + uname) : (modalUserUsername.textContent || "");
            if (modalUserCreated) modalUserCreated.textContent = _ncFmtDateRU(p.created_at);
            if (modalUserActivity) modalUserActivity.textContent = _ncFmtActivityRU(p.last_seen, !!p.is_online);
            try{ _ncApplyMiniShowcase(p.showcase || {}); }catch(e){}

            // status fallback
            if (modalUserStatus && (!modalUserStatus.textContent || !modalUserStatus.textContent.trim())) {
                const st = (p.status_text || "").trim();
                if (st) modalUserStatus.textContent = st;
                else {
                    if (p.presence_mode === "dnd") modalUserStatus.textContent = "не беспокоить";
                    else if (p.presence_mode === "away") modalUserStatus.textContent = "нет на месте";
                    else modalUserStatus.textContent = (p.is_online ? "в сети" : "не в сети");
                }
            }

            // avatar
            if (modalUserAvatar) {
                const av = (p.avatar_url || "").trim();
                if (av) {
                    modalUserAvatar.style.backgroundImage = `url(${av})`;
                    modalUserAvatar.classList.add("has-image");
                }
            }
        })();
        try{
            if ((!status || !String(status).trim()) && opts && opts.userId && typeof presenceById !== "undefined") {
                const p = presenceById[parseInt(opts.userId,10)] || null;
                if (p && modalUserStatus) {
                    if (p.mode === "dnd") modalUserStatus.textContent = "не беспокоить";
                    else if (p.mode === "away") modalUserStatus.textContent = "нет на месте";
                    else modalUserStatus.textContent = (p.is_online ? "в сети" : "не в сети");
                }
            }
        }catch(e){}

        const onlineGuess = (status || "").toLowerCase().includes("в сети");

        if (modalUserAvatar) {
            if (avatarUrl) {
                modalUserAvatar.style.backgroundImage = `url(${avatarUrl})`;
                modalUserAvatar.classList.add("has-image");
            } else {
                modalUserAvatar.style.backgroundImage = "";
                modalUserAvatar.classList.remove("has-image");
            }
        }
        if (modalUserInitial) modalUserInitial.textContent = name ? name.charAt(0).toUpperCase() : "?";
        setPresenceDot(modalUserDot, onlineGuess);
        if (modalUserCreated) modalUserCreated.textContent = "—";
        if (modalUserActivity) modalUserActivity.textContent = onlineGuess ? "сейчас" : "—";
        try{ _ncApplyMiniShowcase({}); }catch(e){}

        
        // Role pill (optional; supplied by context)
        try{
            if (modalUserRolePill) {
                const rn = (opts.roleName || "").trim();
                const rc = (opts.roleColor || "").trim();
                modalUserRolePill.textContent = rn ? rn : "—";
                if (rc) modalUserRolePill.style.setProperty("--role-color", rc);
                else modalUserRolePill.style.removeProperty("--role-color");
            }
        }catch(e){}

        // Notes (local-only, Discord-like)
        try{
            if (modalUserNote) {
                const uid = parseInt((modalUserMini.dataset && modalUserMini.dataset.userId) ? modalUserMini.dataset.userId : "0", 10) || 0;
                const k = uid ? ("nc_note_user_" + uid) : "";
                modalUserNote.value = (k && window.localStorage) ? (localStorage.getItem(k) || "") : "";
                modalUserNote.oninput = () => {
                    try{
                        if (!k || !window.localStorage) return;
                        localStorage.setItem(k, modalUserNote.value || "");
                    }catch(e){}
                };
            }
        }catch(e){}

        // Positioning: center by default when requested; otherwise near cursor.
        // IMPORTANT: reset old inline positioning so we never get stuck in top-left.
        try{
            const inner = modalUserMini.querySelector(".user-mini-popout") || modalUserMini.querySelector(".user-mini-modal") || modalUserMini.querySelector(".modal");
            if (inner) {
                const x = (opts && typeof opts.x === "number") ? opts.x : null;
                const y = (opts && typeof opts.y === "number") ? opts.y : null;
                const wantsCenter = !!(opts && opts.center);

                // clear any old transforms from previous opens
                inner.style.transform = "";

                if (wantsCenter || x === null || y === null) {
                    inner.style.position = "fixed";
                    inner.style.left = "50%";
                    inner.style.top = "50%";
                    inner.style.transform = "translate(-50%, -50%)";
                } else {
                    const pad = 10;
                    const w = inner.offsetWidth || 360;
                    const h = inner.offsetHeight || 320;
                    let left = x + 12;
                    let top = y + 12;
                    if (left + w + pad > window.innerWidth) left = window.innerWidth - w - pad;
                    if (top + h + pad > window.innerHeight) top = window.innerHeight - h - pad;
                    if (left < pad) left = pad;
                    if (top < pad) top = pad;
                    inner.style.position = "fixed";
                    inner.style.left = left + "px";
                    inner.style.top = top + "px";
                    inner.style.transform = "";
                }
            }
        }catch(e){}

        modalUserMini.classList.add("active");
    }

    function closeUserMiniModal() {
        if (!modalUserMini) return;
        modalUserMini.classList.remove("active");
    }

    function openUserFullProfileModal(uid, name, status, avatarUrl, opts){
        if (!modalUserFull) return;
        opts = opts || {};
        uid = parseInt(uid || "0", 10) || 0;
        try{ modalUserFull.dataset.userId = uid ? String(uid) : ""; }catch(e){}

        // basic identity
        const nick = (typeof __ncGetFriendNick === "function" && uid) ? (__ncGetFriendNick(uid) || "") : "";
        const handle0 = (opts && (opts.username || opts.handle)) ? String(opts.username || opts.handle) : (name ? String(name) : "");
        const handle = (handle0 && handle0 !== ("#" + uid)) ? handle0 : "";
        const displayName = (nick || (opts && opts.displayName) || handle || name || (typeof getUserNameById === "function" ? getUserNameById(uid) : ("user#" + uid))) || "—";

        if (fullUserName) fullUserName.textContent = displayName || "—";
        if (fullUserUsername) fullUserUsername.textContent = handle ? ("@" + handle) : (uid ? ("@" + ("user" + uid)) : "—");

        // enrich via API
        (async () => {
            if (!uid) return;
            const p = await _ncFetchUserProfile(uid);
            if (!p) return;
            const uname = (p.username || "").trim();
            const disp2 = (nick || uname || displayName).trim();
            if (fullUserName) fullUserName.textContent = disp2 || displayName;
            if (fullUserUsername) fullUserUsername.textContent = uname ? ("@" + uname) : (fullUserUsername.textContent || "—");
            if (fullUserJoined) fullUserJoined.textContent = _ncFmtDateRU((opts && opts.joinedAt) ? opts.joinedAt : p.created_at);
            try{
                if (fullUserPresence) fullUserPresence.textContent = _ncPresenceLabel(p.presence_mode, p.is_online);
                if (fullUserCustomStatus){
                    const st = (p.status_text || "").trim();
                    if (st){
                        fullUserCustomStatus.style.display = "";
                        fullUserCustomStatus.innerHTML = `<span class="cs-dot" aria-hidden="true"></span><span class="cs-txt">${_ncEscHtml(st)}</span>`;
                    } else {
                        fullUserCustomStatus.style.display = "none";
                        fullUserCustomStatus.textContent = "";
                    }
                }
                if (fullUserBadges){
                    const b = Array.isArray(p.badges) ? p.badges : [];
                    fullUserBadges.innerHTML = b.map(x => {
                        const key = (x && x.key) ? String(x.key) : "";
                        const label = (x && x.label) ? String(x.label) : "";
                        return `<span class="user-badge" title="${_ncEscHtml(label)}" data-key="${_ncEscHtml(key)}">${_ncBadgeSvg(key)}</span>`;
                    }).join("");
                }
                if (fullActivitySub){
                    const st = (p.status_text || "").trim();
                    if (st) fullActivitySub.textContent = st;
                }
                try{
                    _ncApplyFullShowcase(p.showcase || {});
                    const sc = _ncNormShowcase(p.showcase || {});
                    if (fullActivityTitle && sc.tagline) fullActivityTitle.textContent = sc.tagline;
                    else if (fullActivityTitle) fullActivityTitle.textContent = `${disp2 || displayName} не рассказывает здесь о своей активности`;
                    if (fullActivitySub && sc.favorite_game) fullActivitySub.textContent = `Любимая игра: ${sc.favorite_game}`;
                }catch(e){}
            }catch(e){} 
        })();

        // avatar
        if (fullUserAvatar) {
            if (avatarUrl) {
                fullUserAvatar.style.backgroundImage = `url(${avatarUrl})`;
                fullUserAvatar.classList.add("has-image");
            } else {
                fullUserAvatar.style.backgroundImage = "";
                fullUserAvatar.classList.remove("has-image");
            }
        }
        if (fullUserInitial) fullUserInitial.textContent = displayName ? displayName.charAt(0).toUpperCase() : "?";

        // presence dot / status fallback
        try{
            if (uid && typeof presenceById !== "undefined") {
                const p = presenceById[uid] || null;
                if (p && fullUserDot) {
                    fullUserDot.classList.remove("is-online","is-away","is-dnd","is-offline");
                    if (!p.is_online) fullUserDot.classList.add("is-offline");
                    else if (p.mode === "dnd") fullUserDot.classList.add("is-dnd");
                    else if (p.mode === "away") fullUserDot.classList.add("is-away");
                    else fullUserDot.classList.add("is-online");
                }
            }
        }catch(e){}

        // joined/date: handled via profile API

        // activity empty state text
        if (fullActivityTitle) {
            fullActivityTitle.textContent = `${displayName} не рассказывает здесь о своей активности`;
        }
        if (fullActivitySub) {
            fullActivitySub.textContent = "Адепт минимализма. Спросите, как этого добиться.";
        }
        try{ _ncApplyFullShowcase({}); }catch(e){}

        // note (общий ключ с мини-профилем)
        try{
            if (fullUserNote) {
                const k = uid ? ("nc_note_user_" + uid) : "";
                fullUserNote.value = (k && window.localStorage) ? (localStorage.getItem(k) || "") : "";
                fullUserNote.oninput = () => {
                    try{
                        if (!k || !window.localStorage) return;
                        localStorage.setItem(k, fullUserNote.value || "");
                    }catch(e){}
                };
            }
        }catch(e){}

        // tabs labels (пока без серверной части — как на скрине по умолчанию)
        try{
            if (fullTabFriends) fullTabFriends.textContent = "Нет общих друзей";
            if (fullTabServers) fullTabServers.textContent = "Нет общих серверов";
        }catch(e){}

        // open
        modalUserFull.classList.add("active");
        // default tab
        try{ _fullProfileSelectTab("activity"); }catch(e){}
    }

