    function _fullProfileSelectTab(tab){
        if (!modalUserFull) return;
        const tabs = modalUserFull.querySelectorAll(".user-full-tab");
        const panels = modalUserFull.querySelectorAll(".user-full-panel");
        tabs.forEach(t => {
            const on = (t.dataset.tab === tab);
            t.classList.toggle("is-active", on);
            t.setAttribute("aria-selected", on ? "true" : "false");
        });
        panels.forEach(p => {
            const on = (p.dataset.panel === tab);
            p.classList.toggle("is-active", on);
        });
    }


