function escapeHtml(s){
    const str = String(s || "");
    return str.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;");
}

function _safeCssUrl(u){
    try{
        return encodeURI(String(u || "")).replace(/'/g, "%27");
    }catch(e){
        return "";
    }
}



