    // channels

    const channelCtxMenu = document.getElementById("channel-context-menu");
    const channelCtxDelete = document.getElementById("ctx-delete-channel");
    let channelCtxTarget = null;

	// ===== Screen share context menu (ПКМ по демке) =====
	const ssCtxMenu = document.getElementById('ss-context-menu');
	const ssCtxStopView = document.getElementById('ssctx-stop-view');
	const ssCtxMute = document.getElementById('ssctx-mute');
	const ssCtxVol = document.getElementById('ssctx-volume');
	const ssCtxVolWrap = document.getElementById('ssctx-volume-wrap');
	const ssCtxClose = document.getElementById('ssctx-close');
	let __ncSsCtxMode = '';
	let __ncSsVolume = 1.0;
	try{
		const sv = parseInt(localStorage.getItem('ss_stream_volume')||'100',10);
		if (isFinite(sv)) __ncSsVolume = Math.min(2, Math.max(0, sv/100));
	}catch(e){}

	function __ncGetSsVideoForMode(mode){
		try{
			const m = String(mode||'');
			if (m.indexOf('voice') !== -1) return voiceShareVideoEl || null;
			return callScreenVideo || null;
		}catch(e){ return null; }
	}


	function __ncSsHasStreamForMode(mode){
	    try{
	        const m = String(mode||'');
	        if (m === 'local-dm') return !!isScreenSharing;
	        if (m === 'remote-dm') return !!(remoteScreenStream || _pendingRemoteScreenStream);
	        if (m === 'local-voice') return !!groupScreenSharing;
	        if (m === 'remote-voice') return !!(groupRemoteScreensByPeer && Object.keys(groupRemoteScreensByPeer).length);
	        if (m.indexOf('voice') !== -1) return !!(groupScreenSharing || (groupRemoteScreensByPeer && Object.keys(groupRemoteScreensByPeer).length));
	        return !!(isScreenSharing || remoteScreenStream || _pendingRemoteScreenStream);
	    }catch(e){
	        return false;
	    }
	}

	function __ncApplySsVolumeToVideo(v){
		try{
			if (!v) return;
			// Support up to 200% via WebAudio gain (fallback clamps to 0..1).
			_ncSetMediaElementGain(v, __ncSsVolume);
		}catch(e){}
	}

	function __ncCloseSsCtx(){
	    if (!ssCtxMenu) return;
	    try{ ssCtxMenu.classList.remove('active'); }catch(e){}
	    try{ ssCtxMenu.setAttribute('aria-hidden','true'); }catch(e){}
	    __ncSsCtxMode = '';
	}

	function __ncSsCtxRefreshControls(mode){
	    try{
	        const m = String(mode||'');
	        const isLocal = (m.indexOf('local-') === 0);
	        // Stop/close button label + visibility
	        if (ssCtxStopView){
	            ssCtxStopView.style.display = '';
	            ssCtxStopView.textContent = isLocal ? 'Остановить демонстрацию' : 'Прекратить просмотр';
	        }
	        // Volume/mute only for REMOTE stream
	        const muteWrap = ssCtxMute ? (ssCtxMute.closest ? ssCtxMute.closest('.context-check') : null) : null;
	        if (ssCtxVolWrap) ssCtxVolWrap.style.display = isLocal ? 'none' : '';
	        if (muteWrap) muteWrap.style.display = isLocal ? 'none' : '';
	    }catch(e){}
	}

	function __ncOpenSsCtx(x, y, mode){
	    if (!ssCtxMenu) return;
	    __ncSsCtxMode = String(mode||'');
	    try{ __ncSsCtxRefreshControls(__ncSsCtxMode); }catch(e){}
	    // sync mute state
	    try{
	        if (ssCtxMute) {
	            const v = __ncGetSsVideoForMode(__ncSsCtxMode);
	            ssCtxMute.checked = !!(v && v.muted);
	        }
	    }catch(e){}
	    // sync volume state
	    try{
	        if (ssCtxVol) {
	            const v = __ncGetSsVideoForMode(__ncSsCtxMode);
	            let vv = (v && typeof v.volume === 'number') ? Math.round(v.volume*100) : Math.round(__ncSsVolume*100);
            try{
                const m = String(__ncSsCtxMode||'');
                if (m === 'remote-dm') {
                    // DM screenshare audio is usually on a dedicated <audio>; keep the slider in sync with stored value.
                    vv = Math.round(__ncSsVolume*100);
                }
            }catch(e){}
	            ssCtxVol.value = String(Math.min(200, Math.max(0, vv)));
	        }
	    }catch(e){}

	    try{
	        ssCtxMenu.style.left = '0px';
	        ssCtxMenu.style.top = '0px';
	        ssCtxMenu.hidden = false;
	        ssCtxMenu.classList.add('active');
	        ssCtxMenu.setAttribute('aria-hidden','false');
	        const rect = ssCtxMenu.getBoundingClientRect();
	        const pad = 8;
	        const maxX = Math.max(pad, window.innerWidth - rect.width - pad);
	        const maxY = Math.max(pad, window.innerHeight - rect.height - pad);
	        const nx = Math.min(Math.max(pad, x), maxX);
	        const ny = Math.min(Math.max(pad, y), maxY);
	        ssCtxMenu.style.left = nx + 'px';
	        ssCtxMenu.style.top = ny + 'px';
	    }catch(e){}
	}

	function __ncSsCtxStopAction(){
	    // Local share: stop. Remote share: stop viewing (go to preview in DM).
	    const m = __ncSsCtxMode;
	    try{ if (typeof __ncExitFullscreenIfAny === 'function') __ncExitFullscreenIfAny(); }catch(e){}
	    if (m === 'local-dm') {
	        try{ stopScreenShare({ notify:true, force:true }); }catch(e){}
	    } else if (m === 'local-voice') {
	        try{ stopGroupScreenShare({ notify:false, force:true }); }catch(e){}
	    } else if (m === 'remote-dm') {
	        try{
	            _callWatchingRemoteScreen = false;
	            if (remoteScreenStream) _attachCallInlineScreenShare(remoteScreenStream, 'remote');
	        }catch(e){}
		    } else if (m === 'remote-voice') {
		        try{
		            if (voiceShareVideoEl) {
		                voiceShareVideoEl.pause();
		                voiceShareVideoEl.srcObject = null;
		            }
		            _setVoiceTileText('Голосовой канал', 'Просмотр демонстрации остановлен');
		        }catch(e){}
		    }
	    __ncCloseSsCtx();
	}

	function __ncSsCtxMuteAction(){
    try{
        const m = String(__ncSsCtxMode||'');
        const isLocal = (m.indexOf('local-') === 0);
        const wantMuted = !!(ssCtxMute && ssCtxMute.checked);

        // Local sharer should NEVER hear their own stream audio
        // regardless of menu state/volume.
        const muted = isLocal ? true : wantMuted;

        isScreenMuted = muted;
        const v = __ncGetSsVideoForMode(m);
        if (v){
            v.muted = muted;
            // If user set volume to 0, also treat as muted for remote.
            if (!isLocal && __ncSsVolume <= 0) v.muted = true;
        
        }

        // DM screenshare audio may be played via a dedicated <audio> element
        try{
            if (!isLocal && m === 'remote-dm' && remoteScreenAudio) remoteScreenAudio.muted = muted;
        }catch(e){}

        // keep checkbox in sync if we had to force-local mute
        if (ssCtxMute && isLocal) ssCtxMute.checked = true;
    }catch(e){}


	}

	function __ncSsCtxVolumeAction(){
    try{
        if (!ssCtxVol) return;
        const n = parseInt(ssCtxVol.value||'100',10);
        if (!isFinite(n)) return;

        const m = String(__ncSsCtxMode||'');
        const isLocal = (m.indexOf('local-') === 0);

		__ncSsVolume = Math.min(2, Math.max(0, n/100));
		try{ localStorage.setItem('ss_stream_volume', String(Math.round(__ncSsVolume*100))); }catch(e){}

        const v = __ncGetSsVideoForMode(m);
        if (v){
            // Local sharer: always silent
            if (isLocal){
                try{ v.volume = 0; }catch(e){}
                try{ v.muted = true; }catch(e){}
            } else {
				__ncApplySsVolumeToVideo(v);
				try{ if (m === 'remote-dm' && remoteScreenAudio) _ncSetMediaElementGain(remoteScreenAudio, __ncSsVolume); }catch(e){}
                // if user drags to 0 -> mute; if >0 and checkbox not set -> unmute
                const wantMuted = !!(ssCtxMute && ssCtxMute.checked);
                try{ v.muted = wantMuted || (__ncSsVolume <= 0); }catch(e){}

                try{
					if (m === 'remote-dm' && remoteScreenAudio) {
						_ncSetMediaElementGain(remoteScreenAudio, __ncSsVolume);
						remoteScreenAudio.muted = wantMuted || (__ncSsVolume <= 0);
					}
                }catch(e){}
            }
        }
    }catch(e){}

	}

	if (ssCtxStopView) ssCtxStopView.addEventListener('click', (e) => {
	    try{ e.preventDefault(); e.stopPropagation(); }catch(_){ }
	    __ncSsCtxStopAction();
	});
	if (ssCtxClose) ssCtxClose.addEventListener('click', (e) => {
	    try{ e.preventDefault(); e.stopPropagation(); }catch(_){ }
	    __ncCloseSsCtx();
	});
	if (ssCtxMute) ssCtxMute.addEventListener('change', () => __ncSsCtxMuteAction());
	if (ssCtxClose) ssCtxClose.addEventListener('click', (e) => { try{ e.preventDefault(); e.stopPropagation(); }catch(_){} __ncCloseSsCtx(); });
	if (ssCtxVol) {
	    ssCtxVol.addEventListener('input', () => __ncSsCtxVolumeAction());
	    ssCtxVol.addEventListener('change', () => __ncSsCtxVolumeAction());
	}

	// Open on right click over demo video
	function __ncBindSsCtxTarget(el, modeGetter){
	    if (!el) return;
	    el.addEventListener('contextmenu', (e) => {
	        const mode = (typeof modeGetter === 'function') ? String(modeGetter() || '') : 'remote-dm';
	        const hasStream = __ncSsHasStreamForMode(mode);
	        try{ window.isStreaming = hasStream; }catch(_e){}
	        if (!hasStream) return; // FIX217: нет стрима → нет меню стрима
	        try{ e.preventDefault(); e.stopPropagation(); }catch(_){ }
	        __ncOpenSsCtx(e.clientX, e.clientY, mode);
	    }, true);
	}

	// Важно: видео может иметь pointer-events, но safest — вешаем на frame
	__ncBindSsCtxTarget((callScreenFrame || callScreenStage || callScreenVideo), () => {
	    if (isScreenSharing) return 'local-dm';
	    if (remoteScreenStream) return 'remote-dm';
	    return 'remote-dm';
	});
	__ncBindSsCtxTarget((voiceShareVideoEl && (voiceShareVideoEl.parentElement || voiceShareVideoEl)) || null, () => {
	    if (groupScreenSharing) return 'local-voice';
	    if (groupRemoteScreensByPeer && Object.keys(groupRemoteScreensByPeer).length) return 'remote-voice';
	    return 'remote-voice';
	});

	// Fallback: event delegation so it works for BOTH users even if elements were recreated
	document.addEventListener('contextmenu', (e) => {
	    try{
	        if (!ssCtxMenu) return;
	        if (e.defaultPrevented) return;
	        const t = e.target;
	        if (!t || (ssCtxMenu.classList && ssCtxMenu.classList.contains('active'))) return;
	        const inCall = (t.closest && t.closest('#call-screen-stage, #call-screen-frame, #call-screen-video'));
	        const inVoice = (t.closest && t.closest('#voice-share-video, #voice-tile-main'));
	        if (!inCall && !inVoice) return;

			        // If the user right-clicks a participant/avatar tile, we must NOT open the screenshare menu.
			        // (Discord-like DM layout places tiles near/over the stream area.) Let the user context menu win.
			        if (t.closest) {
			            const onUserTile = t.closest(
			                '#call-participants .participant-tile, #call-participants .voice-participant, #call-participants .voice-roster-user,'+
			                ' .participant-tile, .voice-participant, .voice-roster-user,'+
			                ' #call-peer-initial, #call-peer-name, .call-avatar, .tile-more-btn'
			            );
			            if (onUserTile) return;
			        }

			        // Open only when we have something to control
	        if (inCall && !(isScreenSharing || remoteScreenStream || _pendingRemoteScreenStream)) return;
	        if (inVoice && !(groupScreenSharing || (groupRemoteScreensByPeer && Object.keys(groupRemoteScreensByPeer).length))) return;

	        try{ e.preventDefault(); e.stopPropagation(); }catch(_){ }
	        if (inVoice) {
	            const m = groupScreenSharing ? 'local-voice' : 'remote-voice';
	            __ncOpenSsCtx(e.clientX, e.clientY, m);
	        } else {
	            const m = isScreenSharing ? 'local-dm' : 'remote-dm';
	            __ncOpenSsCtx(e.clientX, e.clientY, m);
	        }
	    }catch(err){}
	}, true);

	// Close on click outside / ESC
	document.addEventListener('click', (e) => {
	    if (!ssCtxMenu || !ssCtxMenu.classList.contains('active')) return;
	    const t = e.target;
	    if (t && ssCtxMenu.contains(t)) return;
	    __ncCloseSsCtx();
	}, true);
	document.addEventListener('keydown', (e) => {
	    if (e.key === 'Escape') __ncCloseSsCtx();
	});

    // context menus: friends + messages + emoji
    const friendCtxMenu = document.getElementById("friend-context-menu");
    try{ window.__ncFriendCtxMenuReady = !!friendCtxMenu; }catch(e){}

    // -------------------------------------------------------------------------
    // Fullscreen API: keep context menus visible while a stream/call is fullscreen
    // In Fullscreen API mode, only the fullscreen element's subtree is rendered.
    // If menus live outside that subtree, they simply won't appear.
    // We portal key overlay nodes into the fullscreen root on fullscreenchange.
    // -------------------------------------------------------------------------
    const __ncFsPortalIds = [
        'friend-context-menu',
        'message-context-menu',
        'emoji-pop',
        'ss-context-menu',
        'guild-channel-context-menu',
        'guild-category-context-menu',
        'user-popout'
    ];
    const __ncFsPortalState = new Map();

    function __ncFsPortalCapture(){
        try{
            for (const id of __ncFsPortalIds) {
                const el = document.getElementById(id);
                if (!el) continue;
                if (!__ncFsPortalState.has(id)) {
                    __ncFsPortalState.set(id, { parent: el.parentNode, next: el.nextSibling });
                }
            }
        }catch(e){}
    }

    function __ncFsPortalMoveInto(root){
        try{
            if (!root) return;
            for (const id of __ncFsPortalIds) {
                const el = document.getElementById(id);
                if (!el) continue;
                if (el.parentNode === root) continue;
                try{ root.appendChild(el); }catch(_){ }
            }
        }catch(e){}
    }

    function __ncFsPortalRestore(){
        try{
            for (const [id, st] of __ncFsPortalState.entries()) {
                const el = document.getElementById(id);
                if (!el) continue;
                const parent = st && st.parent ? st.parent : document.body;
                if (!parent || !parent.appendChild) continue;
                try{
                    if (st.next && st.next.parentNode === parent) parent.insertBefore(el, st.next);
                    else parent.appendChild(el);
                }catch(_){ try{ document.body.appendChild(el); }catch(__){} }
            }
        }catch(e){}
    }

    function __ncSyncPortalsForFullscreen(){
        try{
            __ncFsPortalCapture();
            const fs = document.fullscreenElement || document.webkitFullscreenElement;
            if (!fs) { __ncFsPortalRestore(); return; }

            // If the fullscreen element is a <video>, portal into its parent container.
            let root = fs;
            try{
                if (root && root.tagName && String(root.tagName).toLowerCase() === 'video') {
                    if (root.parentElement) root = root.parentElement;
                }
            }catch(_){ }
            __ncFsPortalMoveInto(root);
        }catch(e){}
    }

    document.addEventListener('fullscreenchange', __ncSyncPortalsForFullscreen);
    document.addEventListener('webkitfullscreenchange', __ncSyncPortalsForFullscreen);

    // Cached friend ids for fast checks (context menu toggles)
    const __ncFriendIds = new Set();
    function __ncSeedFriendIdsFromDOM(){
        try{
            document.querySelectorAll('#pane-friends .dm-entry[data-user-id], #friends-view .friends-page-item[data-user-id]').forEach(li => {
                const id = String(li.getAttribute('data-user-id') || '').trim();
                if (id) __ncFriendIds.add(id);
            });
        }catch(e){}
    }
    function __ncIsFriend(uid){
        const id = String(parseInt(uid, 10) || 0);
        if (!id || id === "0") return false;
        if (__ncFriendIds.size === 0) __ncSeedFriendIdsFromDOM();
        if (__ncFriendIds.has(id)) return true;
        // Fallback: DOM query (in case friend list not seeded yet)
        const found = !!__ncGetSidebarFriendItemByUserId(id) || !!__ncGetFriendsPageItemByUserId(id);
        if (found) __ncFriendIds.add(id);
        return found;
    }

    // Friend nicknames (local only)
    function __ncGetFriendNick(uid){
        try{
            const id = String(parseInt(uid,10)||0);
            if(!id||id==="0") return "";
            return (localStorage.getItem("friend_nick_" + id) || "").trim();
        }catch(e){ return ""; }
    }
    function __ncSetFriendNick(uid, nick){
        try{
            const id = String(parseInt(uid,10)||0);
            if(!id||id==="0") return;
            const v = String(nick||"").trim();
            if(!v) localStorage.removeItem("friend_nick_" + id);
            else localStorage.setItem("friend_nick_" + id, v);
        }catch(e){}
    }

    // --- user profile fetch/cache (for mini/full profile) ---
    const __ncProfileCache = {};
    async function _ncFetchUserProfile(uid, guildId){
        uid = parseInt(uid,10)||0;
        guildId = parseInt(guildId||0,10)||0;
        if(!uid) return null;
        const key = String(uid) + "@" + String(guildId||0);
        if(__ncProfileCache[key]) return __ncProfileCache[key];
        try{
            const qs = guildId ? (`?guild_id=${encodeURIComponent(guildId)}`) : "";
            const r = await fetch(`/api/users/${uid}/profile${qs}`, { method: "GET", credentials: "same-origin" });
            if(!r.ok) return null;
            const j = await r.json();
            __ncProfileCache[key] = j;
            return j;
        }catch(e){ return null; }
    }

    function _ncFmtDateRU(iso){
        try{
            if(!iso) return "—";
            const d = new Date(iso);
            if(!isFinite(d.getTime())) return "—";
            return new Intl.DateTimeFormat("ru-RU", { day:"numeric", month:"short", year:"numeric" }).format(d);
        }catch(e){ return "—"; }
    }

    function _ncPresenceLabel(mode, isOnline){
        try{
            if(!isOnline) return "не в сети";
            mode = String(mode||"").toLowerCase();
            if(mode === "dnd") return "не беспокоить";
            if(mode === "away" || mode === "idle") return "нет на месте";
            return "в сети";
        }catch(e){ return "—"; }
    }

    function _ncEscHtml(s){
        return String(s||"").replace(/[&<>"']/g, (c) => ({ "&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;" }[c]));
    }

    function _ncBadgeSvg(key){
        key = String(key||"");
        if(key === "owner"){
            return `<svg class="ub-i" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 3l3 6 6 .8-4.4 4.2 1.1 6L12 17l-5.7 3 1.1-6L3 9.8 9 9z" fill="currentColor"/></svg>`;
        }
        if(key === "admin"){
            return `<svg class="ub-i" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 2l8 4v6c0 5-3.4 9.3-8 10-4.6-.7-8-5-8-10V6z" fill="currentColor"/></svg>`;
        }
        if(key === "mod"){
            return `<svg class="ub-i" viewBox="0 0 24 24" aria-hidden="true"><path d="M14 2l-2 2-2-2H6v4l6 6 6-6V2zM4 10v10h16V10l-8 8z" fill="currentColor"/></svg>`;
        }
        if(key === "staff"){
            return `<svg class="ub-i" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 2a5 5 0 015 5c0 2.8-2.2 5-5 5s-5-2.2-5-5a5 5 0 015-5zm-8 20a8 8 0 0116 0H4z" fill="currentColor"/></svg>`;
        }
        return `<svg class="ub-i" viewBox="0 0 24 24" aria-hidden="true"><circle cx="12" cy="12" r="8" fill="currentColor"/></svg>`;
    }

    function _ncFmtActivityRU(iso, isOnline){
        try{
            if(isOnline) return "сейчас";
            if(!iso) return "—";
            const d = new Date(iso);
            if(!isFinite(d.getTime())) return "—";
            const now = new Date();
            const sameDay = d.toDateString() === now.toDateString();
            if(sameDay) return "сегодня";
            const yesterday = new Date(now.getTime() - 24*3600*1000);
            if(d.toDateString() === yesterday.toDateString()) return "вчера";
            return _ncFmtDateRU(iso);
        }catch(e){ return "—"; }
    }

    function __ncExtractFriendBaseName(nameEl){
        try{
            if(!nameEl) return "";
            const cosName = nameEl.querySelector('.nc-cos-name');
            if(cosName) return String(cosName.textContent || "").trim();
            let raw = "";
            Array.from(nameEl.childNodes || []).forEach((node) => {
                if(node && node.nodeType === 3) raw += (node.nodeValue || "");
            });
            raw = String(raw || "").trim();
            if(raw) return raw;
            const clone = nameEl.cloneNode(true);
            clone.querySelectorAll('.friend-admin-pill, .nc-cos-tag, .unread-badge').forEach((n) => { try{ n.remove(); }catch(_e){} });
            return String(clone.textContent || "").trim();
        }catch(e){ return ""; }
    }
    function __ncSetFriendNameText(nameEl, text){
        try{
            if(!nameEl) return;
            const nextText = String(text || "").trim();
            let cosName = nameEl.querySelector('.nc-cos-name');
            if(cosName){
                cosName.textContent = nextText;
                return;
            }
            let firstText = null;
            Array.from(nameEl.childNodes || []).forEach((node) => {
                if(!firstText && node && node.nodeType === 3) firstText = node;
            });
            if(firstText) firstText.nodeValue = nextText;
            else nameEl.insertBefore(document.createTextNode(nextText), nameEl.firstChild || null);
        }catch(e){}
    }
    function __ncSyncFriendAdminPillForItem(item, profile){
        try{
            if(!item) return;
            const nameEl = item.querySelector('.friend-name');
            if(!nameEl) return;
            const row = nameEl.closest('.friend-row') || item.querySelector('.friend-row') || nameEl.parentElement;
            if(!row) return;
            row.querySelectorAll('.friend-admin-pill').forEach((pill) => { try{ pill.remove(); }catch(_e){} });
            const badges = Array.isArray(profile && profile.badges) ? profile.badges : [];
            const isAdmin = badges.some((b) => {
                const key = String((b && b.key) || '').toLowerCase();
                return key === 'admin' || key === 'owner';
            });
            const rawBase = __ncExtractFriendBaseName(nameEl);
            const cleanedBase = isAdmin ? String(rawBase || '').replace(/\s+ADMIN\s*$/i, '').trim() : rawBase;
            if(cleanedBase && cleanedBase !== rawBase){
                __ncSetFriendNameText(nameEl, cleanedBase);
                if(item.dataset && (!item.dataset.baseName || /\s+ADMIN\s*$/i.test(String(item.dataset.baseName || '')))){
                    item.dataset.baseName = cleanedBase;
                }
            }
            if(!isAdmin) return;
            const pill = document.createElement('span');
            pill.className = 'friend-admin-pill';
            pill.textContent = 'ADMIN';
            row.appendChild(pill);
        }catch(e){}
    }
    function __ncRefreshFriendAdminPills(){
        try{
            document.querySelectorAll("#pane-friends .dm-entry[data-user-id], #friends-view .friends-page-item[data-user-id]").forEach((it) => {
                const uid = parseInt((it.dataset && it.dataset.userId) || '0', 10) || 0;
                if(!uid || it.dataset.ncAdminPillLoading === '1') return;
                it.dataset.ncAdminPillLoading = '1';
                Promise.resolve(typeof _ncFetchUserProfile === 'function' ? _ncFetchUserProfile(uid) : null)
                    .then((profile) => { __ncSyncFriendAdminPillForItem(it, profile || null); })
                    .catch(() => {})
                    .finally(() => {
                        try{ delete it.dataset.ncAdminPillLoading; }catch(_e){}
                    });
            });
        }catch(e){}
    }
    function __ncApplyFriendNicknames(){
        try{
            document.querySelectorAll("#pane-friends .dm-entry[data-user-id], #friends-view .friends-page-item[data-user-id]").forEach(it => {
                const uid = it.dataset.userId;
                const nick = __ncGetFriendNick(uid);
                const nameEl = it.querySelector(".friend-name");
                if(!nameEl) return;
                const baseName = __ncExtractFriendBaseName(nameEl);
                if(!it.dataset.baseName || /\s+ADMIN\s*$/i.test(String(it.dataset.baseName || ''))){
                    it.dataset.baseName = String(baseName || '').replace(/\s+ADMIN\s*$/i, '').trim();
                }
                __ncSetFriendNameText(nameEl, nick ? nick : (it.dataset.baseName || ("#" + uid)));
            });
            __ncRefreshFriendAdminPills();
        }catch(e){}
    }

