    // DM mute (notifications) - local only
    function __ncGetMuteUntil(uid){
        try{
            const id = String(parseInt(uid,10)||0);
            if(!id||id==="0") return 0;
            return parseInt(localStorage.getItem("mute_until_" + id) || "0", 10) || 0;
        }catch(e){ return 0; }
    }
    function __ncSetMuteUntil(uid, until){
        try{
            const id = String(parseInt(uid,10)||0);
            if(!id||id==="0") return;
            const v = parseInt(until,10) || 0;
            localStorage.setItem("mute_until_" + id, String(v));
        }catch(e){}
    }
    function __ncIsMuted(uid){
        const u = __ncGetMuteUntil(uid);
        if(u === -1) return true;
        if(u <= 0) return false;
        return Date.now() < u;
    }



    function __ncPluralRu(n, one, few, many){
        n = Math.abs(parseInt(n,10) || 0);
        const mod10 = n % 10, mod100 = n % 100;
        if(mod10 === 1 && mod100 !== 11) return one;
        if(mod10 >= 2 && mod10 <= 4 && (mod100 < 12 || mod100 > 14)) return few;
        return many;
    }
    function __ncMuteHint(uid){
        try{
            const until = __ncGetMuteUntil(uid);
            if(until === -1) return "пока не включу";
            if(!until || until <= 0) return "";
            const ms = until - Date.now();
            if(ms <= 0) return "";
            const sec = Math.floor(ms/1000);
            const min = Math.floor(sec/60);
            const hr  = Math.floor(min/60);
            const day = Math.floor(hr/24);

            if(day >= 1){
                const d = day;
                return "ещё " + d + " " + __ncPluralRu(d, "день", "дня", "дней");
            }
            if(hr >= 1){
                const h = hr;
                return "ещё " + h + " " + __ncPluralRu(h, "час", "часа", "часов");
            }
            const m = Math.max(1, min);
            return "ещё " + m + " " + __ncPluralRu(m, "минута", "минуты", "минут");
        }catch(e){ return ""; }
    }
