    function closeEmojiPop() {
        _closeMenu(emojiPop);
        emojiMode = "insert";
        emojiTargetMessageId = null;
        emojiInsertTargetOverride = null;
    }

    function insertAtCursor(input, text) {
        if (!input) return;
        const start = input.selectionStart ?? input.value.length;
        const end = input.selectionEnd ?? input.value.length;
        const before = input.value.slice(0, start);
        const after = input.value.slice(end);
        input.value = before + text + after;
        const pos = start + text.length;
        try { input.setSelectionRange(pos, pos); } catch (e) {}
        try { input.focus(); } catch (e) {}
    }

    function openEmojiPopAt(x, y, mode, messageId) {
        if (!emojiPop) return;
        emojiMode = mode || "insert";
        emojiTargetMessageId = messageId || null;
        try { emojiPop.dataset.mode = emojiMode; } catch (e) {}
        _openMenuAt(emojiPop, x, y);
        try { if (window.__ncEmojiPopOnOpen) window.__ncEmojiPopOnOpen(emojiPop); } catch (e) {}
    }

