    // Delegated open on left click
    document.addEventListener('click', (e) => {
        try{
            const t = e.target;
            if (!t) return;

            // Click inside popout: keep open
            if (userPopoutCard && userPopoutCard.contains(t)) return;

            // Click on a member in right list (or server settings members list)
            const el = (t.closest) ? t.closest('.dc-member, .svs-member') : null;
            if (el) {
                const inMembers = !!(el.closest && (el.closest('#right-members-list') || el.closest('#svs-members-list')));
                if (inMembers) {
                    // Prevent interfering with other click handlers
                    try{ e.preventDefault(); }catch(err){}
                    try{ e.stopPropagation(); }catch(err){}
                    openUserPopoutFromEl(el, e);
                    return;
                }
            }

            // Otherwise: close if open
            if (_popoutIsOpen()) closeUserPopout();
        }catch(err){}
    }, true);

    // Close on ESC / resize / scroll (Discord-like)
    document.addEventListener('keydown', (e) => {
        try{
            if (!e) return;
            if (e.key === 'Escape' && _popoutIsOpen()) {
                closeUserPopout();
            }
        }catch(err){}
    });

    window.addEventListener('resize', () => { try{ if (_popoutIsOpen()) closeUserPopout(); }catch(e){} }, {passive:true});
    window.addEventListener('scroll', () => { try{ if (_popoutIsOpen()) closeUserPopout(); }catch(e){} }, {passive:true, capture:true});

    // Universal user context menu (ПКМ) – delegated, robust across dynamic DOM.
    // This fixes cases where a user tile is rendered without an explicit handler.
    document.addEventListener('contextmenu', (e) => {
        try{
            // Keep browser context menu for inputs/editables
            const t = e.target;
            if (t && t.closest) {
                if (t.closest('input, textarea, [contenteditable="true"], [contenteditable=""], .allow-browser-context')) return;
                // Do not hijack right-click inside existing menus
                if (t.closest('.context-menu')) return;
            }

            const __ncUserCtxSel = [
                    '.friend-item[data-user-id]',
                    '.dc-member',
                    '#right-members-list .dc-member',
                    '.svs-member',
                    '.msg-avatar',
                    '.msg-user',
                    '#call-peer-initial',
                    '#call-peer-name',
                    '.call-peer-initial',
                    '.call-peer-name',
                    '.voice-roster-user',
                    '.voice-participant[data-uid]',
                    '.participant-tile[data-uid]',
                    '.group-call-friend-item[data-user-id]',
                    '#me-panel',
                    '#current-user-avatar',
                    '#me-panel .profile-name'
                ].join(', ');

            const el = (t && t.closest) ? t.closest(__ncUserCtxSel) : null;

            // If user right-clicks inside the call UI but the specific element is not
            // recognized (call DOM often re-renders and some layers use pointer-events:none),
            // still open the user context menu for the current DM peer.
            if (!el) {
                try{
                    const inCall = !!(peerConnection || groupCallActive);
                    if (inCall && callBar) {
                        // Prefer DOM containment checks when possible.
                        let insideCallUi = false;
                        try{
                            if (t && t.closest && (t.closest('#call-bar') || t.closest('.call-window'))) insideCallUi = true;
                        }catch(_){ }
                        // If pointer-events blocked target traversal, fall back to geometry hit-test.
                        if (!insideCallUi) {
                            try{
                                const r = callBar.getBoundingClientRect();
                                const x = e.clientX || 0, y = e.clientY || 0;
                                if (x >= r.left && x <= r.right && y >= r.top && y <= r.bottom) insideCallUi = true;
                            }catch(_){ }
                        }
                        if (insideCallUi) {
                            const dmUid = parseInt((currentCallTargetId || currentDmUserId || 0), 10) || 0;
                            if (dmUid && typeof openUserCtxFromEl === 'function') {
                                let proxy = document.getElementById('__nc_call_ctx_proxy');
                                if (!proxy) {
                                    proxy = document.createElement('div');
                                    proxy.id = '__nc_call_ctx_proxy';
                                    proxy.style.position = 'fixed';
                                    proxy.style.left = '-9999px';
                                    proxy.style.top = '-9999px';
                                    proxy.style.width = '1px';
                                    proxy.style.height = '1px';
                                    proxy.style.pointerEvents = 'none';
                                    document.body.appendChild(proxy);
                                }
                                try{ proxy.dataset.userId = String(dmUid); }catch(e){}
                                try{ proxy.dataset.uid = String(dmUid); }catch(e){}
                                e.preventDefault();
                                try{ e.stopPropagation(); }catch(err){}
                                openUserCtxFromEl(proxy, e.clientX || 0, e.clientY || 0);
                                return;
                            }
                        }
                    }
                }catch(err){}
                return;
            }

            const uid = parseInt(el.dataset.userId || el.dataset.userid || el.dataset.uid || '0', 10) || 0;

            // Calls UI (DM header) may not carry data-user-id depending on how the call was opened.
            // If we're inside the call HUD, fall back to the current DM peer id.
            if (!uid) {
                try{
                    const inCallHud = !!(t && t.closest && t.closest('#call-bar'));
                    if (inCallHud && (peerConnection || groupCallActive)) {
                        const dmUid = parseInt((currentCallTargetId || currentDmUserId || 0), 10) || 0;
                        if (dmUid) {
                            try{ el.dataset.userId = String(dmUid); }catch(e){}
                            try{ el.dataset.uid = String(dmUid); }catch(e){}
                            // Use the same element so menu positioning matches click target.
                            e.preventDefault();
                            try{ e.stopPropagation(); }catch(err){}
                            openUserCtxFromEl(el, e.clientX || 0, e.clientY || 0);
                            return;
                        }
                    }
                }catch(err){}
                return;
            }

            // Prevent browser menu and open our menu
            e.preventDefault();
            try{ e.stopPropagation(); }catch(err){}
            openUserCtxFromEl(el, e.clientX || 0, e.clientY || 0);
        }catch(err){}
    }, true);

    // (voice roster right-click handler removed: now covered by the universal user context menu listener above)

    async function _sendServerInviteToUser(uid, serverId){
        try{
            const sid = parseInt(serverId, 10) || 0;
            const id = parseInt(uid, 10) || 0;
            if (!sid || !id) return;

            const r = await fetch(`/api/channels/${sid}/details`);
            const d = await r.json();
            if (!d || d.error) {
                ncToast(d && d.error ? d.error : 'Не удалось получить приглашение');
                return;
            }
            const url = (d.invite_url || '').trim();
            if (!url) {
                ncToast('Нет прав создавать приглашения на этот сервер.');
                return;
            }
            const serverName = (d.name || d.title || '').trim() || ('Сервер #' + sid);
            const ok = await sendDmToUser(id, `Приглашение на сервер “${serverName}”: ${url}`);
            if (ok) ncToast('Приглашение отправлено в личные сообщения.');
            else ncToast('Не удалось отправить приглашение.');
        }catch(e){ ncToast('Не удалось отправить приглашение.'); }
    }

