    // DM-only items in user context menu
    function _openUserMuteMenuForUid(uid){
        try{
            if (!userMuteMenu || !friendCtxMenu) return;
            const id = parseInt(uid,10)||0;
            if(!id) return;

            const isMuted = __ncIsMuted(id);
            userMuteMenu.innerHTML = "";

            const makeBtn = (label, cb, danger=false) => {
                const b = document.createElement("button");
                b.type = "button";
                b.className = "context-item" + (danger ? " danger" : "");
                b.textContent = label;
                b.addEventListener("click", (ev) => {
                    ev.preventDefault();
                    ev.stopPropagation();
                    try{ cb(); }catch(e){}
                    try{ _closeMenu(userMuteMenu); }catch(e){}
                    try{ closeFriendCtxMenu(); }catch(e){}
                });
                userMuteMenu.appendChild(b);
            };

            if (isMuted) {
                makeBtn("Включить звук", () => { __ncSetMuteUntil(id, 0); ncToast("Уведомления включены."); });
                userMuteMenu.appendChild(document.createElement("div")).className="context-sep";
            }

            const now = Date.now();
            makeBtn("На 15 минут", () => { __ncSetMuteUntil(id, now + 15*60*1000); ncToast("Заглушено на 15 минут."); });
            makeBtn("На 1 час", () => { __ncSetMuteUntil(id, now + 60*60*1000); ncToast("Заглушено на 1 час."); });
            makeBtn("На 8 часов", () => { __ncSetMuteUntil(id, now + 8*60*60*1000); ncToast("Заглушено на 8 часов."); });
            makeBtn("На 24 часа", () => { __ncSetMuteUntil(id, now + 24*60*60*1000); ncToast("Заглушено на 24 часа."); });
            makeBtn("Пока не включу", () => { __ncSetMuteUntil(id, -1); ncToast("Заглушено."); });

            // position to the right of main menu
            const r = friendCtxMenu.getBoundingClientRect();
            const x = Math.min(window.innerWidth - 10, r.right + 6);
            const y = Math.min(window.innerHeight - 10, r.top + 220);
            _openMenuAt(userMuteMenu, x, y);
        }catch(e){}
    }

