    // message context open (document-level, capture) - more reliable across dynamic DOM
    document.addEventListener("contextmenu", (e) => {
        if (!msgCtxMenu) return;
        // If user element is right-clicked, show user context menu (Profile/DM/Call)
        try{
            const uEl = e.target && e.target.closest ? e.target.closest(".msg-avatar, .msg-user, .voice-roster-user") : null;
            if (uEl && uEl.dataset && (uEl.dataset.userId || uEl.dataset.userid) && friendCtxMenu) {
                e.preventDefault();
                try { e.stopPropagation(); } catch (err) {}
                openUserCtxFromEl(uEl, e.clientX, e.clientY);
                return;
            }
        }catch(e){}

        const row = e.target && e.target.closest ? e.target.closest(".msg-row") : null;
        if (!row) return;
        // only inside chat messages area
        if (messagesContainer && !messagesContainer.contains(row)) return;

        e.preventDefault();
        try { e.stopPropagation(); } catch (err) {}

        msgCtxTargetRow = row; try { window.__msgCtxTargetRow = row; } catch (e) {}

        // show/hide mine actions
        const mine = row.classList.contains("mine");
        if (msgCtxEdit) msgCtxEdit.style.display = mine ? "" : "none";
        if (msgCtxDelete) msgCtxDelete.style.display = mine ? "" : "none";

        // pin label
        const pinned = (row.dataset.pinned === "1");
        if (msgCtxPin) msgCtxPin.textContent = pinned ? "Открепить" : "Закрепить";

        _openMenuAt(msgCtxMenu, e.clientX, e.clientY);
    }, true);
// message context actions
