    function closeChannelCtxMenu() {
        if (!channelCtxMenu) return;
        channelCtxMenu.classList.remove("active");
        channelCtxMenu.setAttribute("aria-hidden", "true");
        channelCtxTarget = null;
    }

    function openChannelCtxMenu(x, y, li) {
        if (!channelCtxMenu) return;
        channelCtxTarget = li;
        channelCtxMenu.style.left = x + "px";
        channelCtxMenu.style.top = y + "px";
        channelCtxMenu.classList.add("active");
        channelCtxMenu.setAttribute("aria-hidden", "false");

        // clamp into viewport
        requestAnimationFrame(() => {
            try {
                const rect = channelCtxMenu.getBoundingClientRect();
                let nx = x;
                let ny = y;
                if (rect.right > window.innerWidth - 8) nx = Math.max(8, window.innerWidth - rect.width - 8);
                if (rect.bottom > window.innerHeight - 8) ny = Math.max(8, window.innerHeight - rect.height - 8);
                channelCtxMenu.style.left = nx + "px";
                channelCtxMenu.style.top = ny + "px";
            } catch (e) {}
        });
    }

    if (channelCtxMenu) {
        document.addEventListener("click", (e) => {
            if (!channelCtxMenu.classList.contains("active")) return;
            if (e.target && channelCtxMenu.contains(e.target)) return;
            closeChannelCtxMenu();
        });
        window.addEventListener("resize", closeChannelCtxMenu);
        window.addEventListener("scroll", closeChannelCtxMenu, true);
        document.addEventListener("keydown", (e) => {
            if (e.key === "Escape") closeChannelCtxMenu();
        });
    }

    if (channelCtxDelete) {
        channelCtxDelete.addEventListener("click", () => {
            if (!channelCtxTarget) return;
            const targetEl = channelCtxTarget; // keep reference (closeChannelCtxMenu() clears channelCtxTarget)
            const id = targetEl.dataset.channelId;
            const name = targetEl.dataset.channelName || "";
            if (!id) return;
            // Left rail items are servers (root channels)
            if (!confirm(`Удалить сервер ${name ? '"' + name + '"' : ('#' + id)}?`)) return;
            closeChannelCtxMenu();
            fetch(`/api/channels/${id}`, { method: "DELETE" })
                .then(r => r.json())
                .then(async (data) => {
                    if (!data || !data.success) return;

                    const deletedIds = Array.isArray(data.deleted_ids) ? data.deleted_ids.map(String) : [String(id)];

                    // If we just deleted the active voice channel, disconnect immediately.
                    try {
                        if (groupCallActive && groupCallChannelId && deletedIds.includes(String(groupCallChannelId))) {
                            endGroupCall(true);
                        }
                    } catch (e) {}

                    // If the current channel is deleted, clear the center view.
                    if (currentChannelId && deletedIds.includes(String(currentChannelId))) {
                        currentChannelId = null;
                        currentChannelType = null;
                        currentDmUserId = null;
                        currentDmName = null;
                        if (channelNameEl) channelNameEl.textContent = "Канал не выбран";
                        if (messagesContainer) messagesContainer.innerHTML = "";
                try { messagesContainer.dataset.lastDayKey = ""; } catch (e) {}
                        try { updateHeaderCallActions(); } catch (e) {}
                    }

                    // Always refresh the guild channel list (Discord-like: no page reload required).
                    try {
                        if (currentGuildId) {
                            const keep = currentChannelId ? String(currentChannelId) : "";
                            await loadGuildChannels(currentGuildId);
                            if (keep) {
                                try { setActiveGuildChannel(keep); } catch (e) {}
                            }
                            // If nothing selected (e.g., deleted active channel), auto-open first text channel.
                            if (!currentChannelId) {
                                const firstText = document.querySelector('.guild-channel-item[data-type="text"]');
                                if (firstText) firstText.click();
                            }
                        }
                    } catch (e) {}

                    // If we deleted a server (root channel), remove it from the left rail immediately.
                    try {
                        const el = targetEl || document.querySelector(`.channel-list .channel-item[data-channel-id="${String(id)}"]`);
                        const wasActive = !!(el && (el.classList.contains('is-active') || (currentGuildId && String(currentGuildId) === String(id))));
                        if (el && el.parentElement) {
                            el.parentElement.removeChild(el);
                        }
                        refreshSidebarEmptyStates();

                        if (wasActive) {
                            // When deleting the currently opened server, fall back to another server or Home.
                            currentGuildId = null;
                            currentGuildName = null;
                            try { clearGuildUI(); } catch (e) {}
                            const next = document.querySelector('.channel-list .channel-item');
                            if (next) {
                                try { next.click(); } catch (e) {}
                            } else {
                                try { if (railBrand) railBrand.click(); } catch (e) {}
                            }
                        }
                    } catch (e) {}
                })
                .catch(() => {});
        });
    }


