function ncCopy(text){
    const val = String(text || "");
    if (!val) return false;
    try{
        if (navigator.clipboard && navigator.clipboard.writeText) {
            navigator.clipboard.writeText(val);
            return true;
        }
        const ta = document.createElement("textarea");
        ta.value = val;
        document.body.appendChild(ta);
        ta.select();
        document.execCommand("copy");
        ta.remove();
        return true;
    }catch(e){
        return false;
    }
}

function _waitForSelector(selector, timeoutMs=4500, intervalMs=60){
    return new Promise((resolve) => {
        const start = Date.now();
        const tick = () => {
            const el = document.querySelector(selector);
            if (el) return resolve(el);
            if (Date.now() - start >= timeoutMs) return resolve(null);
            setTimeout(tick, intervalMs);
        };
        tick();
    });
}

async function openGuildAndMaybeSub(rootId, subId){
    if (!rootId) return;
    const rid = String(rootId);
    const rootItem = document.querySelector(`.channel-item[data-channel-id="${rid}"]`) ||
                     document.querySelector(`.channel-item[data-channelId="${rid}"]`);
    if (rootItem) rootItem.click();

    if (subId) {
        const sid = String(subId);
        const selector = `.guild-channel-item[data-guild-channel-id="${sid}"], .guild-channel-item[data-channel-id="${sid}"]`;
        const el = await _waitForSelector(selector, 5000, 75);
        if (el) el.click();
    }
}


