// --- v15: server wizard logic ---
let __cswStep = 1;
let __cswTemplate = "custom";
let __cswAudience = null;
let __cswIconFile = null;

function __cswReset(){
    __cswStep = 1;
    __cswTemplate = "custom";
    __cswAudience = null;
    __cswIconFile = null;
    try{ if (cswResult) cswResult.textContent = ""; }catch(e){}
    try{ if (cswNameInput) cswNameInput.value = ""; }catch(e){}
    try{ if (cswIconInput) cswIconInput.value = ""; }catch(e){}
    try{
        if (cswIconPreview){
            cswIconPreview.style.backgroundImage = "";
            cswIconPreview.textContent = "+";
            cswIconPreview.classList.remove("has-image");
        }
    }catch(e){}
}

function __cswSetStep(n){
    __cswStep = parseInt(n || 1, 10) || 1;
    const s1 = (__cswStep === 1);
    const s2 = (__cswStep === 2);
    const s3 = (__cswStep === 3);

    try{
        if (cswStep1){ cswStep1.classList.toggle("is-hidden", !s1); cswStep1.setAttribute("aria-hidden", s1 ? "false" : "true"); }
        if (cswStep2){ cswStep2.classList.toggle("is-hidden", !s2); cswStep2.setAttribute("aria-hidden", s2 ? "false" : "true"); }
        if (cswStep3){ cswStep3.classList.toggle("is-hidden", !s3); cswStep3.setAttribute("aria-hidden", s3 ? "false" : "true"); }
        if (cswBack){ cswBack.classList.toggle("is-hidden", s1); }
    }catch(e){}
}

function __cswClose(){
    try{
        if (!modalCreateServer) return;
        modalCreateServer.classList.remove("active");
        modalCreateServer.setAttribute("aria-hidden", "true");
    }catch(e){}
}

