async function __cswUploadIcon(serverId){
    if (!serverId || !__cswIconFile) return null;
    try{
        const fd = new FormData();
        fd.append("icon", __cswIconFile);
        const resp = await fetch(`/api/channels/${serverId}/icon`, { method:"POST", body: fd });
        const data = await resp.json();
        if (!resp.ok || !data || data.error) return null;
        return data.icon_url || null;
    }catch(e){ return null; }
}

