    // friends / DM

    let __ncDmOpenGuard = { uid: 0, at: 0, pending: false };
    function __ncTryBeginOpenDm(uid){
        uid = parseInt(uid, 10) || 0;
        if (!uid) return false;
        const now = Date.now();
        if (__ncDmOpenGuard.uid === uid) {
            if (__ncDmOpenGuard.pending && (now - __ncDmOpenGuard.at) < 1800) return false;
            if ((now - __ncDmOpenGuard.at) < 700) return false;
        }
        __ncDmOpenGuard = { uid, at: now, pending: true };
        return true;
    }
    function __ncFinishOpenDm(uid){
        uid = parseInt(uid, 10) || 0;
        if (!uid) return;
        if (__ncDmOpenGuard.uid === uid) {
            __ncDmOpenGuard.pending = false;
            __ncDmOpenGuard.at = Date.now();
        }
    }

    async function openDmByUserId(uid, preferredName){
        uid = parseInt(uid, 10) || 0;
        if (!uid) return null;
        if (!__ncTryBeginOpenDm(uid)) return null;
        // Content settings: optionally restrict DMs from non-friends
        try{
            const cs = JSON.parse(localStorage.getItem('nc_content_settings')||'{}')||{};
            if (cs && cs.allowDmsFromServers === false) {
                try{
                    if (typeof __ncIsFriend === 'function' && !__ncIsFriend(uid)) {
                        try{ if (typeof ncToast === 'function') ncToast('Личные сообщения отключены. Добавьте пользователя в друзья, чтобы написать.'); }catch(e){}
                        return null;
                    }
                }catch(e){}
            }
        }catch(e){}
        try{
            try{ __ncSaveScrollForCurrent(); }catch(e){}
            const resp = await fetch(`/api/open_dm/${uid}`, {method:"POST"});
            const data = await resp.json();
            if (!resp.ok || !data || data.error) return null;

            const title = data.title || preferredName || ("#" + uid);
            currentChannelId = parseInt(data.channel_id, 10) || null;
            currentDmUserId = uid;
            currentChannelType = 'dm';
            try{ currentChannelCanSend = (data && data.can_send !== false); }catch(e){ currentChannelCanSend = true; }
            currentDmName = title;
            currentDmAvatar = (data && data.avatar_url) ? data.avatar_url : (currentDmAvatar || "");

            try{ if (typeof __ncCloseFriendsPage === 'function') __ncCloseFriendsPage(); }catch(e){}
            try{ document.body.classList.remove('nc-friends-mode'); }catch(e){}
            try{
                const chatMain = document.querySelector('.chat-main');
                if (chatMain) chatMain.classList.remove('friends-mode');
                const fv = document.getElementById('friends-view');
                if (fv) {
                    fv.classList.add('is-hidden');
                    fv.style.display = 'none';
                    fv.setAttribute('aria-hidden', 'true');
                }
                const msgs = document.getElementById('chat-messages'); if (msgs) msgs.style.display = '';
                const form = document.getElementById('message-form'); if (form) form.style.display = '';
            }catch(e){}
            try{ if (typeof __ncSetGuildPage === 'function') __ncSetGuildPage(null); }catch(e){}
            try{ hideChannelPanel(); }catch(e){}
            try{ setVoiceViewActive(false); }catch(e){}

            if (channelNameEl) channelNameEl.textContent = "@" + title;
            try{ __ncApplyComposerPerms({ placeholder: 'Написать @' + title }); }catch(e){}

            try{
                document.querySelectorAll(`#pane-friends .dm-entry[data-user-id="${uid}"], #pane-friends .friend-item.dm-entry[data-user-id="${uid}"], #friends-view .friends-page-item[data-user-id="${uid}"]`).forEach(li => {
                    try { li.dataset.dmChannelId = String(currentChannelId || ''); } catch(_e) {}
                    try { _setUnreadBadge(li, 0); } catch(_e) {}
                });
                try{ __ncUpdateGlobalUnreadUI(); }catch(_e){}
            }catch(e){}

            try{
                const p = presenceById[uid] || {};
                setMiniProfile({
                    user_id: data.user_id || uid,
                    title: title,
                    status: data.status || "",
                    avatar_url: data.avatar_url || currentDmAvatar || "",
                    is_online: (typeof data.is_online === 'boolean') ? !!data.is_online : !!p.online,
                    mode: data.mode || p.mode || "",
                    presence_text: data.presence_text || p.presence_text || "",
                    activity_label: data.activity_label || p.activity_label || "",
                    created_at: data.created_at || p.created_at,
                    last_seen: data.last_seen || p.last_seen,
                    created_at_label: data.created_at_label || p.created_at_label,
                    last_seen_label: data.last_seen_label || p.last_seen_label
                });
            }catch(e){}

            try{ updateHeaderCallActions(); }catch(e){}
            try{ loadMessages(currentChannelId); }catch(e){}
            try{ joinChannel(currentChannelId); }catch(e){}
            try{ __ncSetLastView({ kind: 'dm', userId: uid, channelId: parseInt(data.channel_id,10)||0 }); }catch(e){}
            // Try to highlight existing friend item if present
            try{
                const li = __ncGetSidebarFriendItemByUserId(uid);
                if (li) { setActiveItem(li); }
            }catch(e){}
            return data;
        }catch(e){
            return null;
        }
        finally{ try{ __ncFinishOpenDm(uid); }catch(e){} }
    }

function attachFriendItemHandlers(item) {
        if (!item || item.dataset.ncFriendHandlersBound === "1") return;
        item.dataset.ncFriendHandlersBound = "1";

        item.addEventListener("contextmenu", (e) => {
            if (!friendCtxMenu) return;
            e.preventDefault();
            try{ e.stopPropagation(); }catch(err){}
            openUserCtxFromEl(item, e.clientX, e.clientY);
        });

        item.addEventListener("click", async (e) => {
            try{ if (e) { e.preventDefault(); e.stopPropagation(); } }catch(_evtErr){}
            const friendId = parseInt(item.dataset.userId || '0', 10) || 0;
            const isFriendsPageItem = !!(item.classList && item.classList.contains("friends-page-item") && !item.closest("#pane-friends"));
            try{ if (typeof __ncCloseFriendsPage === 'function') __ncCloseFriendsPage(); }catch(_closeErr){}
            try{
                document.body.classList.remove('nc-friends-mode');
                const chatMain = document.querySelector('.chat-main');
                if (chatMain) chatMain.classList.remove('friends-mode');
                const fv = document.getElementById('friends-view');
                if (fv) {
                    fv.classList.add('is-hidden');
                    fv.style.display = 'none';
                    fv.setAttribute('aria-hidden', 'true');
                }
                const msgs = document.getElementById('chat-messages'); if (msgs) msgs.style.display = '';
                const form = document.getElementById('message-form'); if (form) form.style.display = '';
            }catch(_closeErr){}
            if (friendId && currentDmUserId === friendId) {
                try{ setActiveItem(item); }catch(e){}
                try{ if (channelNameEl && item.dataset.username) channelNameEl.textContent = '@' + item.dataset.username; }catch(e){}
                try{ __ncApplyComposerPerms({ placeholder: 'Написать @' + (item.dataset.username || '') }); }catch(e){}
                try{ updateHeaderCallActions(); }catch(e){}
                return;
            }

            try{
                if (item.dataset.adhocGroupId){
                    const cid = item.dataset.adhocGroupId;
                    const title = item.dataset.adhocTitle || "Групповой звонок";
                    try{ const b=item.querySelector(".unread-badge"); if(b){ b.textContent=""; b.classList.add("is-hidden"); b.setAttribute("aria-hidden","true"); } }catch(e){}
                    openAdhocGroupChat(cid, title);
                    setActiveItem(item);
                    return;
                }
            }catch(e){}

            if (!friendId) return;

            try{ setActiveItem(item); }catch(e){}
            const data = await openDmByUserId(friendId, item.dataset.username || "");
            if (!data) return;

            try {
                presenceById[friendId] = Object.assign({}, presenceById[friendId] || {}, {
                    online: !!data.is_online,
                    mode: (data.mode || "").toLowerCase().trim(),
                    presence_text: data.presence_text || "",
                    activity_label: data.activity_label || "",
                    created_at: data.created_at,
                    last_seen: data.last_seen,
                    created_at_label: data.created_at_label,
                    last_seen_label: data.last_seen_label
                });
                applyPresenceToFriendItem(friendId, !!data.is_online, data.mode, (data.presence_text||""), data.last_seen, (data.activity_label||""));
            } catch (e) {}

            try{
                if (isFriendsPageItem && typeof __ncCloseFriendsPage === 'function') __ncCloseFriendsPage();
            }catch(e){}
        });
    }

    friendItems.forEach(item => {
        attachFriendItemHandlers(item);
    });

    // Restore last opened DM / server channel on full page refresh.
    // Runs after handlers are bound so that simulated clicks work.
    function __ncRestoreLastViewOnBoot(){
        try{
            const v = __ncGetLastView();
            if (!v || !v.kind) return;

            // Home
            if (v.kind === 'home') {
                try{ if (railBrand) railBrand.click(); }catch(e){}
                return;
            }

            

            // Friends page
            if (v.kind === 'friends') {
                try{ setSidebarMode('friends'); }catch(e){}
                try{ const b = document.getElementById('btn-open-friends-view'); if (b) b.click(); }catch(e){}
                return;
            }

// DM
            if (v.kind === 'dm') {
                const uid = parseInt(v.userId || v.user_id || 0, 10) || 0;
                if (!uid) return;
            // Ad-hoc group call chat
            if (v.kind === 'adhoc_group' && v.channelId) {
                try{ setSidebarMode('friends'); }catch(e){} // ensure DM list mounted
                try{ openAdhocGroupChat(v.channelId, ((__adhocGroupChats||{})[String(v.channelId)]||{}).title || 'Групповой звонок'); }catch(e){}
                return;
            }


                try{ setSidebarMode('friends'); }catch(e){}
                const li = __ncGetSidebarFriendItemByUserId(uid);
                if (li) {
                    try{ li.click(); }catch(e){}
                } else {
                    try{ openDmByUserId(uid); }catch(e){}
                }
                return;
            }

            // Server channel
            if (v.kind === 'guild_channel') {
                const gid = parseInt(v.guildId || v.guild_id || 0, 10) || 0;
                const cid = parseInt(v.channelId || v.channel_id || 0, 10) || 0;
                if (!gid) return;
                // Ensure the server-level "last channel" is set so selectGuildFromRail auto-opens it.
                try{ if (cid) localStorage.setItem(`nc_last_channel_${String(gid)}`, String(cid)); }catch(e){}
                try{ setSidebarMode('channels'); }catch(e){}
                const serverLi = document.querySelector(`.channel-item.dc-server[data-channel-id="${gid}"], #server-list .dc-server[data-channel-id="${gid}"]`);
                if (serverLi) {
                    try{ serverLi.click(); }catch(e){}
                }
                return;
            }
        }catch(e){}
    }

    try{ setTimeout(__ncRestoreLastViewOnBoot, 80); }catch(e){}

    try { refreshSidebarMeta(); } catch (e) {}


// messages

    // Update delivery/read receipt UI for an outgoing message row.
    function updateReceiptUI(messageId, deliveredAt, readAt) {
        const row = document.querySelector(`.msg-row[data-msg-id="${messageId}"]`);
        if (!row) return;
        if (!row.classList.contains("mine")) return;

        const r = row.querySelector(".msg-receipt");
        if (!r) return;

        const delivered = !!deliveredAt;
        const read = !!readAt;

        r.classList.remove("is-delivered", "is-read");
        r.textContent = "✓";

        if (delivered) {
            r.textContent = "✓✓";
            r.classList.add("is-delivered");
        }
        if (read) {
            r.textContent = "✓✓";
            r.classList.add("is-read");
        }
    }

    // Send message (text and/or attachments)
    async function sendTextMessage(value) {
        if (!socket && window.__nc_initSocket) {
            try { await window.__nc_initSocket(); } catch (e) {}
        }
        if (!socket) {
            alert("Нет соединения с сервером. Сообщение не отправлено.");
            return;
        }
        // stop typing indicator for others
        try {
            if (__ncTypingTimer) { clearTimeout(__ncTypingTimer); __ncTypingTimer = null; }
            if (__ncTypingSent && currentChannelId) {
                socket.emit("typing", { channel_id: parseInt(currentChannelId), typing: false });
                __ncTypingSent = false;
            }
        } catch (e) {}

        try { joinChannel(currentChannelId); } catch (e) {}

        // chat settings: auto emoji conversion
        try{
            const st = _ncChatLoad();
            const autoEmoji = (typeof st.autoEmoji === "undefined") ? true : !!st.autoEmoji;
            if (autoEmoji) value = _ncChatConvertEmoticons(value);
        }catch(e){}

        // If we're in a temporary ad-hoc group chat, send via its socket event (in-memory, 24h TTL)
        try{
            if (String(currentChannelType||"") === "adhoc_group") {
                const nonce = String(Date.now()) + "_" + String(Math.random()).slice(2);
                socket.emit("adhoc_group_chat_message", {
                    channel_id: parseInt(currentChannelId),
                    content: value,
                    client_nonce: nonce
                });
                return;
            }
        }catch(e){}

        socket.emit("send_message", {
            channel_id: parseInt(currentChannelId),
            content: value
        });}

    function uploadFilesAndSend(contentText) {
        return new Promise((resolve, reject) => {
            if (uploadInFlight) return reject(new Error("upload busy"));
            // Temporary ad-hoc group chat: attachments not supported (in-memory chat)
            try{
                if (String(currentChannelType||"") === "adhoc_group"){
                    uploadInFlight = false;
                    ncToast("Вложения в чат звонка пока не поддерживаются");
                    return reject(new Error("attachments not supported"));
                }
            }catch(e){}
            uploadInFlight = true;

            const fd = new FormData();
            fd.append("channel_id", String(parseInt(currentChannelId)));
            // chat settings: auto emoji conversion
            try{
                const st = _ncChatLoad();
                const autoEmoji = (typeof st.autoEmoji === "undefined") ? true : !!st.autoEmoji;
                if (autoEmoji) contentText = _ncChatConvertEmoticons(contentText || "");
            }catch(e){}

            fd.append("content", contentText || "");
            pendingFiles.forEach(f => fd.append("files", f, f.name));

            if (uploadProgress) {
                uploadProgress.classList.remove("is-hidden");
                uploadProgress.setAttribute("aria-hidden", "false");
            }
            if (btnSend) btnSend.disabled = true;
            if (btnAttach) btnAttach.disabled = true;

            const xhr = new XMLHttpRequest();
            xhr.open("POST", "/api/upload", true);

            xhr.upload.onprogress = (ev) => {
                if (!ev.lengthComputable) return;
                const pct = Math.max(0, Math.min(100, Math.round((ev.loaded / ev.total) * 100)));
                if (uploadProgressBar) uploadProgressBar.style.width = pct + "%";
                if (uploadProgressText) uploadProgressText.textContent = pct + "%";
            };

            xhr.onload = () => {
                uploadInFlight = false;
                if (btnSend) btnSend.disabled = false;
                if (btnAttach) btnAttach.disabled = false;

                let data = null;
                try { data = JSON.parse(xhr.responseText || "{}"); } catch (e) {}

                if (xhr.status >= 400) {
                    const msg = (data && data.error) ? data.error : "Ошибка загрузки";
                    ncToast(msg);
                    if (uploadProgress) uploadProgress.classList.add("is-hidden");
                    return reject(new Error(msg));
                }

                // optimistically append message (server also broadcasts)
                if (data && data.message) {
                    try { appendMessage(data.message); } catch (e) {}
                }

                // cleanup
                clearUploadQueue();
                if (uploadProgressBar) uploadProgressBar.style.width = "0%";
                if (uploadProgressText) uploadProgressText.textContent = "0%";
                if (uploadProgress) uploadProgress.classList.add("is-hidden");
                resolve(true);
            };

            xhr.onerror = () => {
                uploadInFlight = false;
                if (btnSend) btnSend.disabled = false;
                if (btnAttach) btnAttach.disabled = false;
                if (uploadProgress) uploadProgress.classList.add("is-hidden");
                ncToast("Ошибка сети при загрузке");
                reject(new Error("network"));
            };

            xhr.send(fd);
        });
    }

    if (messageForm && messageInput) {
        messageForm.addEventListener("submit", async (e) => {
            e.preventDefault();
            if (!currentChannelId) return;

            // Permissions: block sending if you can't send to this channel
            try{
                if (!currentChannelCanSend) {
                    if (String(currentChannelType||'') === 'dm') {
                        ncToast('Нельзя отправлять ЛС этому пользователю (ЛС только от друзей / отключены).');
                    } else {
                        ncToast('Нет прав отправлять сообщения в этот канал');
                    }
                    return;
                }
            }catch(err){}

            const value = (messageInput.value || "").trim();
            const hasFiles = pendingFiles && pendingFiles.length > 0;
            if (!value && !hasFiles) return;

            // If we have files, upload them and create a message on the server.
            if (hasFiles) {
                try {
                    await uploadFilesAndSend(value);
                    messageInput.value = "";
                    try { if (typeof autoGrowTextarea === 'function') autoGrowTextarea(messageInput); } catch (e) {}
                } catch (err) {
                    // keep queued files so user can retry
                }
                return;
            }

            // text-only message
            await sendTextMessage(value);
            messageInput.value = "";
            try { if (typeof autoGrowTextarea === 'function') autoGrowTextarea(messageInput); } catch (e) {}
        });
    }

    // friend requests

    function openAddFriend(){
        if (!modalAddFriend) return;
        // Click-recovery may have set inline styles (display:none / pointer-events:none)
        // on hidden modal backdrops. Restore defaults so the modal can show.
        try{ modalAddFriend.style.display = ''; }catch(e){}
        try{ modalAddFriend.style.pointerEvents = ''; }catch(e){}
        try{ modalAddFriend.classList.add('active'); }catch(e){}
        // IMPORTANT: modal backdrops are hidden by aria-hidden="true" in CSS.
        // We must explicitly set aria-hidden=false when opening.
        try{ modalAddFriend.setAttribute('aria-hidden','false'); }catch(e){}
        try{ modalAddFriend.hidden = false; }catch(e){}
        try{ document.body.classList.add('nc-modal-open'); }catch(e){}
        try{ if (addFriendResult) addFriendResult.textContent = ''; }catch(e){}
        try{ if (addFriendUsernameInput) addFriendUsernameInput.value = ''; }catch(e){}
        try{ if (addFriendUsernameInput) addFriendUsernameInput.focus(); }catch(e){}
    }
