    // Friend requests (accept / decline / cancel) - support both server-rendered and JS-rendered lists.
    function __ncFriendReqActionFromButton(btn){
        if (!btn) return null;
        // prefer explicit data-action
        const da = (btn.dataset && btn.dataset.action) ? String(btn.dataset.action).toLowerCase() : "";
        if (da) return da;
        if (btn.classList.contains("btn-accept") || btn.classList.contains("accept")) return "accept";
        if (btn.classList.contains("btn-reject") || btn.classList.contains("btn-decline") || btn.classList.contains("reject")) return "reject";
        if (btn.classList.contains("btn-cancel") || btn.classList.contains("cancel")) return "cancel";
        return null;
    }

    async function __ncHandleFriendRequest(button){
        const li = button.closest(".request-item, .pending-item");
        if (!li) return;

        const reqId = li.dataset.reqId || li.getAttribute("data-req-id") || li.getAttribute("data-reqId");
        const action = __ncFriendReqActionFromButton(button);
        if (!reqId || !action) return;

        try{ button.disabled = true; }catch(_e){}

        try{
            const r = await fetch(`/api/friend-request/${reqId}/respond`, {
                method: "POST",
                headers: {"Content-Type": "application/json"},
                body: JSON.stringify({action})
            });
            const data = await r.json().catch(()=>({}));
            if (data && data.success) {
                try{ li.remove(); }catch(_e){}
                try{ if (typeof __ncRefreshPendingRequests === "function") __ncRefreshPendingRequests(); }catch(_e){}
                try{ if (typeof refreshFriendsList === "function") refreshFriendsList(); }catch(_e){}
            } else {
                try{ button.disabled = false; }catch(_e){}
            }
        }catch(e){
            try{ button.disabled = false; }catch(_e){}
        }
    }

    // Legacy bindings (if list is static)
    document.querySelectorAll(".request-list .btn-accept, .request-list .btn-reject, .request-list .btn-decline, .request-list .btn-cancel").forEach(btn => {
        btn.addEventListener("click", () => __ncHandleFriendRequest(btn));
    });

    // Delegated handler (works for dynamically rendered pending lists)
    document.addEventListener("click", (e)=>{
        const btn = e.target && e.target.closest ? e.target.closest(".pending-actions button, .request-list button") : null;
        if (!btn) return;
        // Only react to friend-request buttons
        if (!(btn.classList.contains("btn-accept") || btn.classList.contains("btn-reject") || btn.classList.contains("btn-decline") || btn.classList.contains("btn-cancel") || btn.classList.contains("pending-btn"))) return;
        e.preventDefault();
        e.stopPropagation();
        __ncHandleFriendRequest(btn);
    }, true);
    // incoming call modal

    if (btnAcceptCall) {
        btnAcceptCall.addEventListener("click", async () => {
            // Voice channel "join" via call HUD
            if (pendingVoiceChannelJoin && !pendingIncomingCall) {
                const v = pendingVoiceChannelJoin;
                pendingVoiceChannelJoin = null;
                try { _resetCallCtaLabels(); _resetCallEmptyText(); } catch (e) {}

                // If already in another group call, leave it first
                try{
                    if (groupCallActive && groupCallChannelId && String(groupCallChannelId) !== String(v.channel_id)) {
                        endGroupCall(true);
                    }
                }catch(e){}

                try{
                    await startLocalAudio();
                    groupCallChannelId = v.channel_id;
                    groupCallActive = true;
    try{ __ncGroupAudioNoteUserGesture(); }catch(e){}
    try{ isRemoteMuted = false; if (window._callUI && window._callUI.remoteAudio) window._callUI.remoteAudio.muted = false; }catch(e){}
    try{ __ncUnlockAudioNow(true); }catch(e){}
    try{ if (typeof __ncRetryPendingAudio==='function') { setTimeout(__ncRetryPendingAudio, 50); setTimeout(__ncRetryPendingAudio, 300); setTimeout(__ncRetryPendingAudio, 900);} }catch(e){}
                    try { _markJoinedVoiceChannel(v.channel_id); } catch (e) {}
                    socket.emit('group_join', { channel_id: v.channel_id });
                }catch(e){}

                try{
                    setCallHudMode("group");
                    updateCallUI(true, "🔊 " + (v.channel_name || ""));
                    const refs = window._callUI || {};
                    if (refs.callStatusText) refs.callStatusText.textContent = "Подключаемся…";
                }catch(e){}

                try { syncVoiceConnectedIndicator(); } catch (e) {}
                try { updateVoiceMini(); } catch (e) {}
                try { updateVoiceToolbarState(); } catch (e) {}
                try { updateMePanelStatusText(); } catch (e) {}
                return;
            }

            if (!pendingIncomingCall) return;
            const data = pendingIncomingCall;
            // Cross-tab: answering in this tab should stop ringing in other tabs.
            try{
                const ck = (window.__ncIncomingCallKey) ? window.__ncIncomingCallKey : (typeof window.__ncCallKeyFromOffer === 'function' ? window.__ncCallKeyFromOffer(data) : null);
                if (typeof window.__ncBroadcastCallSync === 'function') {
                    window.__ncBroadcastCallSync({ type: 'answered', call_key: ck, from_id: data.from_id });
                }
            }catch(e){}

            // Do NOT hide the modal before we actually start answering.
            // If something fails (mic permission / RTC), the user must be able to retry.
            try{ btnAcceptCall.disabled = true; btnAcceptCall.classList.add('is-loading'); }catch(e){}
            try{
                setCallHudMode('connecting');
                const refs2 = window._callUI || {};
                if (refs2.callStatusText) refs2.callStatusText.textContent = 'Подключаемся…';
            }catch(e){}

            const ok = await acceptIncomingCallOffer(data, {silent: false, waitAck: true});
            if (ok) {
                pendingIncomingCall = null;
                try{ if (typeof hideIncomingCallModal === 'function') hideIncomingCallModal(); }catch(e){}
            } else {
                // Restore button so user can retry.
                try{ btnAcceptCall.disabled = false; btnAcceptCall.classList.remove('is-loading'); }catch(e){}
                // Keep pendingIncomingCall intact.
            }
        });
    }

