function __ncScheduleAt(ts, fn){
    try{
        const d = Math.max(0, (Number(ts) || 0) - Date.now());
        setTimeout(() => { try{ fn(); }catch(e){} }, d);
    }catch(e){ try{ fn(); }catch(_e){} }
}

async function __ncStartMusicFromLink(url, opts = {}){
    const broadcast = !!opts.broadcast;
    const startAt = Number(opts.startAt || Date.now());
    const action = String(opts.action || 'play');

    try{
        if (action === 'stop') { __ncStopMusicLink({ broadcast }); return; }

        // Stop any previous link playback locally (but keep file playlist untouched)
        try{ __ncStopMusicLink({ broadcast:false, quiet:true }); }catch(e){}

        const info = __ncParseMusicLink(url);
        __ncMusicLinkLast = String(url || '');
        __ncMusicLinkActive = true;
        try{ __ncMusicMiniBarUpdate(true); }catch(e){}

        // Link playback is local on every client, so do NOT enable streaming/tab-capture.
        try{ if (__ncMusicMode !== 'link') __ncSetMusicSharing(false); }catch(e){}

        const offsetSec = Math.max(0, (Date.now() - startAt) / 1000);

        if (info.kind === 'audio') {
            __ncMusicLinkEngine = 'audio';
            __ncMusicLinkPaused = false;
            try{ __ncClearMusicEmbed(); }catch(e){}
            try{ __ncSetMusicMode('link'); }catch(e){}
            try{ musicAudioEl.crossOrigin = 'anonymous'; }catch(e){}
            try{ musicAudioEl.src = info.url; musicAudioEl.load(); }catch(e){}
            try{ musicAudioEl.currentTime = 0; }catch(e){}

            // Seek after metadata is available (keeps play() call simple and more compatible).
            try{
                musicAudioEl.onloadedmetadata = () => {
                    try{
                        const dur = (isFinite(musicAudioEl.duration) ? musicAudioEl.duration : 0);
                        const t = (offsetSec > 0) ? offsetSec : 0;
                        if (t > 0) {
                            const clamped = (dur > 0) ? Math.min(Math.max(0, dur - 0.25), t) : t;
                            musicAudioEl.currentTime = clamped;
                        }
                    }catch(e){}
                };
            }catch(e){}

            // Start now. If autoplay is blocked on receivers, our helper will mark it pending and retry on next user interaction.
            try{ __ncTryPlay(musicAudioEl); }catch(e){}

            try{ document.getElementById('music-now').textContent = 'Ссылка (аудио): ' + (info.url||''); }catch(e){}
        } else if (info.kind === 'youtube') {
            // Best-effort YouTube playback via embed (works without heavy JS API; remote may need one click due to autoplay policy).
            __ncMusicLinkEngine = 'youtube';
            __ncMusicLinkPaused = false;
            try{ __ncSetMusicMode('link'); }catch(e){}
            try{ __ncClearMusicEmbed(); }catch(e){}

            const wrap = __ncEnsureMusicEmbed();
            if (wrap) {
                wrap.hidden = false;
                const start = Math.max(0, Math.floor(offsetSec));
                const __origin = encodeURIComponent((location && location.origin) ? location.origin : '');
                const src = `https://www.youtube.com/embed/${info.videoId}?autoplay=1&start=${start}&playsinline=1&rel=0&controls=1&enablejsapi=1&origin=${__origin}`;
                wrap.innerHTML = `<iframe id="music-yt-iframe" src="${src}" style="width:100%;height:190px;border:0;border-radius:16px;" allow="autoplay; encrypted-media; picture-in-picture" allowfullscreen></iframe>`;
            } else {
                try{ window.open(info.url, '_blank', 'noopener,noreferrer'); }catch(e){}
            }
            try{ document.getElementById('music-now').textContent = 'YouTube: ' + info.videoId; }catch(e){}
        } else if (info.kind === 'iframe' && info.embedUrl) {
            __ncMusicLinkEngine = 'iframe';
            try{ __ncSetMusicMode('link'); }catch(e){}
            const wrap = __ncEnsureMusicEmbed();
            if (wrap) {
                wrap.hidden = false;
                wrap.innerHTML = `<iframe src="${info.embedUrl}" style="width:100%;height:130px;border:0;border-radius:16px;" allow="autoplay; encrypted-media"></iframe>`;
                try{ document.getElementById('music-now').textContent = (info.provider || 'Плеер') + ': ' + (info.url||''); }catch(e){}
                // Iframe widgets often cannot autoplay without user gesture; user can click play inside.
            }
        } else {
            __ncMusicLinkEngine = null;
            __ncMusicLinkActive = false;
            try{ __ncSetMusicMode('file'); }catch(e){}
            try{ toast('Этот сервис не даёт прямой запуск по ссылке. Для YouTube — вставь ссылку на видео. Для прямых mp3 — вставь URL файла. Для Яндекс — откроется виджет, иногда нужен логин.'); }catch(e){}
            return;
        }

        // Broadcast to peer(s)
        if (broadcast && socket) {
            const payload = { action: 'play', url: String(url||''), startAt: startAt };
            try{
                if (groupCallActive && groupCallChannelId) {
                    payload.channel_id = groupCallChannelId;
                    socket.emit('music_link', payload);
                } else if (currentCallTargetId) {
                    payload.target_id = currentCallTargetId;
                    socket.emit('music_link', payload);
                }
            }catch(e){}
        }
    }catch(e){
        console.warn('start music link failed', e);
    }
}


function __ncStopMusicLink(opts = {}){
    const broadcast = !!opts.broadcast;
    const quiet = !!opts.quiet;
    try{
        __ncMusicLinkActive = false;
        try{ __ncMusicMiniBarUpdate(true); }catch(e){}
        __ncMusicLinkEngine = null;
        // Stop audio element (if it was used for link)
        try{
            if (musicAudioEl && __ncMusicMode === 'link') {
                musicAudioEl.pause();
            }
        }catch(e){}
        try{ __ncClearMusicEmbed(); }catch(e){}
        try{
            if (__ncYTPlayer && __ncYTPlayer.stopVideo) __ncYTPlayer.stopVideo();
        }catch(e){}
        try{ __ncSetMusicMode('file'); }catch(e){}
        if (!quiet) {
            try{ document.getElementById('music-now').textContent = 'Музыка'; }catch(e){}
        }

        if (broadcast && socket) {
            const payload = { action: 'stop', url: String(__ncMusicLinkLast||'') };
            try{
                if (groupCallActive && groupCallChannelId) {
                    payload.channel_id = groupCallChannelId;
                    socket.emit('music_link', payload);
                } else if (currentCallTargetId) {
                    payload.target_id = currentCallTargetId;
                    socket.emit('music_link', payload);
                }
            }catch(e){}
        }
    }catch(e){}
}

function __ncOnMusicLink(p){
    try{
        if (!p) return;
        // Only react if we're in a call matching the payload
        const isGroup = !!(p.channel_id);
        if (isGroup) {
            if (!groupCallActive || !groupCallChannelId) return;
            if (String(p.channel_id) !== String(groupCallChannelId)) return;
        } else {
            if (!currentCallTargetId) return;
            if (String(p.from_id||'') && String(p.from_id) !== String(currentCallTargetId)) {
                // server may include from_id; ignore others
            }
        }
        const act = String(p.action || 'play');
        if (act === 'stop') { __ncStopMusicLink({ broadcast:false }); return; }
        const url = String(p.url || '');
        const startAt = Number(p.startAt || Date.now());
        __ncStartMusicFromLink(url, { broadcast:false, startAt: startAt, action: act });
    }catch(e){}
}

function __ncAttachMusicToActiveCall(trackOrNull){
    try{
        if (!peerConnection) return false;
        const pc = peerConnection;
        // Prefer reserved DM slot if available
        if (pc.__ncDmTxMusicA && pc.__ncDmTxMusicA.sender){
            try{ pc.__ncDmTxMusicA.sender.replaceTrack(trackOrNull || null); }catch(e){}
            return true;
        }
        // Fallback: addTrack once
        if (trackOrNull){
            try{ pc.addTrack(trackOrNull, new MediaStream([trackOrNull])); }catch(e){}
            return true;
        }
    }catch(e){}
    return false;
}

function __ncAttachMusicToActiveGroup(trackOrNull){
    try{
        if (!groupCallActive || !groupPeers) return;
        Object.keys(groupPeers || {}).forEach(pidStr => {
            const pid = parseInt(pidStr, 10);
            const ent = groupPeers[pidStr];
            const pc = ent && ent.pc;
            if (!pc) return;

            const existing = groupMusicSendersByPeer ? groupMusicSendersByPeer[pidStr] : null;

            if (trackOrNull){
                if (existing){
                    try{ existing.replaceTrack(trackOrNull); }catch(e){}
                } else {
                    try{
                        const sender = pc.addTrack(trackOrNull, new MediaStream([trackOrNull]));
                        if (!groupMusicSendersByPeer) groupMusicSendersByPeer = {};
                        groupMusicSendersByPeer[pidStr] = sender;
                        // Adding a new track requires renegotiation in group calls
                        try{ if (pid) _groupRenegotiate(pid); }catch(e){}
                    }catch(e){}
                }
            } else {
                if (existing){
                    try{ pc.removeTrack(existing); }catch(e){
                        try{ existing.replaceTrack(null); }catch(_e){}
                    }
                    try{ delete groupMusicSendersByPeer[pidStr]; }catch(e){}
                    try{ if (pid) _groupRenegotiate(pid); }catch(e){}
                }
            }
        });
    }catch(e){}
}

function __ncSetMusicSharing(on){
    try{
        __ncMusicSharing = !!on;
        __ncUpdateMusicShareBadge();

        const tr = __ncMusicSharing ? __ncGetMusicOutboundTrack() : null;

        // DM call
        try{
            if (currentCallTargetId && peerConnection){
                __ncAttachMusicToActiveCall(tr);
            }
        }catch(e){}

        // Group call (adhoc / voice channels)
        try{
            if (groupCallActive){
                __ncAttachMusicToActiveGroup(tr);
            }
        }catch(e){}
    }catch(e){}
}


function __ncEmitMusicControl(action, value){
    try{
        if (!socket || !currentCallTargetId) return;
        socket.emit("music_control", { target_id: currentCallTargetId, action: action, value: value });
    }catch(e){}
}

function __ncEmitMusicState(force){
    try{
        if (!socket || !currentCallTargetId) return;
        const now = Date.now();
        if (!force && (now - (__ncMusicLastStateSentAt||0) < 400)) return;
        __ncMusicLastStateSentAt = now;

        const st = {
            sharing: !!__ncMusicSharing,
            mode: __ncMusicMode || "file",
            playing: (__ncMusicMode === 'tab') ? !!__ncMusicTabStream : !!(musicAudioEl && !musicAudioEl.paused && !musicAudioEl.ended),
            t: (__ncMusicMode === 'tab') ? 0 : (musicAudioEl ? (musicAudioEl.currentTime || 0) : 0),
            dur: (__ncMusicMode === 'tab') ? 0 : ((musicAudioEl && isFinite(musicAudioEl.duration)) ? musicAudioEl.duration : 0),
            idx: __ncMusicIndex || 0,
            title: (__ncMusicMode === 'tab')
                ? (__ncMusicLinkLast || 'Вкладка')
                : (((__ncMusicPlaylist && __ncMusicPlaylist[__ncMusicIndex] && __ncMusicPlaylist[__ncMusicIndex].name) ? __ncMusicPlaylist[__ncMusicIndex].name : ''))
        };
        socket.emit("music_state", { target_id: currentCallTargetId, state: st });
    }catch(e){}
}

function __ncMusicFormatTime(sec){
    const s = Math.max(0, Number(sec)||0);
    const m = Math.floor(s/60);
    const r = Math.floor(s%60);
    return String(m)+":"+String(r).padStart(2,'0');
}

function __ncMusicUpdateNow(){
    try{
        const now = document.getElementById('music-now');
        if (!now) return;
        const name = (__ncMusicPlaylist && __ncMusicPlaylist[__ncMusicIndex]) ? __ncMusicPlaylist[__ncMusicIndex].name : '';
        now.textContent = name || 'Музыка';
        try{ __ncMusicMiniBarUpdate(true); }catch(e){}
    }catch(e){}
}



// Mini bar anchor: DM call HUD OR voice-channel stage
function __ncMusicMiniBarAnchor(){
    try{
        if (typeof isVoiceView !== 'undefined' && isVoiceView){
            const inner = document.querySelector('#voice-tile-main .voice-tile-inner');
            if (inner) return inner;
        }
    }catch(e){}
    try{
        const cw = document.querySelector('#call-bar .call-window') || document.querySelector('.call-window');
        if (cw) return cw;
    }catch(e){}
    return document.body;
}

function __ncReanchorMusicMiniBar(){
    try{
        if (!__ncMusicMiniBarEl) __ncMusicMiniBarEl = document.getElementById('music-minibar');
        if (!__ncMusicMiniBarEl) return;
        const a = __ncMusicMiniBarAnchor();
        if (a && __ncMusicMiniBarEl.parentElement !== a){
            a.appendChild(__ncMusicMiniBarEl);
        }
        const voice = !!(typeof isVoiceView !== 'undefined' && isVoiceView);
        try{ __ncMusicMiniBarEl.classList.toggle('is-voice-anchor', voice); }catch(e){}
    }catch(e){}
}

function __ncReanchorMusicDrawer(){
    try{
        if (!__ncMusicDrawerEl) __ncMusicDrawerEl = document.getElementById('call-music-drawer');
        if (!__ncMusicDrawerEl) return;
        const a = __ncMusicMiniBarAnchor();
        if (a && __ncMusicDrawerEl.parentElement !== a){
            a.appendChild(__ncMusicDrawerEl);
        }
        const voice = !!(typeof isVoiceView !== 'undefined' && isVoiceView);
        try{ __ncMusicDrawerEl.classList.toggle('is-voice-anchor', voice); }catch(e){}
    }catch(e){}
}

// ----- Mini music bar helpers -----
function __ncIsCallUiActive(){
    try{
        // Voice channel view also counts as an active call area (so the mini player can appear there).
        try{ if (typeof isVoiceView !== 'undefined' && isVoiceView && typeof groupCallActive !== 'undefined' && groupCallActive) return true; }catch(_e){}

        const callBar = document.getElementById('call-bar');
        if (!callBar) return false;
        const cs = (window.getComputedStyle) ? getComputedStyle(callBar) : null;
        if (cs) return (cs.display !== 'none' && cs.visibility !== 'hidden' && cs.opacity !== '0');
        return callBar.style.display !== 'none';
    }catch(e){ return false; }
}

function __ncMusicMiniBarSetVisible(v){
    if (!__ncMusicMiniBarEl) return;
    try{ __ncMusicMiniBarEl.classList.toggle('is-visible', !!v); }catch(e){}
    try{ __ncMusicMiniBarEl.setAttribute('aria-hidden', v ? 'false' : 'true'); }catch(e){}
}

function __ncMusicMiniBarIsPlaying(){
    let playing = false;
    try{ if (musicAudioEl && !musicAudioEl.paused && (musicAudioEl.currentTime||0) > 0.02) playing = true; }catch(e){}
    if (!playing){ try{ if (__ncMusicLinkActive && !__ncMusicLinkPaused) playing = true; }catch(e){} }
    if (!playing){
        try{
            const rm = document.getElementById('remoteMusicAudio');
            if (rm && rm.srcObject) playing = true;
        }catch(e){}
    }
    return playing;
}

function __ncMusicMiniBarUpdate(force){
    try{
        if (!__ncMusicMiniBarEl) return;
        const now = (window.performance && performance.now) ? performance.now() : Date.now();
        if (!force && (now - (__ncMusicMiniBarLastUiAt||0) < 220)) return;
        __ncMusicMiniBarLastUiAt = now;

        try{ __ncReanchorMusicMiniBar(); }catch(e){}

        // hide when full drawer is open
        let drawerOpen = false;
        try{ drawerOpen = !!(__ncMusicDrawerEl && __ncMusicDrawerEl.classList.contains('is-open')); }catch(e){}
        if (drawerOpen){ __ncMusicMiniBarSetVisible(false); return; }

        const callActive = __ncIsCallUiActive();
        let shouldShow = !!callActive;
        __ncMusicMiniBarSetVisible(shouldShow);
        if (!shouldShow) return;

        // Title
        let title = '';
        try{
            const nowEl = document.getElementById('music-now');
            title = nowEl ? String(nowEl.textContent||'').trim() : '';
        }catch(e){}
        if (!title){
            try{ title = (__ncMusicLinkLast ? String(__ncMusicLinkLast).trim() : 'Музыка'); }catch(e){ title='Музыка'; }
        }
        if (__ncMusicMiniBarTitleEl){
            const t = title.length > 60 ? (title.slice(0,60) + '…') : title;
            __ncMusicMiniBarTitleEl.textContent = t || 'Музыка';
        }

        const playing = __ncMusicMiniBarIsPlaying();
        if (__ncMusicMiniBarEl){
            try{ __ncMusicMiniBarEl.classList.toggle('is-playing', !!playing); }catch(e){}
        }

        // Subline
        let sub = 'остановлено';
        try{
            if (playing){
                if (__ncMusicSharing) sub = 'играет · ты';
                else if (__ncMusicRemoteActive) sub = 'играет · у друга';
                else sub = 'играет';
            } else {
                if (__ncMusicRemoteActive) sub = 'у друга включено';
                else if (__ncMusicLinkLast) sub = 'готово · по ссылке';
                else if (__ncMusicPlaylist && __ncMusicPlaylist.length) sub = 'готово · плейлист';
                else sub = 'вставь ссылку или файлы';
            }
        }catch(e){}
        if (__ncMusicMiniBarSubEl) __ncMusicMiniBarSubEl.textContent = sub;

        // Progress
        if (__ncMusicMiniBarProgEl){
            let w = 0;
            let live = false;
            try{
                if (musicAudioEl && isFinite(musicAudioEl.duration) && musicAudioEl.duration > 0.2){
                    w = Math.max(0, Math.min(1, (musicAudioEl.currentTime||0) / musicAudioEl.duration));
                } else if (__ncMusicLinkActive || __ncMusicRemoteActive){
                    live = true;
                }
            }catch(e){}

            if (live){
                try{ __ncMusicMiniBarEl.classList.add('is-live'); }catch(e){}
                __ncMusicMiniBarProgEl.style.width = '100%';
            } else {
                try{ __ncMusicMiniBarEl.classList.remove('is-live'); }catch(e){}
                __ncMusicMiniBarProgEl.style.width = (w*100).toFixed(2) + '%';
            }
        }
    }catch(e){}
}

function __ncMusicMiniBarOpen(){
    try{
        if (!__ncMusicDrawerEl) __ncMusicDrawerEl = document.getElementById('call-music-drawer');
        if (!__ncMusicDrawerEl) return;
        try{ __ncReanchorMusicDrawer(); }catch(e){}
        __ncMusicDrawerEl.classList.add('is-open');
        try{ const c = document.getElementById('music-card'); if (c) c.classList.remove('is-advanced'); }catch(e){}
        const toggleBtn = document.getElementById('btn-toggle-music');
        try{ if (toggleBtn) toggleBtn.classList.add('toggled'); }catch(e){}
        __ncMusicMiniBarUpdate(true);
    }catch(e){}
}

function __ncMusicLoadIndex(i, autoplay){
    try{
        if (!musicAudioEl) return;
        if (!__ncMusicPlaylist || !__ncMusicPlaylist.length) return;
        __ncMusicIndex = (i + __ncMusicPlaylist.length) % __ncMusicPlaylist.length;
        const item = __ncMusicPlaylist[__ncMusicIndex];
        if (!item) return;
        try{
            if (musicAudioEl.src && musicAudioEl.src.startsWith('blob:')) { /* old blob urls are fine to keep */ }
        }catch(e){}
        try{ musicAudioEl.src = item.url; }catch(e){}
        __ncMusicUpdateNow();
        if (autoplay){
            const p = musicAudioEl.play();
            if (p && p.catch) p.catch(()=>{});
        }
        __ncEmitMusicState(true);
    }catch(e){}
}

function __ncMusicNext(){
    try{ __ncMusicLoadIndex(__ncMusicIndex+1, true); }catch(e){}
}
function __ncMusicPrev(){
    try{ __ncMusicLoadIndex(__ncMusicIndex-1, true); }catch(e){}
}
function __ncMusicStop(){
    try{
        // In TAB capture mode, stop capture + stop sharing
        if (__ncMusicMode === 'tab') {
            try{ __ncStopMusicTabCapture(true); }catch(e){}
            return;
        }
        if (!musicAudioEl) return;
        musicAudioEl.pause();
        try{ musicAudioEl.currentTime = 0; }catch(e){}
        if (__ncMusicMode !== 'link') __ncSetMusicSharing(false);
        __ncEmitMusicControl('stop');
        __ncEmitMusicState(true);
    }catch(e){}
}

function __ncOnMusicControl(payload){
    try{
        if (!payload) return;
        // Only react to controls when YOU are the one sharing music.
        if (!__ncMusicSharing) return;
        if (__ncMusicMode === 'tab') return;
        // Only accept controls from the current peer in DM
        try{
            if (payload.from_id && currentCallTargetId && Number(payload.from_id) !== Number(currentCallTargetId)) return;
        }catch(e){}
        const action = payload.action;
        const value = payload.value;

        if (!musicAudioEl) return;

        if (action === 'play') { musicAudioEl.play(); }
        else if (action === 'pause') { musicAudioEl.pause(); }
        else if (action === 'toggle') { if (musicAudioEl.paused) musicAudioEl.play(); else musicAudioEl.pause(); }
        else if (action === 'seek') { if (isFinite(Number(value))) musicAudioEl.currentTime = Math.max(0, Number(value)||0); }
        else if (action === 'vol') {
            const v = Math.max(0, Math.min(2, Number(value)||0));
            saveVolume(VOL_KEY_MUSIC, v);
            if (__ncMusicGain) __ncMusicGain.gain.value = v;
            // For receiver-side, also apply
            __ncApplyRemoteMusicVolume();
        }
        else if (action === 'next') { __ncMusicNext(); }
        else if (action === 'prev') { __ncMusicPrev(); }
        else if (action === 'stop') { __ncMusicStop(); }

        __ncEmitMusicState(true);
    }catch(e){}
}

function __ncOnMusicState(payload){
    try{
        if (!payload || !payload.state) return;
        // Peer state: show badge when they are sharing
        const st = payload.state || {};
        if (!__ncMusicSharing){
            __ncMusicRemoteActive = !!st.sharing;
            __ncUpdateMusicShareBadge();
            try{ __ncMusicMiniBarUpdate(true); }catch(e){}
        }
    }catch(e){}
}

function __ncMusicGetEnergy(){
    try{
        if (__ncMusicAnalyser){
            if (!__ncMusicVizData) __ncMusicVizData = new Uint8Array(__ncMusicAnalyser.fftSize);
            __ncMusicAnalyser.getByteTimeDomainData(__ncMusicVizData);
            let sum = 0;
            for (let i = 0; i < __ncMusicVizData.length; i++){
                const v = (__ncMusicVizData[i] - 128) / 128;
                sum += v * v;
            }
            const rms = Math.sqrt(sum / __ncMusicVizData.length);
            return Math.max(0, Math.min(1, rms * 1.8));
        }
    }catch(e){}
    const t = (window.performance && performance.now) ? performance.now() : Date.now();
    return 0.18 + 0.12 * Math.sin(t / 900);
}

function __ncMusicVizResize(){
    try{
        if (!__ncMusicVizCanvas) return;
        const r = __ncMusicVizCanvas.getBoundingClientRect();
        const dpr = Math.max(1, Math.min(2, window.devicePixelRatio || 1));
        __ncMusicVizCanvas.width = Math.max(2, Math.floor(r.width * dpr));
        __ncMusicVizCanvas.height = Math.max(2, Math.floor(r.height * dpr));
        if (__ncMusicVizCtx) __ncMusicVizCtx.setTransform(1,0,0,1,0,0);
    }catch(e){}
}

function __ncMusicVizLoop(){
    try{
        const card = document.getElementById('music-card');
        if (!card) return;
        const energy = __ncMusicGetEnergy();
        try{ card.style.setProperty('--music-energy', String(energy)); }catch(e){}

        const stateEl = document.getElementById('music-wave-state');
        let playing = false;
        try{
            if (musicAudioEl && !musicAudioEl.paused && musicAudioEl.currentTime > 0.05) playing = true;
        }catch(e){}
        try{
            if (!playing && __ncMusicLinkActive) playing = true;
        }catch(e){}
        if (stateEl){
            try{ stateEl.textContent = playing ? '⏸' : '▶'; }catch(e){}
        }

        if (__ncMusicVizCtx && __ncMusicVizCanvas){
            const ctx = __ncMusicVizCtx;
            const w = __ncMusicVizCanvas.width, h = __ncMusicVizCanvas.height;
            ctx.clearRect(0,0,w,h);

            // simple waveform
            const data = (__ncMusicVizData && __ncMusicVizData.length) ? __ncMusicVizData : null;
            if (data){
                ctx.globalAlpha = 0.28 + energy * 0.25;
                ctx.lineWidth = Math.max(1, Math.floor(w/480));
                ctx.beginPath();
                const step = w / (data.length - 1);
                for (let i=0; i<data.length; i++){
                    const v = (data[i]-128)/128;
                    const y = h/2 + v * (h*0.18 + energy*(h*0.18));
                    const x = i * step;
                    if (i===0) ctx.moveTo(x,y); else ctx.lineTo(x,y);
                }
                ctx.strokeStyle = 'rgba(210,255,235,1)';
                ctx.stroke();
            }
        }
    }catch(e){}
    try{ __ncMusicVizRAF = requestAnimationFrame(__ncMusicVizLoop); }catch(e){}
}

function __ncInitMusicWaveFX(){
    try{
        const __isYa = !!(window.__NC_YABROWSER || (document.documentElement && document.documentElement.classList && (document.documentElement.classList.contains('is-yabrowser') || document.documentElement.classList.contains('yabrowser'))));
        // YaBrowser performance mode: disable canvas visualizer loop (it can freeze the browser)
        if (__isYa){
            try{ if (__ncMusicVizRAF){ cancelAnimationFrame(__ncMusicVizRAF); __ncMusicVizRAF = null; } }catch(e){}
        }

        const canvas = document.getElementById('music-viz');
        if (canvas && !__isYa){
            __ncMusicVizCanvas = canvas;
            __ncMusicVizCtx = canvas.getContext('2d');
            __ncMusicVizResize();
            window.addEventListener('resize', __ncMusicVizResize);
            if (!__ncMusicVizRAF) __ncMusicVizRAF = requestAnimationFrame(__ncMusicVizLoop);
        }

        // Mirror now-playing text into headline/sub (modern look)
        const nowEl = document.getElementById('music-now');
        const titleEl = document.getElementById('music-wave-title');
        const subEl = document.getElementById('music-wave-sub');
        if (nowEl && titleEl && subEl){
            const sync = () => {
                const t = (nowEl.textContent || '').trim();
                if (!t){
                    titleEl.textContent = 'Моя волна';
                    subEl.textContent = 'Ссылка → Запустить · или выбери файлы';
                    return;
                }
                // Title: provider hint
                let title = 'Моя волна';
                if (/^YouTube/i.test(t)) title = 'YouTube';
                else if (/Яндекс/i.test(t)) title = 'Яндекс Музыка';
                else if (/VK|ВК/i.test(t)) title = 'VK Музыка';
                else if (/Ссылка/i.test(t)) title = 'Ссылка';
                titleEl.textContent = title;

                // Sub: trimmed now-playing
                const sub = t.length > 70 ? (t.slice(0, 70) + '…') : t;
                subEl.textContent = sub;
            };
            sync();
            try{
                const obs = new MutationObserver(sync);
                obs.observe(nowEl, { characterData:true, childList:true, subtree:true });
            }catch(e){}
        }
    }catch(e){}
}
