            if (mbNext){ mbNext.addEventListener('click', (ev) => { stop(ev); try{ __ncMusicNext(); __ncEmitMusicControl('next'); __ncMusicMiniBarUpdate(true); }catch(e){} }); }
            if (mbPlay){ mbPlay.addEventListener('click', (ev) => { stop(ev); try{ __ncMusicToggleFromUi(); __ncMusicMiniBarUpdate(true); }catch(e){} }); }

