// audio helpers


// Promise-safe audio play with retry after user interaction (autoplay policy)
let __ncAudioUnlockArmed = false;

function __ncArmAudioUnlock(){
    if (__ncAudioUnlockArmed) return;
    __ncAudioUnlockArmed = true;

    const handler = () => {
        try { document.removeEventListener('pointerdown', handler, true); } catch(e){}
        try { document.removeEventListener('keydown', handler, true); } catch(e){}
        __ncAudioUnlockArmed = false;
        try { __ncRetryPendingAudio(); } catch(e){}
    };

    try { document.addEventListener('pointerdown', handler, true); } catch(e){}
    try { document.addEventListener('keydown', handler, true); } catch(e){}
}

function __ncMarkPendingAudio(el){
    try{ if (el) el.dataset.ncPendingPlay = "1"; }catch(e){}
    __ncArmAudioUnlock();
}

function __ncTryPlay(el){
    if (!el || !el.play) return;
    try{
        const p = el.play();
        if (p && typeof p.catch === 'function') {
            p.catch((err) => {
                // Autoplay can be blocked on receivers (no user gesture). Try a "muted start" once.
                try{
                    const name = String((err && err.name) || '');
                    const msg  = String(err || '');
                    if ((name === 'NotAllowedError' || msg.includes('NotAllowed')) && !el.__ncTriedMutedAutoplay){
                        el.__ncTriedMutedAutoplay = true;
                        const wasMuted = !!el.muted;
                        try{ el.muted = true; }catch(e){}
                        try{
                            const p2 = el.play();
                            if (p2 && typeof p2.catch === 'function') p2.catch(() => __ncMarkPendingAudio(el));
                        }catch(e){ __ncMarkPendingAudio(el); }
                        setTimeout(() => { try{ el.muted = wasMuted; }catch(e){} }, 220);
                        return;
                    }
                }catch(e){}
                __ncMarkPendingAudio(el);
            });
        }
    }catch(e){
        try{
            const name = String((e && e.name) || '');
            const msg  = String(e || '');
            if ((name === 'NotAllowedError' || msg.includes('NotAllowed')) && !el.__ncTriedMutedAutoplay){
                el.__ncTriedMutedAutoplay = true;
                const wasMuted = !!el.muted;
                try{ el.muted = true; }catch(_e){}
                try{
                    const p2 = el.play();
                    if (p2 && typeof p2.catch === 'function') p2.catch(() => __ncMarkPendingAudio(el));
                }catch(_e){ __ncMarkPendingAudio(el); }
                setTimeout(() => { try{ el.muted = wasMuted; }catch(_e){} }, 220);
                return;
            }
        }catch(_e){}
        __ncMarkPendingAudio(el);
    }
}

function __ncRetryPendingAudio(){
    try{
        const els = document.querySelectorAll('audio[data-nc-pending-play="1"]');
        els.forEach((a) => {
            try{ a.dataset.ncPendingPlay = ""; }catch(e){}
            try{
                const p = a.play();
                if (p && typeof p.catch === 'function') p.catch(()=>{});
            }catch(e){}
        });
    }catch(e){}
}


