function startCallHeartbeat() {
    if (callHeartbeatInterval) clearInterval(callHeartbeatInterval);
    if (!socket) return;
    callHeartbeatInterval = setInterval(() => {
        try {
            if (socket && socket.connected && !groupCallActive && currentCallTargetId) {
                socket.emit('call_heartbeat', { target_id: currentCallTargetId });
            }
        } catch (e) {}
    }, 20000);
}

