        if (!track || track.kind !== 'video') return () => { stopped = true; cleanup(); };
        st = new MediaStream();
        try{ st.addTrack(track); }catch(e){}
        v = document.createElement('video');
        v.muted = true;
        v.playsInline = true;
        v.autoplay = true;
