      color: 'neon',         // palette id
      density: 'default',    // compact | default | spacious
      msgDisplay: 'default', // default | compact
      msgGap: 16,            // 0..24
      chatFont: 16,          // 12..24
      bgStops: ['#7AF3FF','#FF7CFB','#1B7CFF'], // gradient colors (2..5)
      bgAngle: 135,          // 0..360
      bgSat: 60,             // 0..100 (multiplier)

      /* Discord-like appearance controls */
