    emerald:{ name:'Emerald',a:'#00f5a0', s:'#00d9f5', l1:'rgba(0,245,160,0.12)',  l2:'rgba(0,217,245,0.14)',  b1:'rgba(0,245,160,0.22)',  b2:'rgba(0,217,245,0.22)',  b3:'rgba(0,217,245,0.16)' },
    violet: { name:'Violet', a:'#b86bff', s:'#ff7cfb', l1:'rgba(184,107,255,0.14)', l2:'rgba(255,124,251,0.12)', b1:'rgba(184,107,255,0.24)', b2:'rgba(255,124,251,0.20)', b3:'rgba(184,107,255,0.16)' },
